      alert("Por favor, preencha Marca, Modelo, ID e Empresa para todos os itens.");
      return;
    }

    bulkEntries.forEach(entry => {
      onAdd({
        id: entry.id,
        companyId: entry.companyId,
        type: entry.type,
        brand: entry.brand,
        model: entry.model,
        observations: entry.observations,
        photos: [],
