                  <div className="max-h-96 overflow-y-auto p-4 space-y-3">
                    {todayDeliveries.map((d, i) => (
                      <div key={i} className="p-4 bg-blue-50/50 rounded-2xl border border-blue-100">
                         <p className="text-xs font-bold text-slate-900">{d.item} Chegando!</p>
                         <p className="text-[10px] text-slate-700 font-medium">Protocolo: {d.id}</p>
                      </div>
                    ))}
                    {todayDeliveries.length === 0 && <p className="text-center py-6 text-slate-600 font-medium">Sem avisos hoje.</p>}
                  </div>
                </div>
              )}
            </div>

            <div className="flex items-center gap-4 pl-6 border-l border-slate-200">
              <div className="hidden sm:flex flex-col items-end">
                <span className="text-sm font-black text-slate-900">{currentUser.name}</span>
                <span className="text-[10px] font-black uppercase text-blue-600 tracking-widest">{currentUser.sector}</span>
              </div>
              <div className="w-12 h-12 rounded-2xl bg-slate-900 border border-slate-800 shadow-sm flex items-center justify-center font-black text-white text-lg">
                 {currentUser.name.charAt(0)}
              </div>
            </div>
          </div>
        </header>

        <div className="p-6 lg:p-10 max-w-7xl mx-auto w-full">
          {children}
        </div>
      </main>
    </div>
  );
};

