    { tempId: '1', companyId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', id: '', assignedTo: '', observations: '' }
  ]);

  const [newAsset, setNewAsset] = useState<Partial<Asset>>({
    type: 'Notebook',
    status: 'Pendente Documentos',
    photos: [],
    companyId: companies[0]?.id || ''
