import React, { useState, useMemo } from 'react';
import { 
  Plus, 
  Search, 
  Filter, 
  Camera, 
  QrCode,
  Trash2,
  X,
  Cpu,
  Database,
  Printer,
  Package,
  Building2,
  ClipboardList,
  FileSpreadsheet,
  UserPlus,
  Save,
  PlusCircle,
  Eye,
  FileDown,
  Layers,
  Monitor,
  HardDrive
} from 'lucide-react';
import { Asset, AssetType, AssetStatus, Employee, Department } from '../types';
import { ASSET_TYPES } from '../constants';

interface AssetManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  onAdd: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode'> & { id?: string }) => void;
  onUpdate: (asset: Asset) => void;
  onRemove: (id: string) => void;
}

interface BulkAssetEntry {
  tempId: string;
  departmentId: string;
  type: AssetType;
  brand: string;
  model: string;
  ram: string;
  storage: string;
  screenSize: string;
  id: string; // ID patrimonial real
  assignedTo: string;
  observations: string;
}

const AssetManager: React.FC<AssetManagerProps> = ({ assets, employees, companies, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<string>('all');
  const [filterDepartment, setFilterDepartment] = useState<string>('all');
  const [filterAvailability, setFilterAvailability] = useState<string>('all');

  const [bulkEntries, setBulkEntries] = useState<BulkAssetEntry[]>([
    { tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', ram: '', storage: '', screenSize: '', id: '', assignedTo: '', observations: '' }
  ]);

  const [newAsset, setNewAsset] = useState<Partial<Asset>>({
    type: 'Notebook',
    status: 'Pendente Documentos',
    photos: [],
    departmentId: companies[0]?.id || '',
    ram: '',
    storage: '',
    screenSize: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAsset.departmentId) {
      alert("Por favor, selecione o departamento responsável.");
      return;
    }

    if (newAsset.type === 'Notebook' && (!newAsset.ram || !newAsset.storage || !newAsset.screenSize)) {
      alert("Para Notebooks, RAM, Armazenamento e Tamanho da Tela são obrigatórios.");
      return;
    }

    onAdd(newAsset as Omit<Asset, 'id' | 'createdAt' | 'qrCode'>);
    setShowForm(false);
    setNewAsset({ type: 'Notebook', status: 'Pendente Documentos', photos: [], departmentId: companies[0]?.id || '', ram: '', storage: '', screenSize: '' });
  };

  const handleBulkAddRow = () => {
    setBulkEntries([...bulkEntries, { 
      tempId: Math.random().toString(), 
      departmentId: companies[0]?.id || '', 
      type: 'Notebook', 
      brand: '', 
      model: '', 
      ram: '',
      storage: '',
      screenSize: '',
      id: '', 
      assignedTo: '', 
      observations: '' 
    }]);
  };

  const handleBulkRemoveRow = (tempId: string) => {
    setBulkEntries(bulkEntries.filter(e => e.tempId !== tempId));
  };

  const handleBulkSave = () => {
    const invalid = bulkEntries.some(e => {
      const basicInfoMissing = !e.brand || !e.model || !e.id || !e.departmentId;
      const notebookInfoMissing = e.type === 'Notebook' && (!e.ram || !e.storage || !e.screenSize);
      return basicInfoMissing || notebookInfoMissing;
    });

    if (invalid) {
      alert("Por favor, preencha todos os campos obrigatórios (Marca, Modelo, ID, Departamento e Info Técnica de Notebooks).");
      return;
    }

    bulkEntries.forEach(entry => {
      onAdd({
        id: entry.id,
        departmentId: entry.departmentId,
        type: entry.type,
        brand: entry.brand,
        model: entry.model,
        ram: entry.type === 'Notebook' ? entry.ram : undefined,
        storage: entry.type === 'Notebook' ? entry.storage : undefined,
        screenSize: entry.type === 'Notebook' ? entry.screenSize : undefined,
        observations: entry.observations,
        photos: [],
        status: entry.assignedTo ? 'Em Uso' : 'Disponível',
        assignedTo: entry.assignedTo || undefined,
      });
    });

    alert(`${bulkEntries.length} ativos cadastrados com sucesso!`);
    setShowBulkModal(false);
    setBulkEntries([{ tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', ram: '', storage: '', screenSize: '', id: '', assignedTo: '', observations: '' }]);
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || a.type === filterType;
    const matchesDepartment = filterDepartment === 'all' || a.departmentId === filterDepartment;

    let matchesAvailability = true;
    if (filterAvailability === 'available') {
      matchesAvailability = !a.assignedTo;
    } else if (filterAvailability === 'assigned') {
      matchesAvailability = !!a.assignedTo;
    }

    return matchesSearch && matchesType && matchesAvailability && matchesDepartment;
  });

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 print:hidden">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600 w-5 h-5" />
          <input 
