                                />
                                <input 
                                  className="w-1/2 p-2 bg-white border border-slate-300 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-emerald-500 text-slate-900 placeholder:text-slate-600"
                                  placeholder="Modelo"
                                  value={entry.model}
                                  onChange={e => {
                                    const newEntries = [...bulkEntries];
                                    newEntries[idx].model = e.target.value;
                                    setBulkEntries(newEntries);
