  Plus, 
  Search, 
  Filter, 
  Camera, 
  QrCode,
  Trash2,
  X,
  Cpu,
  Database,
  Printer,
  Package,
  Building2,
  ClipboardList,
  FileSpreadsheet,
  UserPlus,
  Save,
