                        <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase w-48 tracking-widest">Departamento / Tipo</th>
                        <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Identificação (Marca/Mod/ID)</th>
                        <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Especificações</th>
