                                </div>
                              )}
                           </td>
                           <td className="px-6 py-4">
                              <select 
                                className="w-full p-2 bg-white border border-slate-300 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-emerald-500 text-slate-900"
