                                onChange={e => {
                                  const newEntries = [...bulkEntries];
                                  newEntries[idx].assignedTo = e.target.value;
                                  setBulkEntries(newEntries);
                                }}
                              >
                                <option value="">Estoque</option>
                                {employees.filter(emp => emp.departmentId === entry.departmentId).map(emp => (
                                  <option key={emp.id} value={emp.id}>{emp.name}</option>
                                ))}
                              </select>
                           </td>
                           <td className="px-6 py-4 text-right">
                              <button 
                                onClick={() => handleBulkRemoveRow(entry.tempId)}
                                className="p-2 text-slate-500 hover:text-rose-600 transition-colors"
                              >
                                <Trash2 className="w-4 h-4" />
                              </button>
                           </td>
                        </tr>
                      ))}
                   </tbody>
                </table>
                <div className="p-6 bg-slate-50 flex items-center justify-between border-t border-slate-200">
                   <button 
                    onClick={handleBulkAddRow}
                    className="flex items-center gap-2 text-emerald-700 font-black text-xs uppercase tracking-widest hover:underline"
                   >
                      <PlusCircle className="w-5 h-5" /> Adicionar mais um item
                   </button>
                   <div className="flex gap-4">
                      <button onClick={() => setShowBulkModal(false)} className="px-8 py-3 rounded-2xl font-black text-slate-700 hover:text-slate-900 transition-colors uppercase text-xs tracking-widest">Cancelar</button>
                      <button onClick={handleBulkSave} className="bg-emerald-600 hover:bg-emerald-700 text-white px-10 py-3 rounded-2xl font-black shadow-xl shadow-emerald-100 flex items-center gap-2 uppercase tracking-widest text-xs transition-all active:scale-95">
                        <Save className="w-4 h-4" /> Finalizar Levantamento
                      </button>
                   </div>
                </div>
             </div>
          </div>
        </div>
      )}

      {showForm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-slate-200 flex justify-between items-center bg-slate-50">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl">
                  <Plus className="w-6 h-6" />
                </div>
                <div>
                   <h3 className="text-2xl font-black text-slate-900 tracking-tight">Onboarding de Ativo</h3>
                   <p className="text-slate-700 text-sm font-bold">Cadastre um novo dispositivo individualmente.</p>
                </div>
              </div>
              <button onClick={() => setShowForm(false)} className="p-3 hover:bg-slate-200 rounded-full transition-colors text-slate-500 hover:text-slate-900">
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-10 overflow-y-auto space-y-8 bg-white">
               <div className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2 col-span-full">
                      <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Departamento Responsável</label>
                      <select className="w-full p-4 rounded-2xl border border-slate-300 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" value={newAsset.departmentId} onChange={(e) => setNewAsset({...newAsset, departmentId: e.target.value})} required>
                        {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Tipo</label>
                      <select className="w-full p-4 rounded-2xl border border-slate-300 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" value={newAsset.type} onChange={(e) => setNewAsset({...newAsset, type: e.target.value as AssetType})} required>
                        {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                      </select>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Marca</label>
                      <input className="w-full p-4 rounded-2xl border border-slate-300 font-bold text-slate-900 focus:ring-2 focus:ring-blue-600 placeholder:text-slate-400" placeholder="Ex: Dell" value={newAsset.brand || ''} onChange={(e) => setNewAsset({...newAsset, brand: e.target.value})} required />
                    </div>
                  </div>

                  {newAsset.type === 'Mouse' && (
                    <div className="p-6 bg-slate-50 border border-slate-200 rounded-[2rem] space-y-4 animate-in fade-in slide-in-from-top-4">
                        <div className="flex items-center gap-2 mb-2">
                         <Wifi className="w-5 h-5 text-blue-600" />
                         <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">Conectividade do Mouse</h4>
                       </div>
                       <div className="grid grid-cols-2 gap-4">
                          <button 
                            type="button"
                            onClick={() => setNewAsset({...newAsset, isWireless: false})}
                            className={`flex items-center justify-center gap-3 p-4 rounded-2xl border-2 transition-all font-black uppercase text-xs tracking-widest ${!newAsset.isWireless ? 'bg-white border-blue-600 text-blue-600 shadow-xl' : 'bg-white border-slate-100 text-slate-400'}`}
                          >
                             <Usb className="w-5 h-5" /> Com Fio
                          </button>
                          <button 
                            type="button"
                            onClick={() => setNewAsset({...newAsset, isWireless: true})}
                            className={`flex items-center justify-center gap-3 p-4 rounded-2xl border-2 transition-all font-black uppercase text-xs tracking-widest ${newAsset.isWireless ? 'bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-100' : 'bg-white border-slate-100 text-slate-400'}`}
                          >
                             <Wifi className="w-5 h-5" /> Sem Fio
                          </button>
                       </div>
                    </div>
                  )}

                  {(newAsset.type === 'Notebook' || newAsset.type === 'Desktop') && (
                    <div className="p-6 bg-blue-50 border border-blue-200 rounded-[2rem] space-y-4 animate-in fade-in slide-in-from-top-4">
                       <div className="flex items-center gap-2 mb-2">
                         <Cpu className="w-5 h-5 text-blue-600" />
                         <h4 className="text-xs font-black text-blue-900 uppercase tracking-widest">
                            Especificações Técnicas {newAsset.type === 'Desktop' ? '(Desktop)' : '(Notebook)'}
                         </h4>
                       </div>
                       <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                         <div className="space-y-1">
                           <label className="text-[9px] font-black text-blue-700 uppercase ml-1">Memória RAM</label>
                           <input className="w-full p-3 rounded-xl border border-blue-200 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" placeholder="Ex: 16GB" value={newAsset.ram || ''} onChange={(e) => setNewAsset({...newAsset, ram: e.target.value})} required />
                         </div>
                         <div className="space-y-1">
                           <label className="text-[9px] font-black text-blue-700 uppercase ml-1">Armazenamento</label>
                           <input className="w-full p-3 rounded-xl border border-blue-200 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" placeholder="Ex: 512GB SSD" value={newAsset.storage || ''} onChange={(e) => setNewAsset({...newAsset, storage: e.target.value})} required />
                         </div>
                         <div className="space-y-1">
                           <label className="text-[9px] font-black text-blue-700 uppercase ml-1">{newAsset.type === 'Notebook' ? 'Tela' : 'Gabinete'}</label>
                           <input className="w-full p-3 rounded-xl border border-blue-200 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" placeholder={newAsset.type === 'Notebook' ? "Ex: 14 pol" : "Ex: Torre ATX"} value={newAsset.type === 'Notebook' ? (newAsset.screenSize || '') : (newAsset.caseModel || '')} onChange={(e) => {
                                 if(newAsset.type === 'Notebook') setNewAsset({...newAsset, screenSize: e.target.value});
                                 else setNewAsset({...newAsset, caseModel: e.target.value});
                               }} required />
                         </div>
                       </div>
                    </div>
                  )}

                  <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 uppercase tracking-widest transition-all active:scale-95 text-sm">Finalizar Cadastro</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AssetManager;

export type AssetType = 
  | 'Desktop' 
  | 'Notebook' 
  | 'Mouse' 
  | 'Cabo' 
  | 'Monitor' 
  | 'Teclado' 
  | 'Headset' 
  | 'Suporte Notebook';

export type AssetStatus = 'Disponível' | 'Em Uso' | 'Manutenção' | 'Baixado' | 'Pendente Documentos';

export interface Department {
  id: string;
  name: string;
  costCenter?: string;
  createdAt: string;
}

export interface Asset {
  id: string;
  departmentId: string; // Vínculo com o departamento
  type: AssetType;
  brand: string;
  model: string;
  ram?: string;
  storage?: string;
  processor?: string;
  screenSize?: string;
  caseModel?: string; // Novo campo para Desktops
  isWireless?: boolean; // Novo campo para Mouses
  monitorInputs?: string[]; // Novo campo para Monitores (HDMI, VGA, DVI)
  observations: string;
  photos: string[];
  status: AssetStatus;
  assignedTo?: string; // Employee ID
  qrCode: string;
  createdAt: string;
}

export interface Employee {
  id: string;
  departmentId: string; // Vínculo com o departamento
  name: string;
  sector: string;
  role: string;
  cpf: string;
}

export type AppModule = 
  | 'dashboard' 
  | 'departments'
  | 'assets' 
  | 'employees' 
  | 'requests' 
  | 'purchase-orders' 
  | 'printing' 
  | 'user-management' 
  | 'inventory-check'
  | 'maintenance';

export interface UserAccount {
  id: string;
  name: string;
  username: string;
  password?: string;
  sector: string;
  modules: AppModule[];
}

export interface Quotation {
  url: string;
  price?: number;
  deliveryPrediction: string;
}

export interface ItemFulfillment {
  type: AssetType;
  linkedAssetId?: string;
  isPurchaseOrder: boolean;
  purchaseStatus?: 'Pendente' | 'Cotação Aprovada' | 'Pedido Autorizado' | 'Comprado';
  quotations?: Quotation[];
  approvedQuotationIndex?: number;
  deliveryForecastDate?: string;
  isDelivered?: boolean;
}

export interface EquipmentRequest {
  id: string;
  requesterId: string;
  employeeId: string;
  items: AssetType[];
  itemFulfillments?: ItemFulfillment[];
  observation?: string;
  status: 'Pendente' | 'Aprovado' | 'Preparando' | 'Entregue' | 'Cancelado' | 'Confronto';
  createdAt: string;
  type?: 'Padrao' | 'Divergencia';
}

export type AuditStatus = 'Bom' | 'Regular' | 'Ruim' | 'Não Encontrado';

export interface AuditEntry {
  assetId: string;
  status: AuditStatus;
  checkedAt: string;
  observation?: string;
}

export interface AuditSession {
  id: string;
  sector: string;
  createdAt: string;
  entries: AuditEntry[];
  isFinished: boolean;
  generatedRequestId?: string;
}

import React, { useState, useMemo } from 'react';
import { 
  Plus, 
  Search, 
  Filter, 
  Camera, 
  QrCode,
  Trash2,
  X,
  Cpu,
  Database,
  Printer,
  Package,
  Building2,
  ClipboardList,
  FileSpreadsheet,
  UserPlus,
  Save,
  PlusCircle,
  Eye,
  FileDown,
  Layers,
  Monitor,
  HardDrive,
  Box,
  Wifi,
  Usb,
  Zap
} from 'lucide-react';
import { Asset, AssetType, AssetStatus, Employee, Department } from '../types';
import { ASSET_TYPES } from '../constants';

interface AssetManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  onAdd: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode'> & { id?: string }) => void;
  onUpdate: (asset: Asset) => void;
  onRemove: (id: string) => void;
}

interface BulkAssetEntry {
  tempId: string;
  departmentId: string;
  type: AssetType;
  brand: string;
  model: string;
  ram: string;
  storage: string;
  screenSize: string;
  caseModel: string;
  isWireless: boolean;
  monitorInputs: string[];
  id: string; // ID patrimonial real
  assignedTo: string;
  observations: string;
}

const AssetManager: React.FC<AssetManagerProps> = ({ assets, employees, companies, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<string>('all');
  const [filterDepartment, setFilterDepartment] = useState<string>('all');
  const [filterAvailability, setFilterAvailability] = useState<string>('all');

  const [bulkEntries, setBulkEntries] = useState<BulkAssetEntry[]>([
    { tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], id: '', assignedTo: '', observations: '' }
  ]);

  const [newAsset, setNewAsset] = useState<Partial<Asset>>({
    type: 'Notebook',
    status: 'Pendente Documentos',
    photos: [],
    departmentId: companies[0]?.id || '',
    ram: '',
    storage: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: []
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAsset.departmentId) {
      alert("Por favor, selecione o departamento responsável.");
      return;
    }

    if (newAsset.type === 'Notebook' && (!newAsset.ram || !newAsset.storage || !newAsset.screenSize)) {
      alert("Para Notebooks, RAM, Armazenamento e Tamanho da Tela são obrigatórios.");
      return;
    }

    if (newAsset.type === 'Desktop' && (!newAsset.ram || !newAsset.storage || !newAsset.caseModel)) {
      alert("Para Desktops, RAM, Armazenamento e Modelo do Gabinete são obrigatórios.");
      return;
    }

    if (newAsset.type === 'Monitor' && (!newAsset.screenSize || !newAsset.monitorInputs || newAsset.monitorInputs.length === 0)) {
      alert("Para Monitores, Tamanho da Tela e ao menos uma entrada de vídeo são obrigatórios.");
      return;
    }

    onAdd(newAsset as Omit<Asset, 'id' | 'createdAt' | 'qrCode'>);
    setShowForm(false);
    setNewAsset({ type: 'Notebook', status: 'Pendente Documentos', photos: [], departmentId: companies[0]?.id || '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [] });
  };

  const handleBulkAddRow = () => {
    setBulkEntries([...bulkEntries, { 
      tempId: Math.random().toString(), 
      departmentId: companies[0]?.id || '', 
      type: 'Notebook', 
      brand: '', 
      model: '', 
      ram: '',
      storage: '',
      screenSize: '',
      caseModel: '',
      isWireless: false,
      monitorInputs: [],
      id: '', 
      assignedTo: '', 
      observations: '' 
    }]);
  };

  const handleBulkRemoveRow = (tempId: string) => {
    setBulkEntries(bulkEntries.filter(e => e.tempId !== tempId));
  };

  const handleBulkSave = () => {
    const invalid = bulkEntries.some(e => {
      const basicInfoMissing = !e.brand || !e.model || !e.id || !e.departmentId;
      const notebookInfoMissing = e.type === 'Notebook' && (!e.ram || !e.storage || !e.screenSize);
      const desktopInfoMissing = e.type === 'Desktop' && (!e.ram || !e.storage || !e.caseModel);
      const monitorInfoMissing = e.type === 'Monitor' && (!e.screenSize || e.monitorInputs.length === 0);
      return basicInfoMissing || notebookInfoMissing || desktopInfoMissing || monitorInfoMissing;
    });

    if (invalid) {
      alert("Por favor, preencha todos os campos obrigatórios (incluindo especificações para PC, Notebook e Monitores).");
      return;
    }

    bulkEntries.forEach(entry => {
      onAdd({
        id: entry.id,
        departmentId: entry.departmentId,
        type: entry.type,
        brand: entry.brand,
        model: entry.model,
        ram: (entry.type === 'Notebook' || entry.type === 'Desktop') ? entry.ram : undefined,
        storage: (entry.type === 'Notebook' || entry.type === 'Desktop') ? entry.storage : undefined,
        screenSize: (entry.type === 'Notebook' || entry.type === 'Monitor') ? entry.screenSize : undefined,
        caseModel: entry.type === 'Desktop' ? entry.caseModel : undefined,
        isWireless: entry.type === 'Mouse' ? entry.isWireless : undefined,
        monitorInputs: entry.type === 'Monitor' ? entry.monitorInputs : undefined,
        observations: entry.observations,
        photos: [],
        status: entry.assignedTo ? 'Em Uso' : 'Disponível',
        assignedTo: entry.assignedTo || undefined,
      });
    });

    alert(`${bulkEntries.length} ativos cadastrados com sucesso!`);
    setShowBulkModal(false);
    setBulkEntries([{ tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], id: '', assignedTo: '', observations: '' }]);
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || a.type === filterType;
    const matchesDepartment = filterDepartment === 'all' || a.departmentId === filterDepartment;

    let matchesAvailability = true;
    if (filterAvailability === 'available') {
      matchesAvailability = !a.assignedTo;
    } else if (filterAvailability === 'assigned') {
      matchesAvailability = !!a.assignedTo;
    }

    return matchesSearch && matchesType && matchesAvailability && matchesDepartment;
  });

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';

  const toggleMonitorInput = (inputs: string[], type: string) => {
    return inputs.includes(type) ? inputs.filter(i => i !== type) : [...inputs, type];
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 print:hidden">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por modelo, marca ou ID..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-300 bg-white focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm font-semibold placeholder:text-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
          <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm">
             <button 
                onClick={() => setShowBulkModal(true)}
                className="flex items-center gap-2 px-4 py-2 text-xs font-black text-slate-800 hover:bg-slate-50 rounded-xl transition-all uppercase tracking-widest"
             >
                <FileSpreadsheet className="w-4 h-4 text-emerald-600" />
                Lançar Levantamento
             </button>
          </div>

          <button 
            onClick={() => setShowForm(true)}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black transition-all shadow-lg shadow-blue-200 uppercase tracking-widest text-xs"
          >
            <Plus className="w-5 h-5" />
            <span>Novo Ativo</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden print:hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Ativo / Departamento</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Tipo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Marca/Modelo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredAssets.map((asset) => (
                <tr 
                  key={asset.id} 
                  onClick={() => setSelectedAsset(asset)}
                  className="hover:bg-blue-50/50 transition-colors cursor-pointer group"
                >
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                      <span className="font-black text-slate-900 group-hover:text-blue-700">{asset.id}</span>
                      <div className="flex items-center gap-1 text-[10px] text-slate-700 font-black uppercase">
                        <Layers className="w-3 h-3" />
                        {getDepartmentName(asset.departmentId)}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                      <span className="text-xs font-black text-slate-800">{asset.type}</span>
                      {(asset.type === 'Notebook' || asset.type === 'Desktop') && (
                        <div className="flex gap-2 text-[8px] font-bold text-slate-500 uppercase mt-1">
                          <span>{asset.ram}</span>
                          <span>{asset.storage}</span>
                        </div>
                      )}
                      {asset.type === 'Monitor' && (
                        <div className="flex gap-2 text-[8px] font-bold text-slate-500 uppercase mt-1">
                          <span className="text-blue-600">{asset.screenSize}</span>
                          <span className="flex items-center gap-1">
                            <Zap className="w-2.5 h-2.5" />
                            {asset.monitorInputs?.join('/')}
                          </span>
                        </div>
                      )}
                      {asset.type === 'Mouse' && (
                        <div className={`flex items-center gap-1 text-[8px] font-black uppercase mt-1 ${asset.isWireless ? 'text-blue-600' : 'text-slate-500'}`}>
                           {asset.isWireless ? <Wifi className="w-2.5 h-2.5" /> : <Usb className="w-2.5 h-2.5" />}
                           {asset.isWireless ? 'S/ Fio' : 'C/ Fio'}
                        </div>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="font-bold text-slate-900">{asset.brand}</span>
                    <span className="text-sm text-slate-700 ml-2 font-medium">{asset.model}</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${
                      asset.status === 'Disponível' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' :
                      asset.status === 'Em Uso' ? 'bg-blue-50 text-blue-700 border-blue-200' : 'bg-slate-50 text-slate-700 border-slate-200'
                    }`}>
                      {asset.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
                    <button onClick={(e) => {e.stopPropagation(); onRemove(asset.id)}} className="p-2 text-slate-500 hover:text-rose-600 transition-colors">
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showBulkModal && (
        <div className="fixed inset-0 z-[200] flex flex-col bg-slate-900/95 backdrop-blur-xl animate-in fade-in duration-300 print:hidden">
          <div className="h-20 bg-slate-800/50 border-b border-white/10 flex items-center justify-between px-8 text-white">
             <div className="flex items-center gap-4">
               <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center">
                  <FileSpreadsheet className="w-6 h-6" />
               </div>
               <div>
                  <h3 className="font-black tracking-tight">Lançamento em Lote</h3>
                  <p className="text-[10px] text-slate-200 font-black uppercase tracking-widest">Transcreva os dados coletados em campo</p>
               </div>
            </div>
            <button onClick={() => setShowBulkModal(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
               <X className="w-6 h-6" />
            </button>
          </div>

          <div className="flex-1 overflow-auto p-8">
             <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200">
                <table className="w-full text-left">
                   <thead className="bg-slate-50 border-b border-slate-200">
