    ram: '',
    storage: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: [],
    isAbnt: true,
    hasNumericKeypad: true
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAsset.departmentId) {
      alert("Por favor, selecione o departamento responsável.");
      return;
    }

    if (newAsset.type === 'Notebook' && (!newAsset.ram || !newAsset.storage || !newAsset.screenSize)) {
      alert("Para Notebooks, RAM, Armazenamento e Tamanho da Tela são obrigatórios.");
      return;
    }

    if (newAsset.type === 'Desktop' && (!newAsset.ram || !newAsset.storage || !newAsset.caseModel)) {
      alert("Para Desktops, RAM, Armazenamento e Modelo do Gabinete são obrigatórios.");
      return;
    }

    if (newAsset.type === 'Monitor' && (!newAsset.screenSize || !newAsset.monitorInputs || newAsset.monitorInputs.length === 0)) {
      alert("Para Monitores, Tamanho da Tela e ao menos uma entrada de vídeo são obrigatórios.");
      return;
    }

    onAdd(newAsset as Omit<Asset, 'id' | 'createdAt' | 'qrCode'>);
    setShowForm(false);
    setNewAsset({ type: 'Notebook', status: 'Pendente Documentos', photos: [], departmentId: companies[0]?.id || '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true });
  };

  const handleBulkAddRow = () => {
    setBulkEntries([...bulkEntries, { 
      tempId: Math.random().toString(), 
      departmentId: companies[0]?.id || '', 
      type: 'Notebook', 
      brand: '', 
      model: '', 
      ram: '',
      storage: '',
      screenSize: '',
      caseModel: '',
      isWireless: false,
      monitorInputs: [],
      isAbnt: true,
      hasNumericKeypad: true,
      id: '', 
      assignedTo: '', 
      observations: '' 
    }]);
  };

  const handleBulkRemoveRow = (tempId: string) => {
    setBulkEntries(bulkEntries.filter(e => e.tempId !== tempId));
  };

  const handleBulkSave = () => {
    const invalid = bulkEntries.some(e => {
      const basicInfoMissing = !e.brand || !e.model || !e.id || !e.departmentId;
      const notebookInfoMissing = e.type === 'Notebook' && (!e.ram || !e.storage || !e.screenSize);
      const desktopInfoMissing = e.type === 'Desktop' && (!e.ram || !e.storage || !e.caseModel);
      const monitorInfoMissing = e.type === 'Monitor' && (!e.screenSize || e.monitorInputs.length === 0);
      return basicInfoMissing || notebookInfoMissing || desktopInfoMissing || monitorInfoMissing;
    });

    if (invalid) {
      alert("Por favor, preencha todos os campos obrigatórios (incluindo especificações técnicas).");
      return;
    }

    bulkEntries.forEach(entry => {
      onAdd({
        id: entry.id,
        departmentId: entry.departmentId,
        type: entry.type,
        brand: entry.brand,
        model: entry.model,
        ram: (entry.type === 'Notebook' || entry.type === 'Desktop') ? entry.ram : undefined,
        storage: (entry.type === 'Notebook' || entry.type === 'Desktop') ? entry.storage : undefined,
        screenSize: (entry.type === 'Notebook' || entry.type === 'Monitor') ? entry.screenSize : undefined,
        caseModel: entry.type === 'Desktop' ? entry.caseModel : undefined,
        isWireless: (entry.type === 'Mouse' || entry.type === 'Teclado') ? entry.isWireless : undefined,
        monitorInputs: entry.type === 'Monitor' ? entry.monitorInputs : undefined,
        isAbnt: entry.type === 'Teclado' ? entry.isAbnt : undefined,
        hasNumericKeypad: entry.type === 'Teclado' ? entry.hasNumericKeypad : undefined,
        observations: entry.observations,
        photos: [],
        status: entry.assignedTo ? 'Em Uso' : 'Disponível',
        assignedTo: entry.assignedTo || undefined,
      });
    });

    alert(`${bulkEntries.length} ativos cadastrados com sucesso!`);
    setShowBulkModal(false);
    setBulkEntries([{ tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' }]);
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || a.type === filterType;
    const matchesDepartment = filterDepartment === 'all' || a.departmentId === filterDepartment;

    let matchesAvailability = true;
    if (filterAvailability === 'available') {
      matchesAvailability = !a.assignedTo;
    } else if (filterAvailability === 'assigned') {
      matchesAvailability = !!a.assignedTo;
    }

    return matchesSearch && matchesType && matchesAvailability && matchesDepartment;
  });

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';

  const toggleMonitorInput = (inputs: string[], type: string) => {
    return inputs.includes(type) ? inputs.filter(i => i !== type) : [...inputs, type];
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 print:hidden">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por modelo, marca ou ID..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-300 bg-white focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm font-semibold placeholder:text-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
          <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm">
             <button 
                onClick={() => setShowBulkModal(true)}
                className="flex items-center gap-2 px-4 py-2 text-xs font-black text-slate-800 hover:bg-slate-50 rounded-xl transition-all uppercase tracking-widest"
             >
                <FileSpreadsheet className="w-4 h-4 text-emerald-600" />
                Lançar Levantamento
             </button>
          </div>

          <button 
            onClick={() => setShowForm(true)}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black transition-all shadow-lg shadow-blue-200 uppercase tracking-widest text-xs"
          >
            <Plus className="w-5 h-5" />
            <span>Novo Ativo</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden print:hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Ativo / Departamento</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Tipo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Marca/Modelo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredAssets.map((asset) => (
                <tr 
                  key={asset.id} 
                  onClick={() => setSelectedAsset(asset)}
                  className="hover:bg-blue-50/50 transition-colors cursor-pointer group"
