                        <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Especificações</th>
                        <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Vincular Usuário</th>
                        <th className="px-6 py-4 text-right"></th>
                      </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-100">
                      {bulkEntries.map((entry, idx) => (
                        <tr key={entry.tempId} className="hover:bg-slate-50/50 transition-colors">
                           <td className="px-6 py-4 space-y-2">
                              <select 
                                className="w-full p-2 bg-slate-100 rounded-xl text-xs font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500 text-slate-900"
                                value={entry.departmentId}
                                onChange={e => {
                                  const newEntries = [...bulkEntries];
                                  newEntries[idx].departmentId = e.target.value;
                                  setBulkEntries(newEntries);
                                }}
                              >
                                {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                              </select>
                              <select 
                                className="w-full p-2 bg-white rounded-xl text-xs font-bold border border-slate-300 outline-none focus:ring-2 focus:ring-emerald-500 text-slate-900"
                                value={entry.type}
                                onChange={e => {
                                  const newEntries = [...bulkEntries];
                                  newEntries[idx].type = e.target.value as AssetType;
                                  setBulkEntries(newEntries);
                                }}
                              >
                                {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                              </select>
                           </td>
                           <td className="px-6 py-4 space-y-2">
                              <div className="flex gap-2">
                                <input 
                                  className="w-1/2 p-2 bg-white border border-slate-300 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-emerald-500 text-slate-900 placeholder:text-slate-600"
                                  placeholder="Marca"
                                  value={entry.brand}
                                  onChange={e => {
                                    const newEntries = [...bulkEntries];
                                    newEntries[idx].brand = e.target.value;
                                    setBulkEntries(newEntries);
                                  }}
                                />
                                <input 
                                  className="w-1/2 p-2 bg-white border border-slate-300 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-emerald-500 text-slate-900 placeholder:text-slate-600"
                                  placeholder="Modelo"
                                  value={entry.model}
                                  onChange={e => {
                                    const newEntries = [...bulkEntries];
                                    newEntries[idx].model = e.target.value;
                                    setBulkEntries(newEntries);
                                  }}
                                />
                              </div>
                              <input 
                                className="w-full p-2 bg-slate-100 border border-slate-300 rounded-xl text-xs font-mono font-black outline-none focus:ring-2 focus:ring-emerald-500 text-center uppercase text-slate-900"
                                placeholder="ID PATRIMONIAL"
                                value={entry.id}
                                onChange={e => {
                                  const newEntries = [...bulkEntries];
                                  newEntries[idx].id = e.target.value;
                                  setBulkEntries(newEntries);
                                }}
                              />
                           </td>
                           <td className="px-6 py-4">
                              {entry.type === 'Notebook' || entry.type === 'Desktop' ? (
                                <div className="space-y-2">
                                  <div className="flex gap-1">
                                    <input 
                                      className="w-1/2 p-2 bg-blue-50 border border-blue-200 rounded-xl text-[10px] font-black outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 placeholder:text-slate-500"
                                      placeholder="RAM"
                                      value={entry.ram}
                                      onChange={e => {
                                        const newEntries = [...bulkEntries];
                                        newEntries[idx].ram = e.target.value;
                                        setBulkEntries(newEntries);
                                      }}
                                    />
                                    <input 
                                      className="w-1/2 p-2 bg-blue-50 border border-blue-200 rounded-xl text-[10px] font-black outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 placeholder:text-slate-500"
                                      placeholder="Disco"
                                      value={entry.storage}
                                      onChange={e => {
                                        const newEntries = [...bulkEntries];
                                        newEntries[idx].storage = e.target.value;
                                        setBulkEntries(newEntries);
                                      }}
                                    />
                                  </div>
                                  <input 
                                    className="w-full p-2 bg-blue-50 border border-blue-200 rounded-xl text-[10px] font-black outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                                    placeholder={entry.type === 'Notebook' ? "Tela (Ex: 14 pol)" : "Modelo Gabinete"}
                                    value={entry.type === 'Notebook' ? entry.screenSize : entry.caseModel}
                                    onChange={e => {
                                      const newEntries = [...bulkEntries];
                                      if(entry.type === 'Notebook') newEntries[idx].screenSize = e.target.value;
                                      else newEntries[idx].caseModel = e.target.value;
                                      setBulkEntries(newEntries);
                                    }}
                                  />
                                </div>
                              ) : entry.type === 'Monitor' ? (
                                <div className="space-y-2">
                                   <input 
                                    className="w-full p-2 bg-blue-50 border border-blue-200 rounded-xl text-[10px] font-black outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                                    placeholder="Tamanho (Ex: 24 polegadas)"
                                    value={entry.screenSize}
                                    onChange={e => {
                                      const newEntries = [...bulkEntries];
                                      newEntries[idx].screenSize = e.target.value;
                                      setBulkEntries(newEntries);
                                    }}
                                  />
                                  <div className="flex gap-1 bg-slate-100 p-1 rounded-xl">
                                     {['HDMI', 'VGA', 'DVI'].map(input => (
                                       <button 
