                                          const newEntries = [...bulkEntries];
                                          newEntries[idx].monitorInputs = toggleMonitorInput(newEntries[idx].monitorInputs, input);
                                          setBulkEntries(newEntries);
                                        }}
                                        className={`flex-1 py-1 text-[8px] font-black uppercase rounded-lg transition-all ${entry.monitorInputs.includes(input) ? 'bg-blue-600 text-white shadow-sm' : 'bg-white text-slate-400'}`}
                                       >
                                         {input}
                                       </button>
                                     ))}
                                  </div>
                                </div>
