                                          const newEntries = [...bulkEntries];
                                          newEntries[idx].isAbnt = !entry.isAbnt;
                                          setBulkEntries(newEntries);
                                        }}
                                        className={`flex-1 py-1 text-[8px] font-black uppercase rounded-lg transition-all ${entry.isAbnt ? 'bg-blue-600 text-white shadow-sm' : 'bg-white text-slate-400'}`}
                                      >
                                        ABNT2
                                      </button>
                                      <button 
                                        onClick={() => {
                                          const newEntries = [...bulkEntries];
                                          newEntries[idx].hasNumericKeypad = !entry.hasNumericKeypad;
                                          setBulkEntries(newEntries);
