            <div className="p-8 border-b border-slate-200 flex justify-between items-center bg-slate-50">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl">
                  <Plus className="w-6 h-6" />
                </div>
                <div>
                   <h3 className="text-2xl font-black text-slate-900 tracking-tight">Onboarding de Ativo</h3>
                   <p className="text-slate-700 text-sm font-bold">Cadastre um novo dispositivo individualmente.</p>
                </div>
              </div>
              <button onClick={() => setShowForm(false)} className="p-3 hover:bg-slate-200 rounded-full transition-colors text-slate-500 hover:text-slate-900">
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-10 overflow-y-auto space-y-8 bg-white">
               <div className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2 col-span-full">
                      <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Departamento Responsável</label>
                      <select className="w-full p-4 rounded-2xl border border-slate-300 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" value={newAsset.departmentId} onChange={(e) => setNewAsset({...newAsset, departmentId: e.target.value})} required>
                        {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Tipo</label>
                      <select className="w-full p-4 rounded-2xl border border-slate-300 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" value={newAsset.type} onChange={(e) => setNewAsset({...newAsset, type: e.target.value as AssetType})} required>
                        {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                      </select>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Marca</label>
                      <input className="w-full p-4 rounded-2xl border border-slate-300 font-bold text-slate-900 focus:ring-2 focus:ring-blue-600 placeholder:text-slate-400" placeholder="Ex: Logitech" value={newAsset.brand || ''} onChange={(e) => setNewAsset({...newAsset, brand: e.target.value})} required />
                    </div>
                    <div className="space-y-2 col-span-full">
                      <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Modelo</label>
                      <input className="w-full p-4 rounded-2xl border border-slate-300 font-bold text-slate-900 focus:ring-2 focus:ring-blue-600 placeholder:text-slate-400" placeholder="Ex: MX Keys S" value={newAsset.model || ''} onChange={(e) => setNewAsset({...newAsset, model: e.target.value})} required />
                    </div>
                  </div>

                  {newAsset.type === 'Teclado' && (
                    <div className="p-6 bg-slate-50 border border-slate-200 rounded-[2rem] space-y-6 animate-in fade-in slide-in-from-top-4">
                       <div className="flex items-center gap-2">
                         <Type className="w-5 h-5 text-blue-600" />
                         <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">Especificações do Teclado</h4>
                       </div>
                       <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          <div className="space-y-2">
                             <label className="text-[9px] font-black text-slate-500 uppercase ml-1 text-center block">Padrão</label>
                             <div className="flex bg-white p-1 rounded-xl border border-slate-200">
                                <button type="button" onClick={() => setNewAsset({...newAsset, isAbnt: true})} className={`flex-1 py-2 text-[9px] font-black uppercase rounded-lg transition-all ${newAsset.isAbnt ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400'}`}>ABNT2</button>
                                <button type="button" onClick={() => setNewAsset({...newAsset, isAbnt: false})} className={`flex-1 py-2 text-[9px] font-black uppercase rounded-lg transition-all ${!newAsset.isAbnt ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400'}`}>INTL</button>
                             </div>
                          </div>
                          <div className="space-y-2">
                             <label className="text-[9px] font-black text-slate-500 uppercase ml-1 text-center block">Teclado Numérico</label>
                             <div className="flex bg-white p-1 rounded-xl border border-slate-200">
                                <button type="button" onClick={() => setNewAsset({...newAsset, hasNumericKeypad: true})} className={`flex-1 py-2 text-[9px] font-black uppercase rounded-lg transition-all ${newAsset.hasNumericKeypad ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-400'}`}>Sim</button>
                                <button type="button" onClick={() => setNewAsset({...newAsset, hasNumericKeypad: false})} className={`flex-1 py-2 text-[9px] font-black uppercase rounded-lg transition-all ${!newAsset.hasNumericKeypad ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-400'}`}>Não</button>
                             </div>
                          </div>
                          <div className="space-y-2">
                             <label className="text-[9px] font-black text-slate-500 uppercase ml-1 text-center block">Conexão</label>
                             <div className="flex bg-white p-1 rounded-xl border border-slate-200">
                                <button type="button" onClick={() => setNewAsset({...newAsset, isWireless: false})} className={`flex-1 py-2 text-[9px] font-black uppercase rounded-lg transition-all ${!newAsset.isWireless ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400'}`}>C/ Fio</button>
                                <button type="button" onClick={() => setNewAsset({...newAsset, isWireless: true})} className={`flex-1 py-2 text-[9px] font-black uppercase rounded-lg transition-all ${newAsset.isWireless ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400'}`}>S/ Fio</button>
                             </div>
                          </div>
                       </div>
                    </div>
                  )}

                  {newAsset.type === 'Monitor' && (
                    <div className="p-6 bg-slate-50 border border-slate-200 rounded-[2rem] space-y-4 animate-in fade-in slide-in-from-top-4">
                       <div className="flex items-center gap-2 mb-2">
                         <Monitor className="w-5 h-5 text-blue-600" />
                         <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">Especificações do Monitor</h4>
                       </div>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                          <div className="space-y-1">
                            <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Tamanho da Tela</label>
                            <input className="w-full p-4 rounded-xl border border-slate-200 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" placeholder="Ex: 24 polegadas" value={newAsset.screenSize || ''} onChange={(e) => setNewAsset({...newAsset, screenSize: e.target.value})} required />
                          </div>
                          <div className="space-y-1">
                             <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Entradas de Vídeo</label>
                             <div className="flex gap-2 bg-white p-2 border border-slate-200 rounded-xl">
                                {['HDMI', 'VGA', 'DVI'].map(input => (
                                  <button key={input} type="button" onClick={() => setNewAsset({...newAsset, monitorInputs: toggleMonitorInput(newAsset.monitorInputs || [], input)})} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${newAsset.monitorInputs?.includes(input) ? 'bg-blue-600 text-white shadow-md' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}>
                                    {input}
                                  </button>
                                ))}
                             </div>
                          </div>
                       </div>
                    </div>
                  )}

                  {newAsset.type === 'Mouse' && (
                    <div className="p-6 bg-slate-50 border border-slate-200 rounded-[2rem] space-y-4 animate-in fade-in slide-in-from-top-4">
                        <div className="flex items-center gap-2 mb-2">
                         <Wifi className="w-5 h-5 text-blue-600" />
                         <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">Conectividade do Mouse</h4>
                       </div>
                       <div className="grid grid-cols-2 gap-4">
                          <button type="button" onClick={() => setNewAsset({...newAsset, isWireless: false})} className={`flex items-center justify-center gap-3 p-4 rounded-2xl border-2 transition-all font-black uppercase text-xs tracking-widest ${!newAsset.isWireless ? 'bg-white border-blue-600 text-blue-600 shadow-xl' : 'bg-white border-slate-100 text-slate-400'}`}>
                             <Usb className="w-5 h-5" /> Com Fio
                          </button>
                          <button type="button" onClick={() => setNewAsset({...newAsset, isWireless: true})} className={`flex items-center justify-center gap-3 p-4 rounded-2xl border-2 transition-all font-black uppercase text-xs tracking-widest ${newAsset.isWireless ? 'bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-100' : 'bg-white border-slate-100 text-slate-400'}`}>
                             <Wifi className="w-5 h-5" /> Sem Fio
                          </button>
                       </div>
                    </div>
                  )}

                  {(newAsset.type === 'Notebook' || newAsset.type === 'Desktop') && (
                    <div className="p-6 bg-blue-50 border border-blue-200 rounded-[2rem] space-y-4 animate-in fade-in slide-in-from-top-4">
                       <div className="flex items-center gap-2 mb-2">
                         <Cpu className="w-5 h-5 text-blue-600" />
                         <h4 className="text-xs font-black text-blue-900 uppercase tracking-widest">Especificações Técnicas {newAsset.type === 'Desktop' ? '(Desktop)' : '(Notebook)'}</h4>
                       </div>
                       <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                         <div className="space-y-1">
                           <label className="text-[9px] font-black text-blue-700 uppercase ml-1">Memória RAM</label>
                           <input className="w-full p-3 rounded-xl border border-blue-200 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" placeholder="Ex: 16GB" value={newAsset.ram || ''} onChange={(e) => setNewAsset({...newAsset, ram: e.target.value})} required />
                         </div>
                         <div className="space-y-1">
                           <label className="text-[9px] font-black text-blue-700 uppercase ml-1">Armazenamento</label>
                           <input className="w-full p-3 rounded-xl border border-blue-200 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" placeholder="Ex: 512GB SSD" value={newAsset.storage || ''} onChange={(e) => setNewAsset({...newAsset, storage: e.target.value})} required />
                         </div>
                         <div className="space-y-1">
                           <label className="text-[9px] font-black text-blue-700 uppercase ml-1">{newAsset.type === 'Notebook' ? 'Tela' : 'Gabinete'}</label>
                           <input className="w-full p-3 rounded-xl border border-blue-200 bg-white font-bold text-slate-900 focus:ring-2 focus:ring-blue-600" placeholder={newAsset.type === 'Notebook' ? "Ex: 14 pol" : "Ex: Torre ATX"} value={newAsset.type === 'Notebook' ? (newAsset.screenSize || '') : (newAsset.caseModel || '')} onChange={(e) => {
                                 if(newAsset.type === 'Notebook') setNewAsset({...newAsset, screenSize: e.target.value});
                                 else setNewAsset({...newAsset, caseModel: e.target.value});
                               }} required />
                         </div>
                       </div>
                    </div>
                  )}

                  <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 uppercase tracking-widest transition-all active:scale-95 text-sm">Finalizar Cadastro</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AssetManager;

import React, { useState, useMemo } from 'react';
import { 
  Wrench, 
  Search, 
  Plus, 
  X, 
  Activity, 
  CheckCircle2, 
  Package, 
  AlertCircle,
  Building2,
  Clock,
  ChevronRight,
  Info,
  Layers,
  ArrowRight,
  User,
  Settings2
} from 'lucide-react';
import { Asset, AssetStatus, Employee, Department } from '../types';

interface MaintenanceManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  onUpdateAsset: (asset: Asset) => void;
}

const MaintenanceManager: React.FC<MaintenanceManagerProps> = ({ assets, employees, companies, onUpdateAsset }) => {
  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [selectedAssetId, setSelectedAssetId] = useState('');
  const [maintenanceType, setMaintenanceType] = useState<'Preventiva' | 'Corretiva'>('Preventiva');
  const [maintenanceScope, setMaintenanceScope] = useState<'Interna' | 'Externa'>('Interna');
  const [reason, setReason] = useState('');

  const assetsInMaintenance = useMemo(() => 
    assets.filter(a => a.status === 'Manutenção')
  , [assets]);

  const availableForMaintenance = useMemo(() => 
    assets.filter(a => a.status !== 'Manutenção' && a.status !== 'Baixado')
  , [assets]);

  const filteredAvailable = availableForMaintenance.filter(a => 
    a.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
    a.model.toLowerCase().includes(searchTerm.toLowerCase()) ||
    a.brand.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleOpenMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAssetId) return;

    const asset = assets.find(a => a.id === selectedAssetId);
    if (!asset) return;

    const updatedAsset: Asset = {
      ...asset,
      status: 'Manutenção',
      observations: `[${maintenanceType} | ${maintenanceScope}] ${reason}`
    };

    onUpdateAsset(updatedAsset);
    setShowModal(false);
    setSelectedAssetId('');
    setReason('');
    setSearchTerm('');
  };

  const handleConcludeMaintenance = (assetId: string) => {
    const asset = assets.find(a => a.id === assetId);
    if (!asset) return;

    const updatedAsset: Asset = {
      ...asset,
      status: 'Disponível',
      observations: `Manutenção concluída em ${new Date().toLocaleDateString('pt-BR')}. Equipamento retornado ao estoque.`
    };

    onUpdateAsset(updatedAsset);
  };

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';
  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'N/A';

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-2xl font-black text-slate-800 tracking-tight">Centro de Manutenção</h3>
          <p className="text-slate-500 font-medium italic">Gestão técnica de ativos fora de operação.</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-amber-600 hover:bg-amber-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-amber-100 flex items-center gap-2 transition-all transform active:scale-95"
        >
          <Wrench className="w-5 h-5" />
          Abrir Manutenção
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {assetsInMaintenance.map(asset => (
          <div key={asset.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm hover:shadow-md transition-all group flex flex-col">
            <div className="flex justify-between items-start mb-6">
              <div className="w-14 h-14 bg-amber-50 rounded-2xl flex items-center justify-center text-amber-600 group-hover:bg-amber-600 group-hover:text-white transition-all duration-500 shadow-sm">
                <Activity className="w-7 h-7" />
              </div>
              <div className="flex flex-col items-end">
                 <span className="bg-amber-600 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest mb-1 shadow-lg shadow-amber-100">
                    Em Manutenção
                 </span>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter font-mono">{asset.id}</p>
              </div>
            </div>

            <div className="space-y-1 mb-6">
              <h4 className="text-xl font-black text-slate-800 tracking-tight leading-none">{asset.type}</h4>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{asset.brand} {asset.model}</p>
              <div className="flex items-center gap-1 text-[10px] text-slate-400 font-bold uppercase pt-2">
                <Layers className="w-3 h-3" /> {getDepartmentName(asset.departmentId)}
              </div>
            </div>

            <div className="bg-amber-50/50 p-4 rounded-2xl border border-amber-100 mb-6 flex-1">
               <div className="flex items-center gap-2 text-amber-600 mb-2">
                  <Info className="w-4 h-4" />
                  <span className="text-[10px] font-black uppercase">Laudo Técnico</span>
               </div>
               <p className="text-xs text-slate-600 font-medium leading-relaxed italic">
                 "{asset.observations}"
               </p>
            </div>

            <button 
              onClick={() => handleConcludeMaintenance(asset.id)}
              className="w-full bg-slate-900 hover:bg-black text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl flex items-center justify-center gap-2 transition-all"
            >
              <CheckCircle2 className="w-4 h-4 text-emerald-400" />
              Concluir Reparo
            </button>
          </div>
        ))}

        {assetsInMaintenance.length === 0 && (
          <div className="col-span-full py-32 bg-slate-50 rounded-[3rem] border border-dashed border-slate-200 flex flex-col items-center justify-center text-center space-y-4">
             <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-sm">
                <Settings2 className="w-10 h-10 text-slate-200" />
             </div>
             <div>
                <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Bancada Técnica Vazia</p>
                <p className="text-[10px] text-slate-300 font-bold uppercase mt-1">Nenhum equipamento aguardando manutenção.</p>
             </div>
          </div>
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-300">
              <div className="p-8 border-b border-slate-100 bg-amber-600 text-white flex items-center justify-between">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center">
                       <Wrench className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-2xl font-black tracking-tight">Ordem de Serviço</h3>
                       <p className="text-amber-100 text-[10px] font-black uppercase tracking-widest">Entrada de Ativo para Manutenção</p>
                    </div>
                 </div>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full">
                    <X className="w-6 h-6" />
                 </button>
              </div>

              <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                 {/* Asset Search Section */}
                 <div className="w-full lg:w-1/2 border-r border-slate-100 flex flex-col p-8 bg-slate-50/50">
                    <div className="relative mb-6">
                       <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                       <input 
                         type="text"
                         placeholder="Buscar por ID, Marca ou Modelo..."
                         className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-amber-500 outline-none font-bold shadow-sm"
                         value={searchTerm}
                         onChange={(e) => setSearchTerm(e.target.value)}
                       />
                    </div>

                    <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
                       {filteredAvailable.map(asset => (
                         <button 
                          key={asset.id}
                          onClick={() => setSelectedAssetId(asset.id)}
                          className={`w-full p-4 rounded-2xl border transition-all flex items-center justify-between group ${
                            selectedAssetId === asset.id 
                              ? 'bg-amber-600 border-amber-600 text-white shadow-xl' 
                              : 'bg-white border-slate-200 text-slate-800 hover:border-amber-300'
                          }`}
                         >
                            <div className="flex items-center gap-3">
                               <Package className={`w-5 h-5 ${selectedAssetId === asset.id ? 'text-white' : 'text-slate-400'}`} />
                               <div className="text-left">
                                  <p className="text-xs font-black uppercase tracking-tight">{asset.type}</p>
                                  <p className={`text-[10px] font-bold ${selectedAssetId === asset.id ? 'text-amber-100' : 'text-slate-500'}`}>
                                    {asset.brand} {asset.model} • {asset.id}
                                  </p>
                               </div>
                            </div>
                            <ArrowRight className={`w-4 h-4 transition-transform ${selectedAssetId === asset.id ? 'translate-x-1' : 'opacity-0 group-hover:opacity-100'}`} />
                         </button>
                       ))}

                       {filteredAvailable.length === 0 && (
                         <div className="text-center py-10">
                            <AlertCircle className="w-10 h-10 text-slate-300 mx-auto mb-2" />
                            <p className="text-xs text-slate-400 font-bold">Nenhum ativo compatível encontrado.</p>
                         </div>
                       )}
                    </div>
                 </div>

                 {/* Form Section */}
                 <div className="flex-1 p-8 bg-white overflow-y-auto custom-scrollbar">
                    <form onSubmit={handleOpenMaintenance} className="space-y-8">
                       <div className="grid grid-cols-2 gap-4">
                          <div className="space-y-2">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo Manutenção</label>
                             <div className="flex bg-slate-100 p-1 rounded-xl">
                                <button 
                                  type="button"
                                  onClick={() => setMaintenanceType('Preventiva')}
                                  className={`flex-1 py-3 text-[10px] font-black uppercase rounded-lg transition-all ${maintenanceType === 'Preventiva' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'}`}
                                >
                                  Preventiva
                                </button>
                                <button 
                                  type="button"
                                  onClick={() => setMaintenanceType('Corretiva')}
                                  className={`flex-1 py-3 text-[10px] font-black uppercase rounded-lg transition-all ${maintenanceType === 'Corretiva' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'}`}
                                >
                                  Corretiva
                                </button>
                             </div>
                          </div>
                          <div className="space-y-2">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Local / Escopo</label>
                             <div className="flex bg-slate-100 p-1 rounded-xl">
                                <button 
                                  type="button"
                                  onClick={() => setMaintenanceScope('Interna')}
                                  className={`flex-1 py-3 text-[10px] font-black uppercase rounded-lg transition-all ${maintenanceScope === 'Interna' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'}`}
                                >
                                  Interna
                                </button>
                                <button 
                                  type="button"
                                  onClick={() => setMaintenanceScope('Externa')}
                                  className={`flex-1 py-3 text-[10px] font-black uppercase rounded-lg transition-all ${maintenanceScope === 'Externa' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'}`}
                                >
                                  Externa
                                </button>
                             </div>
                          </div>
                       </div>

                       <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Laudo de Entrada / Motivo</label>
                          <textarea 
                            className="w-full p-5 rounded-[2rem] border border-slate-200 bg-slate-50 focus:ring-2 focus:ring-amber-500 outline-none resize-none h-40 font-medium text-slate-700 placeholder:text-slate-400"
                            placeholder="Descreva o problema ou as ações preventivas que serão realizadas..."
                            value={reason}
                            onChange={(e) => setReason(e.target.value)}
                            required
                          />
                       </div>

                       {selectedAssetId && (
                         <div className="p-6 bg-amber-50 rounded-[2.5rem] border border-amber-100 flex items-start gap-4">
                            <Info className="w-6 h-6 text-amber-600 shrink-0" />
                            <div>
                               <p className="text-[10px] font-black text-amber-700 uppercase tracking-tight">Aviso de Operação</p>
                               <p className="text-xs text-amber-800 font-bold leading-relaxed mt-1">
                                  Ao confirmar, o ativo será retirado do responsável atual ({getEmployeeName(assets.find(a => a.id === selectedAssetId)?.assignedTo)}) e entrará em status de indisponibilidade no estoque.
                               </p>
                            </div>
                         </div>
                       )}

                       <button 
                        type="submit"
                        disabled={!selectedAssetId}
                        className={`w-full py-5 rounded-[2rem] font-black shadow-xl transition-all uppercase tracking-widest text-xs flex items-center justify-center gap-3 ${
                          selectedAssetId 
                            ? 'bg-amber-600 hover:bg-amber-700 text-white shadow-amber-100' 
                            : 'bg-slate-100 text-slate-300 cursor-not-allowed border border-slate-200'
                        }`}
                       >
                          <Wrench className="w-5 h-5" /> Iniciar Manutenção do Ativo
                       </button>
                    </form>
                 </div>
              </div>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 5px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #e2e8f0;
          border-radius: 10px;
        }
      `}</style>
    </div>
  );
};

