                                       <input className="w-1/2 p-2 bg-blue-50 border border-blue-200 rounded-xl text-[10px] font-black" placeholder="RAM" value={entry.ram} onChange={e => {const n=[...bulkEntries]; n[idx].ram=e.target.value; setBulkEntries(n)}} />
                                       <input className="w-1/2 p-2 bg-blue-50 border border-blue-200 rounded-xl text-[10px] font-black" placeholder="Disco" value={entry.storage} onChange={e => {const n=[...bulkEntries]; n[idx].storage=e.target.value; setBulkEntries(n)}} />
