                                         {['HDMI', 'VGA', 'DVI'].map(v => (
                                           <button key={v} onClick={() => {const n=[...bulkEntries]; n[idx].monitorInputs = toggleMonitorInput(n[idx].monitorInputs, v); setBulkEntries(n)}} className={`flex-1 py-1 text-[8px] font-black uppercase rounded-lg transition-all ${entry.monitorInputs.includes(v) ? 'bg-blue-600 text-white' : 'bg-white text-slate-400'}`}>{v}</button>
