                                       <button onClick={() => {const n=[...bulkEntries]; n[idx].isAbnt = !entry.isAbnt; setBulkEntries(n)}} className={`py-1 text-[8px] font-black uppercase rounded-lg transition-all ${entry.isAbnt ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>ABNT2</button>
