                      {asset.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
                    <button onClick={async (e) => {e.stopPropagation(); if(confirm("Remover este ativo permanentemente?")) await onRemove(asset.id)}} className="p-2 text-slate-400 hover:text-rose-600 transition-colors">
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </td>
                </tr>
