                            value={manualLog}
                            onChange={(e) => setManualLog(e.target.value)}
                          />
                          <button 
                            onClick={handleAddManualLog}
                            className="bg-slate-900 text-white p-3 rounded-xl hover:bg-black transition-colors shadow-lg"
                          >
                            <MessageSquarePlus className="w-5 h-5" />
                          </button>
                       </div>
                    </div>

