                                entry.type === 'Manutenção' ? 'bg-amber-500' :
                                entry.type === 'Atribuição' ? 'bg-blue-600' :
                                entry.type === 'Criação' ? 'bg-emerald-500' :
                                entry.type === 'Status' ? 'bg-rose-500' : 'bg-slate-400'
                              }`}>
                                {entry.type === 'Manutenção' && <Wrench className="w-3 h-3 text-white" />}
                                {entry.type === 'Atribuição' && <User className="w-3 h-3 text-white" />}
                                {entry.type === 'Criação' && <CheckCircle2 className="w-3 h-3 text-white" />}
                                {entry.type === 'Status' && <Clock className="w-3 h-3 text-white" />}
                                {entry.type === 'Observação' && <AlertCircle className="w-3 h-3 text-white" />}
                              </div>

                              <div className="space-y-1">
                                 <div className="flex items-center justify-between">
                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                                       {new Date(entry.date).toLocaleDateString('pt-BR')} {new Date(entry.date).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'})}
                                    </p>
                                    <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full ${
                                       entry.type === 'Manutenção' ? 'bg-amber-100 text-amber-700' :
                                       entry.type === 'Atribuição' ? 'bg-blue-100 text-blue-700' :
                                       entry.type === 'Criação' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-700'
                                    }`}>
                                       {entry.type}
                                    </span>
                                 </div>
                                 <p className="text-sm text-slate-800 font-bold leading-relaxed">{entry.description}</p>
                                 <p className="text-[9px] text-slate-400 font-black uppercase">Executor: {entry.performedBy || 'Sistema'}</p>
                              </div>
                           </div>
                         ))
                       ) : (
                         <div className="text-center py-10 opacity-30">
                            <Clock className="w-10 h-10 mx-auto mb-2" />
                            <p className="text-xs font-bold uppercase tracking-widest">Nenhum histórico registrado</p>
                         </div>
                       )}
                    </div>
                 </div>
              </div>

              <div className="p-8 bg-slate-50 border-t border-slate-100 flex justify-end">
                 <button onClick={() => {setDetailAsset(null); setManualLog('');}} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl shadow-slate-200 transition-all active:scale-95">Fechar Detalhes</button>
              </div>
           </div>
        </div>
      )}

      {/* Modal de Lançamento em Lote Restaurado (Full Tech) */}
      {showBulkModal && (
        <div className="fixed inset-0 z-[200] flex flex-col bg-slate-900/95 backdrop-blur-xl animate-in fade-in duration-300 print:hidden">
          <div className="h-20 bg-slate-800/50 border-b border-white/10 flex items-center justify-between px-8 text-white">
             <div className="flex items-center gap-4">
               <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center">
                  <FileSpreadsheet className="w-6 h-6" />
               </div>
               <div>
                  <h3 className="font-black tracking-tight">Levantamento de Campo em Lote</h3>
                  <p className="text-[10px] text-slate-200 font-black uppercase tracking-widest">Transcreva os dados coletados fisicamente</p>
               </div>
            </div>
            <button onClick={() => setShowBulkModal(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
               <X className="w-6 h-6" />
            </button>
          </div>

          <div className="flex-1 overflow-auto p-8">
             <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200">
                <div className="overflow-x-auto">
                   <table className="w-full text-left min-w-[1200px]">
                      <thead className="bg-slate-50 border-b border-slate-200">
                         <tr>
                           <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase w-48 tracking-widest">Depto / Tipo</th>
                           <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Identificação</th>
                           <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Especificações Técnicas</th>
                           <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Status / Vínculo</th>
                           <th className="px-6 py-4 text-right"></th>
                         </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                         {bulkEntries.map((entry, idx) => (
                           <tr key={entry.tempId} className="hover:bg-slate-50/50 transition-colors">
                              <td className="px-6 py-4 space-y-2">
                                 <select 
                                   className="w-full p-2 bg-slate-100 rounded-xl text-xs font-bold border-none"
                                   value={entry.departmentId}
                                   onChange={e => {
                                     const newEntries = [...bulkEntries];
                                     newEntries[idx].departmentId = e.target.value;
                                     setBulkEntries(newEntries);
                                   }}
                                 >
                                   {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                 </select>
                                 <select 
                                   className="w-full p-2 bg-white rounded-xl text-xs font-bold border border-slate-300"
                                   value={entry.type}
                                   onChange={e => {
                                     const newEntries = [...bulkEntries];
                                     newEntries[idx].type = e.target.value as AssetType;
                                     setBulkEntries(newEntries);
                                   }}
                                 >
                                   {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                                 </select>
                              </td>
                              <td className="px-6 py-4 space-y-2">
                                 <div className="flex gap-2">
                                   <input className="w-1/2 p-2 bg-white border border-slate-300 rounded-xl text-xs font-bold" placeholder="Marca" value={entry.brand} onChange={e => {const n=[...bulkEntries]; n[idx].brand=e.target.value; setBulkEntries(n)}} />
                                   <input className="w-1/2 p-2 bg-white border border-slate-300 rounded-xl text-xs font-bold" placeholder="Modelo" value={entry.model} onChange={e => {const n=[...bulkEntries]; n[idx].model=e.target.value; setBulkEntries(n)}} />
