import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import Auth from './components/Auth';
import { MOCK_USERS, MOCK_ASSETS, MOCK_DEPARTMENTS, MOCK_EMPLOYEES } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, Department, AuditSession, HistoryEntry } from './types';
import { db } from './services/supabase';
import { Loader2, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);

  // Carregamento inicial do Supabase
  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      setError(null);
      try {
        // Tentamos carregar do banco. Se falhar (ex: tabelas não criadas), usamos mocks.
        // Se retornar vazio [], significa que o banco está pronto mas sem dados.
        const [depts, assts, emps, reqs, audits, userList] = await Promise.all([
          db.departments.list().catch(e => { console.warn("Usando Mocks para Departments"); return MOCK_DEPARTMENTS; }),
          db.assets.list().catch(e => { console.warn("Usando Mocks para Assets"); return MOCK_ASSETS; }),
          db.employees.list().catch(e => { console.warn("Usando Mocks para Employees"); return MOCK_EMPLOYEES; }),
          db.requests.list().catch(() => []),
          db.auditSessions.list().catch(() => []),
          db.users.list().catch(e => { console.warn("Usando Mocks para Users"); return MOCK_USERS; })
        ]);

        setDepartments(depts);
        setAssets(assts);
        setEmployees(emps);
        setRequests(reqs);
        setAuditSessions(audits);
        setUsers(userList);
      } catch (err) {
        setError("Erro de sincronização. Verifique as tabelas no Supabase.");
        console.error(err);
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, []);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 9000) + 1000}`;
    const initialHistory: HistoryEntry[] = assetData.history || [
      {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Criação',
        description: 'Ativo registrado no inventário via persistência Supabase.',
        performedBy: currentUser?.name || 'Administrador'
      }
    ];

    if (assetData.assignedTo && !assetData.history) {
      initialHistory.push({
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Atribuição',
        description: 'Atribuição inicial de usuário sincronizada.',
        userContext: employees.find(e => e.id === assetData.assignedTo)?.name
      });
    }

    const newAsset: Asset = { 
      ...assetData, 
      id, 
      qrCode: `QR-${id}`,
      createdAt: new Date().toISOString(),
      history: initialHistory
    };

    setAssets(prev => [newAsset, ...prev]);
    await db.assets.upsert(newAsset);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    setAssets(prev => prev.map(a => a.id === updated.id ? updated : a));
    await db.assets.upsert(updated);
  };

  const handleRemoveAsset = async (id: string) => {
    setAssets(prev => prev.filter(a => a.id !== id));
    await db.assets.remove(id);
  };

  const handleAddRequest = async (reqData: any) => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const newReq: EquipmentRequest = { 
      ...reqData, 
      id, 
      status: 'Pendente',
      createdAt: new Date().toISOString()
    };
    setRequests(prev => [newReq, ...prev]);
    await db.requests.upsert(newReq);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    setRequests(prev => prev.map(r => r.id === req.id ? req : r));
    await db.requests.upsert(req);
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    setAuditSessions(prev => prev.map(old => old.id === session.id ? session : old));
    await db.auditSessions.upsert(session);
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4">
          <Loader2 className="w-12 h-12 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-xs">Sincronizando com Supabase...</p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4 text-center">
          <AlertCircle className="w-16 h-16 text-rose-500" />
          <h3 className="text-xl font-black text-slate-800 tracking-tight">Erro Crítico de Banco</h3>
          <p className="text-slate-500 max-w-sm">{error}</p>
          <button onClick={() => window.location.reload()} className="mt-4 px-6 py-2 bg-slate-900 text-white rounded-xl font-bold uppercase text-[10px] tracking-widest">Tentar Novamente</button>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard assets={assets} requests={requests} employees={employees} />;
      case 'departments': return <CompanyManager companies={departments} assets={assets} onAddCompany={async (d) => { const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; setDepartments(prev => [...prev, newD]); await db.departments.upsert(newD); }} onUpdateCompany={async (updated) => { setDepartments(prev => prev.map(d => d.id === updated.id ? updated : d)); await db.departments.upsert(updated); }} onRemoveCompany={async (id) => { setDepartments(prev => prev.filter(d => d.id !== id)); await db.departments.remove(id); }} />;
      case 'assets': return <AssetManager assets={assets} employees={employees} companies={departments} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={handleRemoveAsset} />;
      case 'employees': return <EmployeeManager employees={employees} departments={departments} onAdd={async (e) => { const newE = {...e, id: `EMP-${Date.now()}`}; setEmployees(prev => [...prev, newE]); await db.employees.upsert(newE); }} />;
      case 'requests': return <RequestsManager requests={requests} employees={employees} assets={assets} onAddRequest={handleAddRequest} onUpdateRequest={handleUpdateRequest} onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if(req) handleUpdateRequest({...req, status}); }} />;
      case 'inventory-check': return <InventoryCheckManager assets={assets} employees={employees} auditSessions={auditSessions} onAddAuditSession={async (s) => { setAuditSessions(prev => [s, ...prev]); await db.auditSessions.upsert(s); }} onUpdateAuditSession={handleUpdateAuditSession} onGenerateDivergenceRequest={(sector, assetIds) => handleAddRequest({ requesterId: currentUser?.id, employeeId: employees.find(e => e.sector === sector)?.id || '', items: assets.filter(a => assetIds.includes(a.id)).map(a => a.type), type: 'Divergencia', observation: `Divergência de auditoria no setor ${sector}` })} />;
      case 'maintenance': return <MaintenanceManager assets={assets} employees={employees} companies={departments} onUpdateAsset={handleUpdateAsset} />;
      case 'purchase-orders': return <PurchaseOrderManager requests={requests} employees={employees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} />;
      case 'printing': return <PrintManager assets={assets} />;
      case 'user-management': return <UserManager users={users} onAddUser={async (u) => { const newU = {...u, id: Date.now().toString()}; setUsers(prev => [...prev, newU]); await db.users.upsert(newU); }} onUpdateUser={async (u) => { setUsers(prev => prev.map(old => old.id === u.id ? u : old)); await db.users.upsert(u); }} onRemoveUser={async (id) => { setUsers(prev => prev.filter(u => u.id !== id)); await db.users.remove(id); }} />;
      default: return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
    }
  };

  if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} requests={requests}>
      {renderContent()}
    </Layout>
  );
};

export default App;

