  observations: string;
}

const AssetManager: React.FC<AssetManagerProps> = ({ assets, employees, companies, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<string>('all');
  const [isSavingBulk, setIsSavingBulk] = useState(false);
  const [manualLog, setManualLog] = useState('');
  const [isUpdatingDept, setIsUpdatingDept] = useState(false);

  const [bulkEntries, setBulkEntries] = useState<BulkAssetEntry[]>([]);
  const [newAsset, setNewAsset] = useState<Partial<Asset>>({
    type: 'Notebook',
    status: 'Disponível',
    photos: [],
    departmentId: '',
    ram: '',
    storage: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: [],
    isAbnt: true,
    hasNumericKeypad: true
  });

  useEffect(() => {
    if (companies.length > 0 && !newAsset.departmentId) {
      setNewAsset(prev => ({ ...prev, departmentId: companies[0].id }));
      setBulkEntries([{ 
        tempId: '1', departmentId: companies[0].id, type: 'Notebook', brand: '', model: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' 
      }]);
    }
  }, [companies, showForm, showBulkModal]);

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';
  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'Em Estoque';

  const handleDepartmentChange = async (newDeptId: string) => {
    if (!detailAsset || newDeptId === detailAsset.departmentId) return;

    setIsUpdatingDept(true);
    const oldDeptName = getDepartmentName(detailAsset.departmentId);
    const newDeptName = getDepartmentName(newDeptId);

    const transferLog: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Status',
      description: `Transferência de departamento: de "${oldDeptName}" para "${newDeptName}".`,
      performedBy: 'Gestor de Ativos'
    };

    const updatedAsset: Asset = {
      ...detailAsset,
      departmentId: newDeptId,
      history: [...(detailAsset.history || []), transferLog]
    };

    try {
      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err) {
      alert("Erro ao transferir departamento.");
    } finally {
      setIsUpdatingDept(false);
    }
  };

  const handleAddManualLog = async () => {
    if (!detailAsset || !manualLog.trim()) return;

    const newEntry: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Observação',
      description: manualLog,
      performedBy: 'Gestor de TI'
    };

    const updatedAsset: Asset = {
      ...detailAsset,
      history: [...(detailAsset.history || []), newEntry]
    };

    await onUpdate(updatedAsset);
    setDetailAsset(updatedAsset);
    setManualLog('');
  };

  const handleStatusChangeManual = async (newStatus: AssetStatus) => {
    if (!detailAsset) return;

    const newEntry: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Status',
      description: `Status alterado manualmente de ${detailAsset.status} para ${newStatus}.`,
      performedBy: 'Gestor de TI'
    };

    const updatedAsset: Asset = {
      ...detailAsset,
      status: newStatus,
      history: [...(detailAsset.history || []), newEntry]
    };

    await onUpdate(updatedAsset);
    setDetailAsset(updatedAsset);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAsset.departmentId) {
      alert("Selecione ou crie um departamento primeiro.");
      return;
    }
    await onAdd(newAsset as any);
    setShowForm(false);
    setNewAsset({ type: 'Notebook', status: 'Disponível', photos: [], departmentId: companies[0]?.id || '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true });
  };

  const handleBulkAddRow = () => {
    setBulkEntries([...bulkEntries, { 
      tempId: Math.random().toString(), 
      departmentId: companies[0]?.id || '', 
      type: 'Notebook', 
      brand: '', 
      model: '', 
      ram: '',
      storage: '',
      screenSize: '',
      caseModel: '',
      isWireless: false,
      monitorInputs: [],
      isAbnt: true,
      hasNumericKeypad: true,
      id: '', 
      assignedTo: '', 
      observations: '' 
    }]);
  };

  const handleBulkSave = async () => {
    if (companies.length === 0) {
      alert("Erro: Você precisa cadastrar pelo menos um Departamento antes.");
      return;
    }

    setIsSavingBulk(true);
    try {
      for (const entry of bulkEntries) {
        if (!entry.id) continue;
        await onAdd({
          id: entry.id,
          departmentId: entry.departmentId || companies[0].id,
          type: entry.type,
          brand: entry.brand,
          model: entry.model,
          ram: entry.ram,
          storage: entry.storage,
          screenSize: entry.screenSize,
          caseModel: entry.caseModel,
          isWireless: entry.isWireless,
          monitorInputs: entry.monitorInputs,
          isAbnt: entry.isAbnt,
          hasNumericKeypad: entry.hasNumericKeypad,
          observations: entry.observations,
          photos: [],
          status: entry.assignedTo ? 'Em Uso' : 'Disponível',
          assignedTo: entry.assignedTo || undefined,
        });
      }
      setShowBulkModal(false);
      setBulkEntries([{ tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' }]);
    } catch (err) {
      alert("Erro ao salvar ativos em lote.");
    } finally {
      setIsSavingBulk(false);
    }
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || a.type === filterType;
    return matchesSearch && matchesType;
  });

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 print:hidden">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por modelo, marca ou ID..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-300 bg-white focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm font-semibold placeholder:text-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
          <button onClick={() => setShowBulkModal(true)} className="flex items-center gap-2 px-4 py-3 text-xs font-black text-slate-800 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all uppercase tracking-widest">
            <FileSpreadsheet className="w-4 h-4 text-emerald-600" />
            Lançar Levantamento
          </button>
          <button onClick={() => setShowForm(true)} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black transition-all shadow-lg uppercase tracking-widest text-xs">
            <Plus className="w-5 h-5" />
            <span>Novo Ativo</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden print:hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Ativo / Departamento</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Tipo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Marca/Modelo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredAssets.map((asset) => (
                <tr 
                  key={asset.id} 
                  onClick={() => setDetailAsset(asset)}
                  className="hover:bg-blue-50/50 transition-colors cursor-pointer group"
                >
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                      <span className="font-black text-slate-900 group-hover:text-blue-700">{asset.id}</span>
                      <div className="flex items-center gap-1 text-[10px] text-slate-700 font-black uppercase">
                        <Layers className="w-3 h-3" />
                        {getDepartmentName(asset.departmentId)}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="text-xs font-black text-slate-800">{asset.type}</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="font-bold text-slate-900">{asset.brand}</span>
                    <span className="text-sm text-slate-700 ml-2 font-medium">{asset.model}</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${
                      asset.status === 'Disponível' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' :
                      asset.status === 'Em Uso' ? 'bg-blue-50 text-blue-700 border-blue-200' :
                      asset.status === 'Manutenção' ? 'bg-amber-50 text-amber-700 border-amber-200' : 'bg-slate-50 text-slate-700 border-slate-200'
                    }`}>
                      {asset.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
                    <button onClick={async (e) => {e.stopPropagation(); if(confirm("Remover este ativo?")) await onRemove(asset.id)}} className="p-2 text-slate-400 hover:text-rose-600 transition-colors">
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </td>
                </tr>
              ))}
              {filteredAssets.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-20 text-center">
                    <div className="flex flex-col items-center justify-center space-y-3 opacity-30">
                       <Package className="w-12 h-12" />
                       <p className="font-black uppercase tracking-widest text-xs">Nenhum ativo registrado.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {detailAsset && (
        <div className="fixed inset-0 z-[150] flex items-center justify-end p-0 md:p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-2xl h-full md:h-auto md:max-h-[90vh] md:rounded-[3rem] shadow-2xl flex flex-col animate-in slide-in-from-right duration-300 overflow-hidden">
              <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl">
                       <Tag className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-2xl font-black text-slate-900 tracking-tight">{detailAsset.id}</h3>
                       <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Detalhes do Patrimônio</p>
                    </div>
                 </div>
                 <button onClick={() => {setDetailAsset(null); setManualLog('');}} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                    <X className="w-6 h-6 text-slate-400" />
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                 <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-200">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 text-center">Gestão de Status</p>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                       {(['Disponível', 'Em Uso', 'Manutenção', 'Baixado'] as AssetStatus[]).map(s => (
                          <button 
                            key={s}
                            onClick={() => handleStatusChangeManual(s)}
                            className={`py-2 text-[9px] font-black uppercase rounded-xl border transition-all ${
                               detailAsset.status === s ? 'bg-blue-600 text-white border-blue-700 shadow-md' : 'bg-white text-slate-500 border-slate-200 hover:border-blue-300'
                            }`}
                          >
                             {s}
                          </button>
                       ))}
                    </div>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 relative group">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Departamento / Setor</p>
                       <div className="flex items-center gap-3">
                          <Building2 className={`w-5 h-5 ${isUpdatingDept ? 'text-blue-400 animate-spin' : 'text-blue-600'}`} />
                          <div className="relative flex-1">
                             <select 
                               className="w-full bg-transparent font-bold text-slate-800 outline-none appearance-none cursor-pointer hover:text-blue-600 transition-colors pr-6"
                               value={detailAsset.departmentId}
                               onChange={(e) => handleDepartmentChange(e.target.value)}
                               disabled={isUpdatingDept}
                             >
                                {companies.map(c => (
                                   <option key={c.id} value={c.id}>{c.name}</option>
                                ))}
                             </select>
                             <ArrowLeftRight className="w-3.5 h-3.5 absolute right-0 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none group-hover:text-blue-400" />
                          </div>
                       </div>
                    </div>
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Responsável Atual</p>
                       <div className="flex items-center gap-3">
                          <User className="w-5 h-5 text-blue-600" />
                          <p className="font-bold text-slate-800">{getEmployeeName(detailAsset.assignedTo)}</p>
                       </div>
                    </div>
                 </div>

                 <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Especificação Técnica</p>
                    <div className="flex items-center gap-3">
                       <Cpu className="w-5 h-5 text-blue-600" />
                       <p className="font-bold text-slate-800">{detailAsset.type} {detailAsset.brand} {detailAsset.model}</p>
                    </div>
                 </div>

                 <div className="space-y-6">
                    <div className="flex items-center justify-between">
                       <div className="flex items-center gap-2">
                          <History className="w-5 h-5 text-blue-600" />
                          <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Linha do Tempo</h4>
                       </div>
                    </div>

                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 space-y-4">
                       <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Adicionar Log Manual</p>
                       <div className="flex gap-2">
                          <input 
                            type="text"
                            placeholder="Descreva um evento..."
                            className="flex-1 p-3 rounded-xl border border-slate-200 text-sm font-medium outline-none focus:ring-2 focus:ring-blue-600"
                            value={manualLog}
                            onChange={(e) => setManualLog(e.target.value)}
                          />
                          <button onClick={handleAddManualLog} className="bg-slate-900 text-white p-3 rounded-xl hover:bg-black transition-colors shadow-lg">
                            <MessageSquarePlus className="w-5 h-5" />
                          </button>
                       </div>
                    </div>

                    <div className="relative pl-8 space-y-8 before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[2px] before:bg-slate-100">
                       {detailAsset.history?.length > 0 ? (
                         [...detailAsset.history].reverse().map((entry) => (
                           <div key={entry.id} className="relative group">
                              <div className={`absolute -left-[30px] top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm flex items-center justify-center ${
                                entry.type === 'Manutenção' ? 'bg-amber-500' :
                                entry.type === 'Atribuição' ? 'bg-blue-600' :
                                entry.type === 'Criação' ? 'bg-emerald-500' : 'bg-slate-400'
                              }`}>
                                {entry.type === 'Manutenção' && <Wrench className="w-3 h-3 text-white" />}
                                {entry.type === 'Atribuição' && <User className="w-3 h-3 text-white" />}
                                {entry.type === 'Criação' && <CheckCircle2 className="w-3 h-3 text-white" />}
                                {entry.type === 'Status' && <ArrowLeftRight className="w-3 h-3 text-white" />}
                              </div>
                              <div className="space-y-1">
                                 <div className="flex items-center justify-between">
                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{new Date(entry.date).toLocaleDateString('pt-BR')}</p>
                                    <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-slate-100 text-slate-700">{entry.type}</span>
                                 </div>
                                 <p className="text-sm text-slate-800 font-bold leading-relaxed">{entry.description}</p>
                              </div>
                           </div>
                         ))
                       ) : <p className="text-center py-10 text-slate-400 font-bold uppercase tracking-widest text-xs opacity-50">Nenhum histórico</p>}
                    </div>
                 </div>
              </div>

              <div className="p-8 bg-slate-50 border-t border-slate-100 flex justify-end">
                 <button onClick={() => setDetailAsset(null)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl transition-all">Fechar Detalhes</button>
              </div>
           </div>
        </div>
      )}

      {showBulkModal && (
        <div className="fixed inset-0 z-[200] flex flex-col bg-slate-900/95 backdrop-blur-xl animate-in fade-in duration-300 print:hidden">
          <div className="h-20 bg-slate-800/50 border-b border-white/10 flex items-center justify-between px-8 text-white">
             <div className="flex items-center gap-4">
               <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center">
                  <FileSpreadsheet className="w-6 h-6" />
               </div>
               <div>
                  <h3 className="font-black tracking-tight">Levantamento de Campo em Lote</h3>
                  <p className="text-[10px] text-slate-200 font-black uppercase tracking-widest">Coleta Física de Inventário</p>
               </div>
            </div>
            <button onClick={() => setShowBulkModal(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
               <X className="w-6 h-6" />
            </button>
          </div>

          <div className="flex-1 overflow-auto p-8">
             {companies.length === 0 ? (
               <div className="bg-white rounded-[2.5rem] p-20 text-center flex flex-col items-center justify-center space-y-6">
                  <Building2 className="w-20 h-20 text-slate-200" />
                  <h3 className="text-xl font-black text-slate-800 uppercase tracking-widest">Banco Sem Departamentos</h3>
                  <p className="text-slate-500 max-w-sm text-sm">Cadastre os Departamentos antes de lançar o levantamento.</p>
                  <button onClick={() => setShowBulkModal(false)} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase text-[10px] tracking-widest">Voltar</button>
               </div>
             ) : (
              <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200">
                  <div className="overflow-x-auto">
                    <table className="w-full text-left min-w-[1000px]">
                        <thead className="bg-slate-50 border-b border-slate-200">
                          <tr>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase w-48 tracking-widest">Depto / Tipo</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Marca / Modelo</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Patrimônio</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-800 uppercase tracking-widest">Responsável</th>
                            <th className="px-6 py-4"></th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                          {bulkEntries.map((entry, idx) => (
                            <tr key={entry.tempId} className="hover:bg-slate-50/50 transition-colors">
                                <td className="px-6 py-4 space-y-2">
                                  <select className="w-full p-2 bg-slate-100 rounded-xl text-xs font-bold border-none appearance-none" value={entry.departmentId} onChange={e => {const n=[...bulkEntries]; n[idx].departmentId=e.target.value; setBulkEntries(n)}}>
                                    {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                  </select>
                                  <select className="w-full p-2 bg-white rounded-xl text-xs font-bold border border-slate-300 appearance-none" value={entry.type} onChange={e => {const n=[...bulkEntries]; n[idx].type=e.target.value as AssetType; setBulkEntries(n)}}>
                                    {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                                  </select>
                                </td>
                                <td className="px-6 py-4 space-y-2">
                                  <input className="w-full p-2 bg-white border border-slate-300 rounded-xl text-xs font-bold" placeholder="Marca" value={entry.brand} onChange={e => {const n=[...bulkEntries]; n[idx].brand=e.target.value; setBulkEntries(n)}} />
                                  <input className="w-full p-2 bg-white border border-slate-300 rounded-xl text-xs font-bold" placeholder="Modelo" value={entry.model} onChange={e => {const n=[...bulkEntries]; n[idx].model=e.target.value; setBulkEntries(n)}} />
                                </td>
                                <td className="px-6 py-4">
                                  <input className="w-full p-2 bg-slate-100 border border-slate-300 rounded-xl text-xs font-mono font-black uppercase text-center" placeholder="ID PATRIMONIAL" value={entry.id} onChange={e => {const n=[...bulkEntries]; n[idx].id=e.target.value; setBulkEntries(n)}} />
                                </td>
                                <td className="px-6 py-4">
                                  <select className="w-full p-2 bg-white border border-slate-300 rounded-xl text-xs font-bold appearance-none" value={entry.assignedTo} onChange={e => {const n=[...bulkEntries]; n[idx].assignedTo=e.target.value; setBulkEntries(n)}}>
                                    <option value="">ESTOQUE</option>
                                    {employees.filter(emp => emp.departmentId === entry.departmentId).map(emp => (
                                      <option key={emp.id} value={emp.id}>{emp.name}</option>
                                    ))}
                                  </select>
                                </td>
                                <td className="px-6 py-4 text-right">
                                  <button onClick={() => setBulkEntries(bulkEntries.filter(b => b.tempId !== entry.tempId))} className="text-slate-400 hover:text-rose-500 transition-colors p-2"><Trash2 className="w-4 h-4" /></button>
                                </td>
                            </tr>
                          ))}
                        </tbody>
                    </table>
                  </div>
                  <div className="p-8 bg-slate-50 border-t border-slate-200 flex justify-between items-center">
                    <button onClick={handleBulkAddRow} disabled={isSavingBulk} className="text-blue-600 font-black text-xs uppercase tracking-widest flex items-center gap-2 hover:underline disabled:opacity-30">
                        <PlusCircle className="w-5 h-5" /> Item
                    </button>
                    <div className="flex gap-4">
                        <button onClick={() => setShowBulkModal(false)} className="px-8 py-3 font-black text-slate-500 uppercase text-xs tracking-widest">Descartar</button>
                        <button onClick={handleBulkSave} disabled={isSavingBulk} className="bg-emerald-600 hover:bg-emerald-700 text-white px-10 py-3 rounded-2xl font-black shadow-xl shadow-emerald-100 flex items-center gap-2 uppercase tracking-widest text-xs transition-all disabled:bg-slate-400">
                          {isSavingBulk ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                          Salvar Levantamento
                        </button>
                    </div>
                  </div>
              </div>
             )}
          </div>
        </div>
      )}

      {showForm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in zoom-in-95">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-10 shadow-2xl">
             <div className="flex items-center gap-4 mb-8">
                <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl"><Plus className="w-8 h-8" /></div>
                <h3 className="text-2xl font-black">Novo Patrimônio</h3>
             </div>
             <form onSubmit={handleSubmit} className="space-y-6">
                <div className="grid grid-cols-2 gap-4">
                   <div className="space-y-1">
                      <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Tipo</label>
                      <select className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none font-bold appearance-none" value={newAsset.type} onChange={e => setNewAsset({...newAsset, type: e.target.value as any})}>
                         {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                      </select>
                   </div>
                   <div className="space-y-1">
                      <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Marca</label>
                      <input className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none font-bold" value={newAsset.brand} onChange={e => setNewAsset({...newAsset, brand: e.target.value})} placeholder="Dell" required />
                   </div>
                </div>
                <div className="space-y-1">
                   <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Modelo</label>
                   <input className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none font-bold" value={newAsset.model} onChange={e => setNewAsset({...newAsset, model: e.target.value})} placeholder="Latitude 5420" required />
                </div>
                <div className="space-y-1">
                   <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Departamento</label>
                   <select className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none font-bold appearance-none" value={newAsset.departmentId} onChange={e => setNewAsset({...newAsset, departmentId: e.target.value})} required>
                     {companies.length === 0 && <option value="">Nenhum Depto Encontrado</option>}
                     {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                   </select>
                </div>
                <div className="flex gap-4 pt-4">
                   <button type="button" onClick={() => setShowForm(false)} className="flex-1 py-4 font-black text-slate-400 uppercase tracking-widest text-xs">Cancelar</button>
                   <button type="submit" className="flex-[2] py-4 bg-blue-600 text-white rounded-2xl font-black shadow-xl uppercase tracking-widest text-xs">Salvar Ativo</button>
                </div>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AssetManager;

import React, { useState } from 'react';
import { 
  FileText, 
  Plus, 
  X, 
  Clock, 
  ChevronRight, 
  CheckCircle, 
  ShoppingCart, 
  Link as LinkIcon, 
  Search, 
  AlertCircle,
  User,
  Calendar,
  Package,
  Check,
  Ban,
  Truck,
  MessageSquare,
  CheckSquare,
  Wrench,
  UserPlus
} from 'lucide-react';
import { EquipmentRequest, Employee, Asset, AssetType, ItemFulfillment } from '../types';
import { ASSET_TYPES } from '../constants';

interface RequestsManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  assets: Asset[];
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  onUpdateStatus: (id: string, status: EquipmentRequest['status']) => Promise<void>;
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
}

const RequestsManager: React.FC<RequestsManagerProps> = ({ requests, employees, assets, onAddRequest, onUpdateStatus, onUpdateRequest }) => {
  const [showModal, setShowModal] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<EquipmentRequest | null>(null);
  const [itemToLink, setItemToLink] = useState<{ index: number; type: AssetType } | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newReq, setNewReq] = useState<Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>>({
    requesterId: '1', 
    employeeId: '',
    items: [],
    observation: ''
  });

  const getEmployeeName = (id: string) => employees.find(e => e.id === id)?.name || 'Desconhecido';
  const getEmployeeSector = (id: string) => employees.find(e => e.id === id)?.sector || 'Setor não informado';

  const toggleItem = (type: AssetType) => {
    setNewReq(prev => ({
      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newReq.items.length === 0) {
      alert("Selecione pelo menos um item.");
      return;
    }
    if (!newReq.employeeId) {
      alert("Selecione o colaborador destinatário.");
      return;
    }

    setIsSubmitting(true);
    try {
      await onAddRequest({
        ...newReq,
        itemFulfillments: newReq.items.map(type => ({
          type,
          isPurchaseOrder: false
        }))
      });
      setShowModal(false);
      setNewReq({ requesterId: '1', employeeId: '', items: [], observation: '' });
    } catch (err) {
      alert("Erro ao criar requisição.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleLinkAsset = async (index: number, assetId: string) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: assetId,
      isPurchaseOrder: false
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleMarkForPurchase = async (index: number) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: undefined,
      isPurchaseOrder: true,
      purchaseStatus: 'Pendente'
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
  };

  const handleStatusChange = async (status: EquipmentRequest['status']) => {
    if (selectedRequest) {
      await onUpdateStatus(selectedRequest.id, status);
      setSelectedRequest(prev => prev ? { ...prev, status } : null);
    }
  };

  const availableAssetsByType = (type: AssetType) => {
    return assets.filter(a => a.type === type && a.status === 'Disponível');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 relative">
      <div className="lg:col-span-2 space-y-4">
        <h3 className="text-lg font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight">
          <Clock className="w-5 h-5 text-blue-600" /> Fluxo de Atendimento
        </h3>

        {requests.map(req => (
          <div 
            key={req.id} 
            onClick={() => setSelectedRequest(req)}
            className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between hover:shadow-md transition-all group cursor-pointer border-l-4 border-l-transparent hover:border-l-blue-600"
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${
                req.status === 'Pendente' ? 'bg-amber-100 text-amber-700' :
                req.status === 'Aprovado' ? 'bg-blue-100 text-blue-700' :
                req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-700' :
                req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'
              }`}>
                {req.status === 'Preparando' ? <Wrench className="w-6 h-6" /> : <FileText className="w-6 h-6" />}
              </div>
              <div>
                <div className="flex items-center gap-2">
                  <p className="font-black text-slate-900">{req.id}</p>
                  {req.itemFulfillments?.some(f => f.isPurchaseOrder) && (
                    <span className="bg-amber-100 text-amber-800 px-2 py-0.5 rounded-full text-[9px] font-black uppercase flex items-center gap-1 border border-amber-200">
                      <ShoppingCart className="w-2.5 h-2.5" /> Compra
                    </span>
                  )}
                </div>
                <p className="text-sm text-slate-600 font-semibold">Para: {getEmployeeName(req.employeeId)}</p>
              </div>
            </div>

            <div className="flex items-center gap-6">
               <div className="hidden md:flex flex-col items-end">
                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Itens</span>
                  <span className="text-sm font-black text-slate-800">{req.items.length} eqp.</span>
               </div>
               <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-tight ${
                 req.status === 'Pendente' ? 'bg-amber-100 text-amber-800 border border-amber-200' : 
                 req.status === 'Aprovado' ? 'bg-blue-100 text-blue-800 border border-blue-200' :
                 req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-800 border border-indigo-200' :
                 req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-800 border border-emerald-200' : 'bg-rose-100 text-rose-800 border border-rose-200'
               }`}>
                 {req.status}
               </span>
               <ChevronRight className="w-5 h-5 text-slate-400 group-hover:text-blue-600 transition-transform group-hover:translate-x-1" />
            </div>
          </div>
        ))}

        {requests.length === 0 && (
          <div className="bg-white p-16 rounded-[2.5rem] border border-dashed border-slate-300 text-center space-y-4">
             <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto">
                <FileText className="w-10 h-10 text-slate-300" />
             </div>
             <p className="text-slate-600 font-black uppercase tracking-widest text-xs">Nenhuma solicitação pendente de triagem.</p>
          </div>
        )}
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-xl h-fit space-y-6 sticky top-24">
        <div className="bg-blue-50 p-5 rounded-3xl mb-6 border border-blue-100">
           <div className="flex items-center gap-2 text-blue-700 mb-2">
             <AlertCircle className="w-5 h-5" />
             <h4 className="font-black text-sm uppercase tracking-widest">Triagem de Ativos</h4>
           </div>
           <p className="text-xs text-blue-800 leading-relaxed font-semibold">
             Toda requisição deve ser vinculada a um item do inventário ou gerar um pedido de compra aprovado pela diretoria.
           </p>
        </div>

        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-slate-900 hover:bg-black text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-2 group uppercase tracking-widest text-xs"
        >
          <Plus className="w-5 h-5 group-hover:rotate-90 transition-transform" />
          <span>Abrir Nova Requisição</span>
        </button>
      </div>

      {/* MODAL DE CRIAÇÃO DE REQUISIÇÃO */}
      {showModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
              <div className="bg-slate-900 p-8 text-white flex items-center justify-between shrink-0">
                 <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center"><UserPlus className="w-5 h-5" /></div>
                    <h3 className="text-xl font-black uppercase tracking-tight">Nova Requisição de Equipamentos</h3>
                 </div>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6" /></button>
              </div>

              <form onSubmit={handleSubmit} className="p-10 space-y-8 overflow-y-auto custom-scrollbar flex-1">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Colaborador Destinatário</label>
                    <div className="relative">
                       <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                       <select 
                        className="w-full pl-12 pr-4 py-4 rounded-2xl bg-slate-50 border-none outline-none font-bold appearance-none shadow-sm focus:ring-2 focus:ring-blue-600"
                        value={newReq.employeeId}
                        onChange={e => setNewReq({...newReq, employeeId: e.target.value})}
                        required
                       >
                         <option value="">Selecione o colaborador...</option>
                         {employees.map(emp => (
                           <option key={emp.id} value={emp.id}>{emp.name} — {emp.sector}</option>
                         ))}
                       </select>
                    </div>
                 </div>

                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Itens Requisitados</label>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                       {ASSET_TYPES.map(type => (
                         <button
                          key={type}
                          type="button"
                          onClick={() => toggleItem(type as AssetType)}
                          className={`p-3 rounded-xl border text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${
                            newReq.items.includes(type as AssetType) 
                              ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100' 
                              : 'bg-white border-slate-200 text-slate-600 hover:border-blue-300'
                          }`}
                         >
                           {newReq.items.includes(type as AssetType) && <Check className="w-3 h-3" />}
                           {type}
                         </button>
                       ))}
                    </div>
                 </div>

                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações / Motivo</label>
                    <textarea 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold h-32 outline-none focus:ring-2 focus:ring-blue-600"
                      placeholder="Ex: Novo colaborador iniciando segunda-feira. Precisa de setup completo."
                      value={newReq.observation}
                      onChange={e => setNewReq({...newReq, observation: e.target.value})}
                      required
                    />
                 </div>

                 <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs flex items-center justify-center gap-3 transition-all disabled:bg-slate-300"
                 >
                    {isSubmitting ? (
                      <Loader2 className="w-5 h-5 animate-spin" />
                    ) : (
                      <>
                        <CheckCircle className="w-5 h-5" /> Abrir Protocolo de Requisição
                      </>
                    )}
                 </button>
              </form>
           </div>
        </div>
      )}

      {selectedRequest && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => { setSelectedRequest(null); setItemToLink(null); }} />
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300 border-l border-slate-200">
            <div className="p-6 border-b border-slate-200 flex items-center justify-between bg-white">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-100">
                  <CheckSquare className="w-6 h-6" />
                </div>
                <div>
                  <h3 className="text-xl font-black text-slate-900">Triagem Técnica</h3>
                  <p className="text-sm text-slate-600 font-bold">{selectedRequest.id}</p>
                </div>
              </div>
              <button onClick={() => { setSelectedRequest(null); setItemToLink(null); }} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500 hover:text-slate-900">
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-white">
               <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-full bg-white border border-slate-300 flex items-center justify-center text-slate-500">
                      <User className="w-6 h-6" />
                    </div>
                    <div>
                      <p className="text-sm font-black text-slate-900">{getEmployeeName(selectedRequest.employeeId)}</p>
                      <p className="text-xs text-slate-700 font-bold uppercase tracking-tight">{getEmployeeSector(selectedRequest.employeeId)}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Data Solicitação</p>
                    <p className="text-xs font-black text-slate-900">{new Date(selectedRequest.createdAt).toLocaleDateString('pt-BR')}</p>
                  </div>
               </div>

               <div className="space-y-4">
                 <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                   <Package className="w-4 h-4 text-blue-600" /> Itens Requisitados ({selectedRequest.items.length})
                 </h4>

                 <div className="space-y-4">
                    {selectedRequest.items.map((itemType, idx) => {
                      const fulfillment = selectedRequest.itemFulfillments?.[idx];
                      const isLinked = !!fulfillment?.linkedAssetId;
                      const isPurchase = !!fulfillment?.isPurchaseOrder;

                      return (
                        <div key={idx} className={`border p-5 rounded-3xl transition-all ${
                          isLinked ? 'bg-emerald-50 border-emerald-200' : 
                          isPurchase ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-200 shadow-sm'
                        }`}>
                          <div className="flex items-center justify-between mb-4">
                            <div className="flex items-center gap-3">
                              <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${
                                isLinked ? 'bg-emerald-100 text-emerald-800' : 
                                isPurchase ? 'bg-amber-100 text-amber-800' : 'bg-slate-100 text-slate-600'
                              }`}>
                                <Package className="w-5 h-5" />
                              </div>
                              <span className="font-black text-slate-900">{itemType}</span>
                            </div>

                            {isLinked ? (
                              <div className="flex items-center gap-1 text-emerald-800">
                                <CheckCircle className="w-4 h-4" />
                                <span className="text-[10px] font-black uppercase tracking-tight">Vinculado: {fulfillment.linkedAssetId}</span>
                              </div>
                            ) : isPurchase ? (
                              <div className={`flex items-center gap-1 ${fulfillment.purchaseStatus === 'Comprado' ? 'text-emerald-800' : 'text-amber-800'}`}>
                                <ShoppingCart className="w-4 h-4" />
                                <span className="text-[10px] font-black uppercase tracking-tight">Status: {fulfillment.purchaseStatus || 'Pendente'}</span>
                              </div>
                            ) : (
                              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Aguardando Triagem</span>
                            )}
                          </div>

                          {!isLinked && !isPurchase && (
                            <div className="grid grid-cols-2 gap-3">
                               <button 
                                onClick={() => setItemToLink({ index: idx, type: itemType })}
                                className="bg-white border border-slate-300 py-2.5 rounded-2xl text-xs font-black text-slate-800 flex items-center justify-center gap-2 hover:bg-slate-900 hover:text-white transition-all shadow-sm uppercase tracking-widest"
                               >
                                 <LinkIcon className="w-3.5 h-3.5" /> Vincular Estoque
                               </button>
                               <button 
                                onClick={() => handleMarkForPurchase(idx)}
                                className="bg-white border border-slate-300 py-2.5 rounded-2xl text-xs font-black text-slate-800 flex items-center justify-center gap-2 hover:bg-slate-900 hover:text-white transition-all shadow-sm uppercase tracking-widest"
                               >
                                 <ShoppingCart className="w-3.5 h-3.5" /> Pedido Compra
                               </button>
                            </div>
                          )}

                          {itemToLink?.index === idx && (
                            <div className="mt-4 p-4 bg-slate-100 rounded-2xl border border-slate-300 animate-in fade-in zoom-in-95">
                               <div className="flex items-center justify-between mb-3">
                                  <h5 className="text-[10px] font-black text-slate-700 uppercase tracking-widest">Escolha um item disponível:</h5>
                                  <button onClick={() => setItemToLink(null)} className="text-slate-500 hover:text-slate-900">
                                    <X className="w-3 h-3" />
                                  </button>
                               </div>
                               <div className="space-y-2 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
                                  {availableAssetsByType(itemType).length > 0 ? (
                                    availableAssetsByType(itemType).map(asset => (
                                      <button 
                                        key={asset.id}
                                        onClick={() => handleLinkAsset(idx, asset.id)}
                                        className="w-full text-left p-3 rounded-xl bg-white border border-slate-300 hover:border-blue-600 hover:shadow-sm transition-all flex items-center justify-between group"
                                      >
                                         <div>
                                           <p className="text-xs font-black text-slate-900">{asset.id}</p>
                                           <p className="text-[10px] text-slate-700 font-semibold">{asset.brand} - {asset.model}</p>
                                         </div>
                                         <Plus className="w-4 h-4 text-slate-400 group-hover:text-blue-600" />
                                      </button>
                                    ))
                                  ) : (
                                    <div className="text-center py-4 space-y-2">
                                       <AlertCircle className="w-6 h-6 text-slate-400 mx-auto" />
                                       <p className="text-[10px] text-slate-600 font-bold uppercase">Ops! Não há saldo disponível para "{itemType}" no inventário.</p>
                                    </div>
                                  )}
                               </div>
                            </div>
                          )}
                        </div>
                      );
                    })}
                 </div>
               </div>

               <div className="space-y-3">
                  <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <MessageSquare className="w-4 h-4 text-blue-600" /> Justificativa do Pedido
                  </h4>
                  <div className="p-5 bg-white rounded-3xl border border-blue-200 text-sm text-slate-800 leading-relaxed font-semibold italic shadow-sm">
                    "{selectedRequest.observation || "Nenhuma observação informada pelo solicitante."}"
                  </div>
               </div>
            </div>

            <div className="p-6 border-t border-slate-200 bg-slate-50 flex flex-col gap-3">
               <div className="flex flex-col gap-2">
                 {selectedRequest.status === 'Pendente' && (
                   <button 
                    onClick={() => handleStatusChange('Aprovado')}
                    disabled={!selectedRequest.itemFulfillments || selectedRequest.itemFulfillments.length === 0}
                    className="w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-100 uppercase tracking-widest text-xs"
                   >
                     <Check className="w-5 h-5" />
                     Aprovar e Avançar para Preparação
                   </button>
                 )}

                 {selectedRequest.status === 'Aprovado' && (
                    <button 
                      onClick={() => handleStatusChange('Preparando')}
                      className="w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all bg-indigo-600 text-white hover:bg-indigo-700 shadow-xl shadow-indigo-100 uppercase tracking-widest text-xs"
                    >
                      <Wrench className="w-5 h-5" />
                      Iniciar Preparação Técnica
                    </button>
                 )}

                 {(selectedRequest.status === 'Aprovado' || selectedRequest.status === 'Preparando') && (
                    <button 
                      onClick={() => handleStatusChange('Entregue')}
                      disabled={selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !(f.isPurchaseOrder && f.purchaseStatus === 'Comprado'))}
                      className={`w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all uppercase tracking-widest text-xs ${
                        selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !(f.isPurchaseOrder && f.purchaseStatus === 'Comprado'))
                          ? 'bg-slate-200 text-slate-500 cursor-not-allowed border border-slate-300'
                          : 'bg-emerald-600 text-white hover:bg-emerald-700 shadow-xl shadow-emerald-100'
                      }`}
                    >
                      <Truck className="w-5 h-5" />
                      Finalizar Entrega ao Colaborador
                    </button>
                 )}
               </div>

               {selectedRequest.status === 'Entregue' && (
                 <div className="p-4 bg-emerald-100 rounded-2xl border border-emerald-300 flex items-center gap-3 text-emerald-800 font-black justify-center uppercase tracking-widest text-[10px]">
                    <CheckCircle className="w-5 h-5" />
                    Requisição Finalizada com Sucesso
                 </div>
               )}

               {selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !f.isPurchaseOrder) && selectedRequest.status === 'Pendente' && (
                 <p className="text-[10px] text-center text-rose-700 font-black uppercase tracking-tight">Atenção: Existem itens pendentes de triagem/vínculo.</p>
               )}
            </div>
          </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default RequestsManager;

import React, { useState } from 'react';
import { 
  FileText, 
  Plus, 
  X, 
  Clock, 
  ChevronRight, 
  CheckCircle, 
  ShoppingCart, 
  Link as LinkIcon, 
  Search, 
  AlertCircle,
  User,
  Calendar,
  Package,
  Check,
  Ban,
  Truck,
  MessageSquare,
  CheckSquare,
  Wrench,
  UserPlus,
  // Fix: Added missing Loader2 import
  Loader2
} from 'lucide-react';
import { EquipmentRequest, Employee, Asset, AssetType, ItemFulfillment } from '../types';
import { ASSET_TYPES } from '../constants';

interface RequestsManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  assets: Asset[];
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  onUpdateStatus: (id: string, status: EquipmentRequest['status']) => Promise<void>;
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
}

const RequestsManager: React.FC<RequestsManagerProps> = ({ requests, employees, assets, onAddRequest, onUpdateStatus, onUpdateRequest }) => {
  const [showModal, setShowModal] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<EquipmentRequest | null>(null);
  const [itemToLink, setItemToLink] = useState<{ index: number; type: AssetType } | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newReq, setNewReq] = useState<Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>>({
    requesterId: '1', 
    employeeId: '',
    items: [],
    observation: ''
  });

  const getEmployeeName = (id: string) => employees.find(e => e.id === id)?.name || 'Desconhecido';
  const getEmployeeSector = (id: string) => employees.find(e => e.id === id)?.sector || 'Setor não informado';

  const toggleItem = (type: AssetType) => {
    setNewReq(prev => ({
      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newReq.items.length === 0) {
      alert("Selecione pelo menos um item.");
      return;
    }
    if (!newReq.employeeId) {
      alert("Selecione o colaborador destinatário.");
      return;
    }

    setIsSubmitting(true);
    try {
      await onAddRequest({
        ...newReq,
        itemFulfillments: newReq.items.map(type => ({
          type,
          isPurchaseOrder: false
        }))
      });
      setShowModal(false);
      setNewReq({ requesterId: '1', employeeId: '', items: [], observation: '' });
    } catch (err) {
      alert("Erro ao criar requisição.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleLinkAsset = async (index: number, assetId: string) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: assetId,
      isPurchaseOrder: false
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleMarkForPurchase = async (index: number) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: undefined,
      isPurchaseOrder: true,
      purchaseStatus: 'Pendente'
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
  };

  const handleStatusChange = async (status: EquipmentRequest['status']) => {
    if (selectedRequest) {
      await onUpdateStatus(selectedRequest.id, status);
      setSelectedRequest(prev => prev ? { ...prev, status } : null);
    }
  };

  const availableAssetsByType = (type: AssetType) => {
    return assets.filter(a => a.type === type && a.status === 'Disponível');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 relative">
      <div className="lg:col-span-2 space-y-4">
        <h3 className="text-lg font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight">
          <Clock className="w-5 h-5 text-blue-600" /> Fluxo de Atendimento
        </h3>

        {requests.map(req => (
          <div 
            key={req.id} 
            onClick={() => setSelectedRequest(req)}
            className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between hover:shadow-md transition-all group cursor-pointer border-l-4 border-l-transparent hover:border-l-blue-600"
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${
                req.status === 'Pendente' ? 'bg-amber-100 text-amber-700' :
                req.status === 'Aprovado' ? 'bg-blue-100 text-blue-700' :
                req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-700' :
                req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'
              }`}>
                {req.status === 'Preparando' ? <Wrench className="w-6 h-6" /> : <FileText className="w-6 h-6" />}
              </div>
              <div>
                <div className="flex items-center gap-2">
                  <p className="font-black text-slate-900">{req.id}</p>
                  {req.itemFulfillments?.some(f => f.isPurchaseOrder) && (
                    <span className="bg-amber-100 text-amber-800 px-2 py-0.5 rounded-full text-[9px] font-black uppercase flex items-center gap-1 border border-amber-200">
                      <ShoppingCart className="w-2.5 h-2.5" /> Compra
                    </span>
                  )}
                </div>
                <p className="text-sm text-slate-600 font-semibold">Para: {getEmployeeName(req.employeeId)}</p>
              </div>
            </div>

            <div className="flex items-center gap-6">
               <div className="hidden md:flex flex-col items-end">
                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Itens</span>
                  <span className="text-sm font-black text-slate-800">{req.items.length} eqp.</span>
               </div>
               <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-tight ${
                 req.status === 'Pendente' ? 'bg-amber-100 text-amber-800 border border-amber-200' : 
                 req.status === 'Aprovado' ? 'bg-blue-100 text-blue-800 border border-blue-200' :
                 req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-800 border border-indigo-200' :
                 req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-800 border border-emerald-200' : 'bg-rose-100 text-rose-800 border border-rose-200'
               }`}>
                 {req.status}
               </span>
               <ChevronRight className="w-5 h-5 text-slate-400 group-hover:text-blue-600 transition-transform group-hover:translate-x-1" />
            </div>
          </div>
        ))}

        {requests.length === 0 && (
          <div className="bg-white p-16 rounded-[2.5rem] border border-dashed border-slate-300 text-center space-y-4">
             <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto">
                <FileText className="w-10 h-10 text-slate-300" />
             </div>
             <p className="text-slate-600 font-black uppercase tracking-widest text-xs">Nenhuma solicitação pendente de triagem.</p>
          </div>
        )}
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-xl h-fit space-y-6 sticky top-24">
        <div className="bg-blue-50 p-5 rounded-3xl mb-6 border border-blue-100">
           <div className="flex items-center gap-2 text-blue-700 mb-2">
             <AlertCircle className="w-5 h-5" />
             <h4 className="font-black text-sm uppercase tracking-widest">Triagem de Ativos</h4>
           </div>
           <p className="text-xs text-blue-800 leading-relaxed font-semibold">
             Toda requisição deve ser vinculada a um item do inventário ou gerar um pedido de compra aprovado pela diretoria.
           </p>
        </div>

        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-slate-900 hover:bg-black text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-2 group uppercase tracking-widest text-xs"
        >
          <Plus className="w-5 h-5 group-hover:rotate-90 transition-transform" />
          <span>Abrir Nova Requisição</span>
        </button>
      </div>

      {/* MODAL DE CRIAÇÃO DE REQUISIÇÃO */}
      {showModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
              <div className="bg-slate-900 p-8 text-white flex items-center justify-between shrink-0">
                 <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center"><UserPlus className="w-5 h-5" /></div>
                    <h3 className="text-xl font-black uppercase tracking-tight">Nova Requisição de Equipamentos</h3>
                 </div>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6" /></button>
              </div>

              <form onSubmit={handleSubmit} className="p-10 space-y-8 overflow-y-auto custom-scrollbar flex-1">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Colaborador Destinatário</label>
                    <div className="relative">
                       <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                       <select 
                        className="w-full pl-12 pr-4 py-4 rounded-2xl bg-slate-50 border-none outline-none font-bold appearance-none shadow-sm focus:ring-2 focus:ring-blue-600"
                        value={newReq.employeeId}
                        onChange={e => setNewReq({...newReq, employeeId: e.target.value})}
                        required
                       >
                         <option value="">Selecione o colaborador...</option>
                         {employees.map(emp => (
                           <option key={emp.id} value={emp.id}>{emp.name} — {emp.sector}</option>
                         ))}
                       </select>
                    </div>
                 </div>

                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Itens Requisitados</label>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                       {ASSET_TYPES.map(type => (
                         <button
                          key={type}
                          type="button"
                          onClick={() => toggleItem(type as AssetType)}
                          className={`p-3 rounded-xl border text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${
                            newReq.items.includes(type as AssetType) 
                              ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100' 
                              : 'bg-white border-slate-200 text-slate-600 hover:border-blue-300'
                          }`}
                         >
                           {newReq.items.includes(type as AssetType) && <Check className="w-3 h-3" />}
                           {type}
                         </button>
                       ))}
                    </div>
                 </div>

                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações / Motivo</label>
                    <textarea 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold h-32 outline-none focus:ring-2 focus:ring-blue-600"
                      placeholder="Ex: Novo colaborador iniciando segunda-feira. Precisa de setup completo."
                      value={newReq.observation}
                      onChange={e => setNewReq({...newReq, observation: e.target.value})}
                      required
                    />
                 </div>

                 <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs flex items-center justify-center gap-3 transition-all disabled:bg-slate-300"
                 >
                    {isSubmitting ? (
                      <Loader2 className="w-5 h-5 animate-spin" />
                    ) : (
                      <>
                        <CheckCircle className="w-5 h-5" /> Abrir Protocolo de Requisição
                      </>
                    )}
                 </button>
              </form>
           </div>
        </div>
      )}

      {selectedRequest && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => { setSelectedRequest(null); setItemToLink(null); }} />
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300 border-l border-slate-200">
            <div className="p-6 border-b border-slate-200 flex items-center justify-between bg-white">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-100">
                  <CheckSquare className="w-6 h-6" />
                </div>
                <div>
                  <h3 className="text-xl font-black text-slate-900">Triagem Técnica</h3>
                  <p className="text-sm text-slate-600 font-bold">{selectedRequest.id}</p>
                </div>
              </div>
              <button onClick={() => { setSelectedRequest(null); setItemToLink(null); }} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500 hover:text-slate-900">
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-white">
               <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-full bg-white border border-slate-300 flex items-center justify-center text-slate-500">
                      <User className="w-6 h-6" />
                    </div>
                    <div>
                      <p className="text-sm font-black text-slate-900">{getEmployeeName(selectedRequest.employeeId)}</p>
                      <p className="text-xs text-slate-700 font-bold uppercase tracking-tight">{getEmployeeSector(selectedRequest.employeeId)}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Data Solicitação</p>
                    <p className="text-xs font-black text-slate-900">{new Date(selectedRequest.createdAt).toLocaleDateString('pt-BR')}</p>
                  </div>
               </div>

               <div className="space-y-4">
                 <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                   <Package className="w-4 h-4 text-blue-600" /> Itens Requisitados ({selectedRequest.items.length})
                 </h4>

                 <div className="space-y-4">
                    {selectedRequest.items.map((itemType, idx) => {
                      const fulfillment = selectedRequest.itemFulfillments?.[idx];
                      const isLinked = !!fulfillment?.linkedAssetId;
                      const isPurchase = !!fulfillment?.isPurchaseOrder;

                      return (
                        <div key={idx} className={`border p-5 rounded-3xl transition-all ${
                          isLinked ? 'bg-emerald-50 border-emerald-200' : 
                          isPurchase ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-200 shadow-sm'
                        }`}>
                          <div className="flex items-center justify-between mb-4">
                            <div className="flex items-center gap-3">
                              <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${
                                isLinked ? 'bg-emerald-100 text-emerald-800' : 
                                isPurchase ? 'bg-amber-100 text-amber-800' : 'bg-slate-100 text-slate-600'
                              }`}>
                                <Package className="w-5 h-5" />
                              </div>
                              <span className="font-black text-slate-900">{itemType}</span>
                            </div>

                            {isLinked ? (
                              <div className="flex items-center gap-1 text-emerald-800">
                                <CheckCircle className="w-4 h-4" />
                                <span className="text-[10px] font-black uppercase tracking-tight">Vinculado: {fulfillment.linkedAssetId}</span>
                              </div>
                            ) : isPurchase ? (
                              <div className={`flex items-center gap-1 ${fulfillment.purchaseStatus === 'Comprado' ? 'text-emerald-800' : 'text-amber-800'}`}>
                                <ShoppingCart className="w-4 h-4" />
                                <span className="text-[10px] font-black uppercase tracking-tight">Status: {fulfillment.purchaseStatus || 'Pendente'}</span>
                              </div>
                            ) : (
                              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Aguardando Triagem</span>
                            )}
                          </div>

                          {!isLinked && !isPurchase && (
                            <div className="grid grid-cols-2 gap-3">
                               <button 
                                onClick={() => setItemToLink({ index: idx, type: itemType })}
                                className="bg-white border border-slate-300 py-2.5 rounded-2xl text-xs font-black text-slate-800 flex items-center justify-center gap-2 hover:bg-slate-900 hover:text-white transition-all shadow-sm uppercase tracking-widest"
                               >
                                 <LinkIcon className="w-3.5 h-3.5" /> Vincular Estoque
                               </button>
                               <button 
                                onClick={() => handleMarkForPurchase(idx)}
                                className="bg-white border border-slate-300 py-2.5 rounded-2xl text-xs font-black text-slate-800 flex items-center justify-center gap-2 hover:bg-slate-900 hover:text-white transition-all shadow-sm uppercase tracking-widest"
                               >
                                 <ShoppingCart className="w-3.5 h-3.5" /> Pedido Compra
                               </button>
                            </div>
                          )}

                          {itemToLink?.index === idx && (
                            <div className="mt-4 p-4 bg-slate-100 rounded-2xl border border-slate-300 animate-in fade-in zoom-in-95">
                               <div className="flex items-center justify-between mb-3">
                                  <h5 className="text-[10px] font-black text-slate-700 uppercase tracking-widest">Escolha um item disponível:</h5>
                                  <button onClick={() => setItemToLink(null)} className="text-slate-500 hover:text-slate-900">
                                    <X className="w-3 h-3" />
                                  </button>
                               </div>
                               <div className="space-y-2 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
                                  {availableAssetsByType(itemType).length > 0 ? (
                                    availableAssetsByType(itemType).map(asset => (
                                      <button 
                                        key={asset.id}
                                        onClick={() => handleLinkAsset(idx, asset.id)}
                                        className="w-full text-left p-3 rounded-xl bg-white border border-slate-300 hover:border-blue-600 hover:shadow-sm transition-all flex items-center justify-between group"
                                      >
                                         <div>
                                           <p className="text-xs font-black text-slate-900">{asset.id}</p>
                                           <p className="text-[10px] text-slate-700 font-semibold">{asset.brand} - {asset.model}</p>
                                         </div>
                                         <Plus className="w-4 h-4 text-slate-400 group-hover:text-blue-600" />
                                      </button>
                                    ))
                                  ) : (
                                    <div className="text-center py-4 space-y-2">
                                       <AlertCircle className="w-6 h-6 text-slate-400 mx-auto" />
                                       <p className="text-[10px] text-slate-600 font-bold uppercase">Ops! Não há saldo disponível para "{itemType}" no inventário.</p>
                                    </div>
                                  )}
                               </div>
                            </div>
                          )}
                        </div>
                      );
                    })}
                 </div>
               </div>

               <div className="space-y-3">
                  <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <MessageSquare className="w-4 h-4 text-blue-600" /> Justificativa do Pedido
                  </h4>
                  <div className="p-5 bg-white rounded-3xl border border-blue-200 text-sm text-slate-800 leading-relaxed font-semibold italic shadow-sm">
                    "{selectedRequest.observation || "Nenhuma observação informada pelo solicitante."}"
                  </div>
               </div>
            </div>

            <div className="p-6 border-t border-slate-200 bg-slate-50 flex flex-col gap-3">
               <div className="flex flex-col gap-2">
                 {selectedRequest.status === 'Pendente' && (
                   <button 
                    onClick={() => handleStatusChange('Aprovado')}
                    disabled={!selectedRequest.itemFulfillments || selectedRequest.itemFulfillments.length === 0}
                    className="w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-100 uppercase tracking-widest text-xs"
                   >
                     <Check className="w-5 h-5" />
                     Aprovar e Avançar para Preparação
                   </button>
                 )}

                 {selectedRequest.status === 'Aprovado' && (
                    <button 
                      onClick={() => handleStatusChange('Preparando')}
                      className="w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all bg-indigo-600 text-white hover:bg-indigo-700 shadow-xl shadow-indigo-100 uppercase tracking-widest text-xs"
                    >
                      <Wrench className="w-5 h-5" />
                      Iniciar Preparação Técnica
                    </button>
                 )}

                 {(selectedRequest.status === 'Aprovado' || selectedRequest.status === 'Preparando') && (
                    <button 
                      onClick={() => handleStatusChange('Entregue')}
                      disabled={selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !(f.isPurchaseOrder && f.purchaseStatus === 'Comprado'))}
                      className={`w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all uppercase tracking-widest text-xs ${
                        selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !(f.isPurchaseOrder && f.purchaseStatus === 'Comprado'))
                          ? 'bg-slate-200 text-slate-500 cursor-not-allowed border border-slate-300'
                          : 'bg-emerald-600 text-white hover:bg-emerald-700 shadow-xl shadow-emerald-100'
                      }`}
                    >
                      <Truck className="w-5 h-5" />
                      Finalizar Entrega ao Colaborador
                    </button>
                 )}
               </div>

               {selectedRequest.status === 'Entregue' && (
                 <div className="p-4 bg-emerald-100 rounded-2xl border border-emerald-300 flex items-center gap-3 text-emerald-800 font-black justify-center uppercase tracking-widest text-[10px]">
                    <CheckCircle className="w-5 h-5" />
                    Requisição Finalizada com Sucesso
                 </div>
               )}

               {selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !f.isPurchaseOrder) && selectedRequest.status === 'Pendente' && (
                 <p className="text-[10px] text-center text-rose-700 font-black uppercase tracking-tight">Atenção: Existem itens pendentes de triagem/vínculo.</p>
               )}
            </div>
          </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

