import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, Department, AuditSession, HistoryEntry } from './types';
import { db } from './services/supabase';
import { Loader2, AlertCircle, Package } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const [depts, assts, emps, reqs, audits, userList] = await Promise.all([
        db.departments.list().catch(() => []),
        db.assets.list().catch(() => []),
        db.employees.list().catch(() => []),
        db.requests.list().catch(() => []),
        db.auditSessions.list().catch(() => []),
        db.users.list().catch(() => [])
      ]);

      setDepartments(depts);
      setAssets(assts);
      setEmployees(emps);
      setRequests(reqs);
      setAuditSessions(audits);

      if (userList.length === 0) {
        setUsers(MOCK_USERS);
      } else {
        setUsers(userList);
      }
    } catch (err) {
      setError("Erro ao conectar com o banco de dados Supabase.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleLogin = async (user: UserAccount) => {
    const isInDatabase = users.some(u => u.username === user.username && u.id === user.id);

    if (!isInDatabase) {
      try {
        await db.users.upsert(user);
        const userList = await db.users.list();
        setUsers(userList);
      } catch (e) {
        console.warn("Aviso: Não foi possível salvar o perfil do usuário no banco. Verifique as políticas de RLS.");
      }
    }

    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 9000) + 1000}`;
    const initialHistory: HistoryEntry[] = assetData.history || [
      {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Criação',
        description: 'Ativo registrado no inventário.',
        performedBy: currentUser?.name || 'Sistema'
      }
    ];

    const newAsset: Asset = { 
      ...assetData, 
      id, 
      qrCode: `QR-${id}`,
      createdAt: new Date().toISOString(),
      history: initialHistory,
      observations: assetData.observations || ''
    };

    setAssets(prev => [newAsset, ...prev]);
    await db.assets.upsert(newAsset);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    setAssets(prev => prev.map(a => a.id === updated.id ? updated : a));
    await db.assets.upsert(updated);
  };

  const handleRemoveAsset = async (id: string) => {
    setAssets(prev => prev.filter(a => a.id !== id));
    await db.assets.remove(id);
  };

  const handleAddRequest = async (reqData: any) => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const newReq: EquipmentRequest = { 
      ...reqData, 
      id, 
      status: 'Pendente',
      createdAt: new Date().toISOString()
    };
    setRequests(prev => [newReq, ...prev]);
    await db.requests.upsert(newReq);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    setRequests(prev => prev.map(r => r.id === req.id ? req : r));
    await db.requests.upsert(req);
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    setAuditSessions(prev => prev.map(old => old.id === session.id ? session : old));
    await db.auditSessions.upsert(session);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
            <Package className="text-white w-10 h-10" />
          </div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">AssetTrack Pro</h1>
        </div>
        <div className="flex items-center gap-3">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Sincronizando com Supabase...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <AlertCircle className="w-16 h-16 text-rose-500 mb-4" />
        <h3 className="text-xl font-black text-slate-800 mb-2">Falha Crítica</h3>
        <p className="text-slate-500 max-w-sm mb-6">{error}</p>
        <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase text-[10px] tracking-widest">Tentar Reconectar</button>
      </div>
    );
  }

  if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} requests={requests}>
      {(() => {
        switch (activeTab) {
          case 'dashboard': 
            return <Dashboard assets={assets} requests={requests} employees={employees} />;

          case 'departments': 
            return <CompanyManager 
              companies={departments} 
              assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                setDepartments(prev => [...prev, newD]); 
                await db.departments.upsert(newD); 
              }} 
              onUpdateCompany={async (updated) => { 
                setDepartments(prev => prev.map(d => d.id === updated.id ? updated : d)); 
                await db.departments.upsert(updated); 
              }} 
              onRemoveCompany={async (id) => { 
                setDepartments(prev => prev.filter(d => d.id !== id)); 
                await db.departments.remove(id); 
              }} 
            />;

          case 'assets': 
            return <AssetManager 
              assets={assets} 
              employees={employees} 
              companies={departments} 
              onAdd={handleAddAsset} 
              onUpdate={handleUpdateAsset} 
              onRemove={handleRemoveAsset} 
            />;

          case 'employees': 
            return <EmployeeManager 
              employees={employees} 
              departments={departments} 
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`}; 
                setEmployees(prev => [...prev, newE]); 
                await db.employees.upsert(newE); 
              }} 
            />;

          case 'requests': 
            return <RequestsManager 
              requests={requests} 
              employees={employees} 
              assets={assets} 
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { 
                const req = requests.find(r => r.id === id); 
                if(!req) return;

                // Lógica de finalização de entrega com efeito cascata nos ativos
                if (status === 'Entregue') {
                  const employee = employees.find(e => e.id === req.employeeId);
                  if (employee) {
                    const fulfillments = req.itemFulfillments || [];
                    for (const f of fulfillments) {
                      if (f.linkedAssetId) {
                        const asset = assets.find(a => a.id === f.linkedAssetId);
                        if (asset) {
                          const historyEntry: HistoryEntry = {
                            id: Math.random().toString(),
                            date: new Date().toISOString(),
                            type: 'Atribuição',
                            description: `Entrega técnica concluída via protocolo ${req.id}. Ativo alocado ao colaborador ${employee.name} e transferido para o setor ${employee.sector}.`,
                            performedBy: currentUser?.name || 'Sistema',
                            userContext: employee.name
                          };

                          // Atualiza o ativo para o novo proprietário e departamento
                          await handleUpdateAsset({
                            ...asset,
                            status: 'Em Uso',
                            assignedTo: employee.id,
                            departmentId: employee.departmentId,
                            history: [...(asset.history || []), historyEntry]
                          });
                        }
                      }
                    }
                  }
                }

                // Finalmente atualiza o status da requisição
                await handleUpdateRequest({...req, status}); 
              }} 
            />;

          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={employees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                setAuditSessions(prev => [s, ...prev]); 
                await db.auditSessions.upsert(s); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, assetIds) => 
                handleAddRequest({ 
                  requesterId: currentUser?.id, 
                  employeeId: employees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => assetIds.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência de auditoria no setor ${sector}` 
                })
              } 
            />;

          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} 
              employees={employees} 
              companies={departments} 
              onUpdateAsset={handleUpdateAsset} 
            />;

          case 'purchase-orders': 
            return <PurchaseOrderManager 
              requests={requests} 
              employees={employees} 
              onUpdateRequest={handleUpdateRequest} 
              onAssetCreated={handleAddAsset} 
              onAddRequest={handleAddRequest}
            />;

          case 'printing': 
            return <PrintManager assets={assets} />;

          case 'user-management': 
            return <UserManager 
              users={users} 
              onAddUser={async (u) => { 
                const newU = {...u, id: Date.now().toString()}; 
                setUsers(prev => [...prev, newU]); 
                await db.users.upsert(newU); 
              }} 
              onUpdateUser={async (u) => { 
                setUsers(prev => prev.map(old => old.id === u.id ? u : old)); 
                await db.users.upsert(u); 
              }} 
              onRemoveUser={async (id) => { 
                setUsers(prev => prev.filter(u => u.id !== id)); 
                await db.users.remove(id); 
              }} 
            />;

          default: 
            return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Plus, 
  Search, 
  Trash2,
  X,
  Cpu,
  Layers,
  Monitor,
  Wifi,
  Usb,
  Zap,
  Type,
  History,
  Clock,
  User,
  Wrench,
  CheckCircle2,
  Tag,
  ArrowRight,
  ShieldCheck,
  FileSpreadsheet,
  PlusCircle,
  Save,
  MessageSquarePlus,
  AlertCircle,
  Loader2,
  Building2,
  Package,
  ArrowLeftRight
} from 'lucide-react';
import { Asset, AssetType, Employee, Department, HistoryEntry, AssetStatus } from '../types';
import { ASSET_TYPES } from '../constants';

interface AssetManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  onAdd: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode' | 'history'> & { id?: string }) => Promise<void>;
  onUpdate: (asset: Asset) => Promise<void>;
  onRemove: (id: string) => Promise<void>;
}

interface BulkAssetEntry {
  tempId: string;
  departmentId: string;
  type: AssetType;
  brand: string;
  model: string;
  ram: string;
  storage: string;
  screenSize: string;
  caseModel: string;
  isWireless: boolean;
  monitorInputs: string[];
  isAbnt: boolean;
  hasNumericKeypad: boolean;
  id: string; 
  assignedTo: string;
  observations: string;
}

const AssetManager: React.FC<AssetManagerProps> = ({ assets, employees, companies, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<string>('all');
  const [isSavingBulk, setIsSavingBulk] = useState(false);
  const [manualLog, setManualLog] = useState('');
  const [isUpdatingDept, setIsUpdatingDept] = useState(false);
  const [isUpdatingEmployee, setIsUpdatingEmployee] = useState(false);

  const [bulkEntries, setBulkEntries] = useState<BulkAssetEntry[]>([]);
  const [newAsset, setNewAsset] = useState<Partial<Asset>>({
    type: 'Notebook',
    status: 'Disponível',
    photos: [],
    departmentId: '',
    ram: '',
    storage: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: [],
    isAbnt: true,
    hasNumericKeypad: true
  });

  useEffect(() => {
    if (companies.length > 0 && !newAsset.departmentId) {
      setNewAsset(prev => ({ ...prev, departmentId: companies[0].id }));
      setBulkEntries([{ 
        tempId: '1', departmentId: companies[0].id, type: 'Notebook', brand: '', model: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' 
      }]);
    }
  }, [companies, showForm, showBulkModal]);

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';
  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'Em Estoque';

  const handleDepartmentChange = async (newDeptId: string) => {
    if (!detailAsset || newDeptId === detailAsset.departmentId) return;

    setIsUpdatingDept(true);
    const oldDeptName = getDepartmentName(detailAsset.departmentId);
    const newDeptName = getDepartmentName(newDeptId);

    const transferLog: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Status',
      description: `Transferência de departamento: de "${oldDeptName}" para "${newDeptName}".`,
      performedBy: 'Gestor de Ativos'
    };

    const updatedAsset: Asset = {
      ...detailAsset,
      departmentId: newDeptId,
      history: [...(detailAsset.history || []), transferLog]
    };

    try {
      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err) {
      alert("Erro ao transferir departamento.");
    } finally {
      setIsUpdatingDept(false);
    }
  };

  const handleEmployeeChange = async (newEmployeeId: string) => {
    if (!detailAsset) return;
    if (newEmployeeId === detailAsset.assignedTo) return;

    setIsUpdatingEmployee(true);
    const oldEmpName = getEmployeeName(detailAsset.assignedTo);
    const newEmp = employees.find(e => e.id === newEmployeeId);
    const newEmpName = newEmp?.name || 'Estoque';

    const historyEntry: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Atribuição',
      description: `Responsável alterado manualmente: de "${oldEmpName}" para "${newEmpName}".`,
      performedBy: 'Gestor de Ativos',
      userContext: newEmpName
    };

    // Se trocar o colaborador, também atualiza o departamento do ativo para o departamento do novo colaborador
    const updatedAsset: Asset = {
      ...detailAsset,
      assignedTo: newEmployeeId || undefined,
      departmentId: newEmp?.departmentId || detailAsset.departmentId,
      status: newEmployeeId ? 'Em Uso' : 'Disponível',
      history: [...(detailAsset.history || []), historyEntry]
    };

    try {
      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err) {
      alert("Erro ao alterar colaborador.");
    } finally {
      setIsUpdatingEmployee(false);
    }
  };

  const handleAddManualLog = async () => {
    if (!detailAsset || !manualLog.trim()) return;

    const newEntry: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Observação',
      description: manualLog,
      performedBy: 'Gestor de TI'
    };

    const updatedAsset: Asset = {
      ...detailAsset,
      history: [...(detailAsset.history || []), newEntry]
    };

    await onUpdate(updatedAsset);
    setDetailAsset(updatedAsset);
    setManualLog('');
  };

  const handleStatusChangeManual = async (newStatus: AssetStatus) => {
    if (!detailAsset) return;

    const newEntry: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Status',
      description: `Status alterado manualmente de ${detailAsset.status} para ${newStatus}.`,
      performedBy: 'Gestor de TI'
    };

    const updatedAsset: Asset = {
      ...detailAsset,
      status: newStatus,
      assignedTo: newStatus === 'Disponível' ? undefined : detailAsset.assignedTo,
      history: [...(detailAsset.history || []), newEntry]
    };

    await onUpdate(updatedAsset);
    setDetailAsset(updatedAsset);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAsset.departmentId) {
      alert("Selecione ou crie um departamento primeiro.");
      return;
    }
    await onAdd(newAsset as any);
    setShowForm(false);
    setNewAsset({ type: 'Notebook', status: 'Disponível', photos: [], departmentId: companies[0]?.id || '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true });
  };

  const handleBulkAddRow = () => {
    setBulkEntries([...bulkEntries, { 
      tempId: Math.random().toString(), 
      departmentId: companies[0]?.id || '', 
      type: 'Notebook', 
      brand: '', 
      model: '', 
      ram: '',
      storage: '',
      screenSize: '',
      caseModel: '',
      isWireless: false,
      monitorInputs: [],
      isAbnt: true,
      hasNumericKeypad: true,
      id: '', 
      assignedTo: '', 
      observations: '' 
    }]);
  };

  const handleBulkSave = async () => {
    if (companies.length === 0) {
      alert("Erro: Você precisa cadastrar pelo menos um Departamento antes.");
      return;
    }

    setIsSavingBulk(true);
    try {
      for (const entry of bulkEntries) {
        if (!entry.id) continue;
        await onAdd({
          id: entry.id,
          departmentId: entry.departmentId || companies[0].id,
          type: entry.type,
          brand: entry.brand,
          model: entry.model,
          ram: entry.ram,
          storage: entry.storage,
          screenSize: entry.screenSize,
          caseModel: entry.caseModel,
          isWireless: entry.isWireless,
          monitorInputs: entry.monitorInputs,
          isAbnt: entry.isAbnt,
          hasNumericKeypad: entry.hasNumericKeypad,
          observations: entry.observations,
          photos: [],
          status: entry.assignedTo ? 'Em Uso' : 'Disponível',
          assignedTo: entry.assignedTo || undefined,
        });
      }
      setShowBulkModal(false);
      setBulkEntries([{ tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' }]);
    } catch (err) {
      alert("Erro ao salvar ativos em lote.");
    } finally {
      setIsSavingBulk(false);
    }
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || a.type === filterType;
    return matchesSearch && matchesType;
  });

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 print:hidden">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por modelo, marca ou ID..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-300 bg-white focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm font-semibold placeholder:text-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
          <button onClick={() => setShowBulkModal(true)} className="flex items-center gap-2 px-4 py-3 text-xs font-black text-slate-800 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all uppercase tracking-widest">
            <FileSpreadsheet className="w-4 h-4 text-emerald-600" />
            Lançar Levantamento
          </button>
          <button onClick={() => setShowForm(true)} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black transition-all shadow-lg uppercase tracking-widest text-xs">
            <Plus className="w-5 h-5" />
            <span>Novo Ativo</span>
          </button>
        </div>
      </div>

