import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, Department, AuditSession, HistoryEntry } from './types';
import { db } from './services/supabase';
import { Loader2, AlertCircle, Package } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const [depts, assts, emps, reqs, audits, userList] = await Promise.all([
        db.departments.list().catch(() => []),
        db.assets.list().catch(() => []),
        db.employees.list().catch(() => []),
        db.requests.list().catch(() => []),
        db.auditSessions.list().catch(() => []),
        db.users.list().catch(() => [])
      ]);

      setDepartments(depts);
      setAssets(assts);
      setEmployees(emps);
      setRequests(reqs);
      setAuditSessions(audits);

      if (userList.length === 0) {
        setUsers(MOCK_USERS);
      } else {
        setUsers(userList);
      }
    } catch (err) {
      setError("Erro ao conectar com o banco de dados Supabase.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleLogin = async (user: UserAccount) => {
    const isInDatabase = users.some(u => u.username === user.username && u.id === user.id);

    if (!isInDatabase) {
      try {
        await db.users.upsert(user);
        const userList = await db.users.list();
        setUsers(userList);
      } catch (e) {
        console.warn("Aviso: Não foi possível salvar o perfil do usuário no banco. Verifique as políticas de RLS.");
      }
    }

    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 9000) + 1000}`;
    const initialHistory: HistoryEntry[] = assetData.history || [
      {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Criação',
        description: 'Ativo registrado no inventário.',
        performedBy: currentUser?.name || 'Sistema'
      }
    ];

    const newAsset: Asset = { 
      ...assetData, 
      id, 
      qrCode: `QR-${id}`,
      createdAt: new Date().toISOString(),
      history: initialHistory,
      observations: assetData.observations || ''
    };

    setAssets(prev => [newAsset, ...prev]);
    await db.assets.upsert(newAsset);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    setAssets(prev => prev.map(a => a.id === updated.id ? updated : a));
    await db.assets.upsert(updated);
  };

  const handleRemoveAsset = async (id: string) => {
    setAssets(prev => prev.filter(a => a.id !== id));
    await db.assets.remove(id);
  };

  const handleAddRequest = async (reqData: any) => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const newReq: EquipmentRequest = { 
      ...reqData, 
      id, 
      status: 'Pendente',
      createdAt: new Date().toISOString()
    };
    setRequests(prev => [newReq, ...prev]);
    await db.requests.upsert(newReq);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    setRequests(prev => prev.map(r => r.id === req.id ? req : r));
    await db.requests.upsert(req);
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    setAuditSessions(prev => prev.map(old => old.id === session.id ? session : old));
    await db.auditSessions.upsert(session);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
            <Package className="text-white w-10 h-10" />
          </div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">AssetTrack Pro</h1>
        </div>
        <div className="flex items-center gap-3">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Sincronizando com Supabase...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <AlertCircle className="w-16 h-16 text-rose-500 mb-4" />
        <h3 className="text-xl font-black text-slate-800 mb-2">Falha Crítica</h3>
        <p className="text-slate-500 max-w-sm mb-6">{error}</p>
        <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase text-[10px] tracking-widest">Tentar Reconectar</button>
      </div>
    );
  }

  if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} requests={requests}>
      {(() => {
        switch (activeTab) {
          case 'dashboard': 
            return <Dashboard assets={assets} requests={requests} employees={employees} />;

          case 'departments': 
            return <CompanyManager 
              companies={departments} 
              assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                setDepartments(prev => [...prev, newD]); 
                await db.departments.upsert(newD); 
              }} 
              onUpdateCompany={async (updated) => { 
                setDepartments(prev => prev.map(d => d.id === updated.id ? updated : d)); 
                await db.departments.upsert(updated); 
              }} 
              onRemoveCompany={async (id) => { 
                setDepartments(prev => prev.filter(d => d.id !== id)); 
                await db.departments.remove(id); 
              }} 
            />;

          case 'assets': 
            return <AssetManager 
              assets={assets} 
              employees={employees} 
              companies={departments} 
              onAdd={handleAddAsset} 
              onUpdate={handleUpdateAsset} 
              onRemove={handleRemoveAsset} 
            />;

          case 'employees': 
            return <EmployeeManager 
              employees={employees} 
              departments={departments} 
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`}; 
                setEmployees(prev => [...prev, newE]); 
                await db.employees.upsert(newE); 
              }} 
            />;

          case 'requests': 
            return <RequestsManager 
              requests={requests} 
              employees={employees} 
              assets={assets} 
              currentUser={currentUser}
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { 
                const req = requests.find(r => r.id === id); 
                if(!req) return;

                // Lógica de finalização de entrega com efeito cascata nos ativos
                if (status === 'Entregue') {
                  const employee = employees.find(e => e.id === req.employeeId);
                  if (employee) {
                    const fulfillments = req.itemFulfillments || [];
                    for (const f of fulfillments) {
                      if (f.linkedAssetId) {
                        const asset = assets.find(a => a.id === f.linkedAssetId);
                        if (asset) {
                          const historyEntry: HistoryEntry = {
                            id: Math.random().toString(),
                            date: new Date().toISOString(),
                            type: 'Atribuição',
                            description: `Entrega técnica concluída via protocolo ${req.id}. Ativo alocado ao colaborador ${employee.name} e transferido para o setor ${employee.sector}.`,
                            performedBy: currentUser?.name || 'Sistema',
                            userContext: employee.name
                          };

                          // Atualiza o ativo para o novo proprietário e departamento
                          await handleUpdateAsset({
                            ...asset,
                            status: 'Em Uso',
                            assignedTo: employee.id,
                            departmentId: employee.departmentId,
                            history: [...(asset.history || []), historyEntry]
                          });
                        }
                      }
                    }
                  }
                }

                // Finalmente atualiza o status da requisição
                await handleUpdateRequest({...req, status}); 
              }} 
            />;

          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={employees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                setAuditSessions(prev => [s, ...prev]); 
                await db.auditSessions.upsert(s); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, assetIds) => 
                handleAddRequest({ 
                  requesterId: currentUser?.id, 
                  employeeId: employees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => assetIds.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência de auditoria no setor ${sector}` 
                })
              } 
            />;

          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} 
              employees={employees} 
              companies={departments} 
              onUpdateAsset={handleUpdateAsset} 
            />;

          case 'purchase-orders': 
            return <PurchaseOrderManager 
              requests={requests} 
              employees={employees} 
              onUpdateRequest={handleUpdateRequest} 
              onAssetCreated={handleAddAsset} 
              onAddRequest={handleAddRequest}
            />;

          case 'printing': 
            return <PrintManager assets={assets} />;

          case 'user-management': 
            return <UserManager 
              users={users} 
              onAddUser={async (u) => { 
                const newU = {...u, id: Date.now().toString()}; 
                setUsers(prev => [...prev, newU]); 
                await db.users.upsert(newU); 
              }} 
              onUpdateUser={async (u) => { 
                setUsers(prev => prev.map(old => old.id === u.id ? u : old)); 
                await db.users.upsert(u); 
              }} 
              onRemoveUser={async (id) => { 
                setUsers(prev => prev.filter(u => u.id !== id)); 
                await db.users.remove(id); 
              }} 
            />;

          default: 
            return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  FileText, 
  Plus, 
  X, 
  Clock, 
  ChevronRight, 
  CheckCircle, 
  ShoppingCart, 
  Link as LinkIcon, 
  Search, 
  AlertCircle,
  User,
  Calendar,
  Package,
  Check,
  Ban,
  Truck,
  MessageSquare,
  CheckSquare,
  Wrench,
  UserPlus,
  Loader2,
  Printer,
  ShieldCheck,
  FileDown
} from 'lucide-react';
import { EquipmentRequest, Employee, Asset, AssetType, ItemFulfillment, UserAccount } from '../types';
import { ASSET_TYPES } from '../constants';

interface RequestsManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  assets: Asset[];
  currentUser: UserAccount;
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  onUpdateStatus: (id: string, status: EquipmentRequest['status']) => Promise<void>;
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
}

const RequestsManager: React.FC<RequestsManagerProps> = ({ requests, employees, assets, currentUser, onAddRequest, onUpdateStatus, onUpdateRequest }) => {
  const [showModal, setShowModal] = useState(false);
  const [showTermModal, setShowTermModal] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<EquipmentRequest | null>(null);
  const [itemToLink, setItemToLink] = useState<{ index: number; type: AssetType } | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newReq, setNewReq] = useState<Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>>({
    requesterId: currentUser.id, 
    employeeId: '',
    items: [],
    observation: ''
  });

  const getEmployee = (id: string) => employees.find(e => e.id === id);
  const getEmployeeName = (id: string) => getEmployee(id)?.name || 'Desconhecido';
  const getEmployeeSector = (id: string) => getEmployee(id)?.sector || 'Setor não informado';

  const getLinkedAssetInfo = (assetId?: string) => {
    if (!assetId) return null;
    return assets.find(a => a.id === assetId);
  };

  const toggleItem = (type: AssetType) => {
    setNewReq(prev => ({
      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newReq.items.length === 0) {
      alert("Selecione pelo menos um item.");
      return;
    }
    if (!newReq.employeeId) {
      alert("Selecione o colaborador destinatário.");
      return;
    }

    setIsSubmitting(true);
    try {
      await onAddRequest({
        ...newReq,
        itemFulfillments: newReq.items.map(type => ({
          type,
          isPurchaseOrder: false
        }))
      });
      setShowModal(false);
      setNewReq({ requesterId: currentUser.id, employeeId: '', items: [], observation: '' });
    } catch (err) {
      alert("Erro ao criar requisição.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleLinkAsset = async (index: number, assetId: string) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: assetId,
      isPurchaseOrder: false
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleMarkForPurchase = async (index: number) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: undefined,
      isPurchaseOrder: true,
      purchaseStatus: 'Pendente'
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
  };

  const handleStatusChange = async (status: EquipmentRequest['status']) => {
    if (selectedRequest) {
      await onUpdateStatus(selectedRequest.id, status);
      setSelectedRequest(prev => prev ? { ...prev, status } : null);
    }
  };

  const availableAssetsByType = (type: AssetType) => {
    return assets.filter(a => a.type === type && a.status === 'Disponível');
  };

  const handlePrintTerm = () => {
    window.print();
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 relative">
      <div className="lg:col-span-2 space-y-4 print:hidden">
        <h3 className="text-lg font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight">
          <Clock className="w-5 h-5 text-blue-600" /> Fluxo de Atendimento
        </h3>

        {requests.map(req => (
          <div 
            key={req.id} 
            onClick={() => setSelectedRequest(req)}
            className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between hover:shadow-md transition-all group cursor-pointer border-l-4 border-l-transparent hover:border-l-blue-600"
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${
                req.status === 'Pendente' ? 'bg-amber-100 text-amber-700' :
                req.status === 'Aprovado' ? 'bg-blue-100 text-blue-700' :
                req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-700' :
                req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'
              }`}>
                {req.status === 'Preparando' ? <Wrench className="w-6 h-6" /> : req.status === 'Entregue' ? <ShieldCheck className="w-6 h-6" /> : <FileText className="w-6 h-6" />}
              </div>
              <div>
                <div className="flex items-center gap-2">
                  <p className="font-black text-slate-900">{req.id}</p>
                  {req.itemFulfillments?.some(f => f.isPurchaseOrder) && (
                    <span className="bg-amber-100 text-amber-800 px-2 py-0.5 rounded-full text-[9px] font-black uppercase flex items-center gap-1 border border-amber-200">
                      <ShoppingCart className="w-2.5 h-2.5" /> Compra
                    </span>
                  )}
                </div>
                <p className="text-sm text-slate-600 font-semibold">Para: {getEmployeeName(req.employeeId)}</p>
              </div>
            </div>

            <div className="flex items-center gap-6">
               <div className="hidden md:flex flex-col items-end">
                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Itens</span>
                  <span className="text-sm font-black text-slate-800">{req.items.length} eqp.</span>
               </div>
               <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-tight ${
                 req.status === 'Pendente' ? 'bg-amber-100 text-amber-800 border border-amber-200' : 
                 req.status === 'Aprovado' ? 'bg-blue-100 text-blue-800 border border-blue-200' :
                 req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-800 border border-indigo-200' :
