                <FileText className="w-10 h-10 text-slate-300" />
             </div>
             <p className="text-slate-600 font-black uppercase tracking-widest text-xs">Nenhuma solicitação pendente de triagem.</p>
          </div>
        )}
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-xl h-fit space-y-6 sticky top-24 print:hidden">
        <div className="bg-blue-50 p-5 rounded-3xl mb-6 border border-blue-100">
           <div className="flex items-center gap-2 text-blue-700 mb-2">
             <AlertCircle className="w-5 h-5" />
             <h4 className="font-black text-sm uppercase tracking-widest">Triagem de Ativos</h4>
           </div>
           <p className="text-xs text-blue-800 leading-relaxed font-semibold">
             Toda requisição deve ser vinculada a um item do inventário ou gerar um pedido de compra aprovado pela diretoria.
           </p>
        </div>

        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-slate-900 hover:bg-black text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-2 group uppercase tracking-widest text-xs"
        >
          <Plus className="w-5 h-5 group-hover:rotate-90 transition-transform" />
          <span>Abrir Nova Requisição</span>
        </button>
      </div>

      {/* MODAL DE CRIAÇÃO DE REQUISIÇÃO */}
      {showModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md print:hidden">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
              <div className="bg-slate-900 p-8 text-white flex items-center justify-between shrink-0">
                 <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center"><UserPlus className="w-5 h-5" /></div>
                    <h3 className="text-xl font-black uppercase tracking-tight">Nova Requisição de Equipamentos</h3>
                 </div>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-6 h-6" /></button>
              </div>

              <form onSubmit={handleSubmit} className="p-10 space-y-8 overflow-y-auto custom-scrollbar flex-1">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Colaborador Destinatário</label>
                    <div className="relative">
                       <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                       <select 
                        className="w-full pl-12 pr-4 py-4 rounded-2xl bg-slate-50 border-none outline-none font-bold appearance-none shadow-sm focus:ring-2 focus:ring-blue-600"
                        value={newReq.employeeId}
                        onChange={e => setNewReq({...newReq, employeeId: e.target.value})}
                        required
                       >
                         <option value="">Selecione o colaborador...</option>
                         {employees.map(emp => (
                           <option key={emp.id} value={emp.id}>{emp.name} — {emp.sector}</option>
                         ))}
                       </select>
                    </div>
                 </div>

                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Itens Requisitados</label>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                       {ASSET_TYPES.map(type => (
                         <button
                          key={type}
                          type="button"
                          onClick={() => toggleItem(type as AssetType)}
                          className={`p-3 rounded-xl border text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${
                            newReq.items.includes(type as AssetType) 
                              ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100' 
                              : 'bg-white border-slate-200 text-slate-600 hover:border-blue-300'
                          }`}
                         >
                           {newReq.items.includes(type as AssetType) && <Check className="w-3 h-3" />}
                           {type}
                         </button>
                       ))}
                    </div>
                 </div>

                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observações / Motivo</label>
                    <textarea 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold h-32 outline-none focus:ring-2 focus:ring-blue-600"
                      placeholder="Ex: Novo colaborador iniciando segunda-feira. Precisa de setup completo."
                      value={newReq.observation}
                      onChange={e => setNewReq({...newReq, observation: e.target.value})}
                      required
                    />
                 </div>

                 <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs flex items-center justify-center gap-3 transition-all disabled:bg-slate-300"
                 >
                    {isSubmitting ? (
                      <Loader2 className="w-5 h-5 animate-spin" />
                    ) : (
                      <>
                        <CheckCircle className="w-5 h-5" /> Abrir Protocolo de Requisição
                      </>
                    )}
                 </button>
              </form>
           </div>
        </div>
      )}

      {selectedRequest && (
        <div className="fixed inset-0 z-[100] flex justify-end print:hidden">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => { setSelectedRequest(null); setItemToLink(null); }} />
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300 border-l border-slate-200">
            <div className="p-6 border-b border-slate-200 flex items-center justify-between bg-white">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-100">
                  <CheckSquare className="w-6 h-6" />
                </div>
                <div>
                  <h3 className="text-xl font-black text-slate-900">Triagem Técnica</h3>
                  <p className="text-sm text-slate-600 font-bold">{selectedRequest.id}</p>
                </div>
              </div>
              <button onClick={() => { setSelectedRequest(null); setItemToLink(null); }} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500 hover:text-slate-900">
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-white">
               <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-full bg-white border border-slate-300 flex items-center justify-center text-slate-500">
                      <User className="w-6 h-6" />
                    </div>
                    <div>
                      <p className="text-sm font-black text-slate-900">{getEmployeeName(selectedRequest.employeeId)}</p>
                      <p className="text-xs text-slate-700 font-bold uppercase tracking-tight">{getEmployeeSector(selectedRequest.employeeId)}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Data Solicitação</p>
                    <p className="text-xs font-black text-slate-900">{new Date(selectedRequest.createdAt).toLocaleDateString('pt-BR')}</p>
                  </div>
               </div>

               <div className="space-y-4">
                 <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                   <Package className="w-4 h-4 text-blue-600" /> Itens Requisitados ({selectedRequest.items.length})
                 </h4>

                 <div className="space-y-4">
                    {selectedRequest.items.map((itemType, idx) => {
                      const fulfillment = selectedRequest.itemFulfillments?.[idx];
                      const isLinked = !!fulfillment?.linkedAssetId;
                      const isPurchase = !!fulfillment?.isPurchaseOrder;

                      return (
                        <div key={idx} className={`border p-5 rounded-3xl transition-all ${
                          isLinked ? 'bg-emerald-50 border-emerald-200' : 
                          isPurchase ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-200 shadow-sm'
                        }`}>
                          <div className="flex items-center justify-between mb-4">
                            <div className="flex items-center gap-3">
                              <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${
                                isLinked ? 'bg-emerald-100 text-emerald-800' : 
                                isPurchase ? 'bg-amber-100 text-amber-800' : 'bg-slate-100 text-slate-600'
                              }`}>
                                <Package className="w-5 h-5" />
                              </div>
                              <span className="font-black text-slate-900">{itemType}</span>
                            </div>

                            {isLinked ? (
                              <div className="flex items-center gap-1 text-emerald-800">
                                <CheckCircle className="w-4 h-4" />
                                <span className="text-[10px] font-black uppercase tracking-tight">Vinculado: {fulfillment.linkedAssetId}</span>
                              </div>
                            ) : isPurchase ? (
                              <div className={`flex items-center gap-1 ${fulfillment.purchaseStatus === 'Comprado' ? 'text-emerald-800' : 'text-amber-800'}`}>
                                <ShoppingCart className="w-4 h-4" />
                                <span className="text-[10px] font-black uppercase tracking-tight">Status: {fulfillment.purchaseStatus || 'Pendente'}</span>
                              </div>
                            ) : (
                              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Aguardando Triagem</span>
                            )}
                          </div>

                          {!isLinked && !isPurchase && (
                            <div className="grid grid-cols-2 gap-3">
                               <button 
                                onClick={() => setItemToLink({ index: idx, type: itemType })}
                                className="bg-white border border-slate-300 py-2.5 rounded-2xl text-xs font-black text-slate-800 flex items-center justify-center gap-2 hover:bg-slate-900 hover:text-white transition-all shadow-sm uppercase tracking-widest"
                               >
                                 <LinkIcon className="w-3.5 h-3.5" /> Vincular Estoque
                               </button>
                               <button 
                                onClick={() => handleMarkForPurchase(idx)}
                                className="bg-white border border-slate-300 py-2.5 rounded-2xl text-xs font-black text-slate-800 flex items-center justify-center gap-2 hover:bg-slate-900 hover:text-white transition-all shadow-sm uppercase tracking-widest"
                               >
                                 <ShoppingCart className="w-3.5 h-3.5" /> Pedido Compra
                               </button>
                            </div>
                          )}

                          {itemToLink?.index === idx && (
                            <div className="mt-4 p-4 bg-slate-100 rounded-2xl border border-slate-300 animate-in fade-in zoom-in-95">
                               <div className="flex items-center justify-between mb-3">
                                  <h5 className="text-[10px] font-black text-slate-700 uppercase tracking-widest">Escolha um item disponível:</h5>
                                  <button onClick={() => setItemToLink(null)} className="text-slate-500 hover:text-slate-900">
                                    <X className="w-3 h-3" />
                                  </button>
                               </div>
                               <div className="space-y-2 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
                                  {availableAssetsByType(itemType).length > 0 ? (
                                    availableAssetsByType(itemType).map(asset => (
                                      <button 
                                        key={asset.id}
                                        onClick={() => handleLinkAsset(idx, asset.id)}
                                        className="w-full text-left p-3 rounded-xl bg-white border border-slate-300 hover:border-blue-600 hover:shadow-sm transition-all flex items-center justify-between group"
                                      >
                                         <div>
                                           <p className="text-xs font-black text-slate-900">{asset.id}</p>
                                           <p className="text-[10px] text-slate-700 font-semibold">{asset.brand} - {asset.model}</p>
                                         </div>
                                         <Plus className="w-4 h-4 text-slate-400 group-hover:text-blue-600" />
                                      </button>
                                    ))
                                  ) : (
                                    <div className="text-center py-4 space-y-2">
                                       <AlertCircle className="w-6 h-6 text-slate-400 mx-auto" />
                                       <p className="text-[10px] text-slate-600 font-bold uppercase">Ops! Não há saldo disponível para "{itemType}" no inventário.</p>
                                    </div>
                                  )}
                               </div>
                            </div>
                          )}
                        </div>
                      );
                    })}
                 </div>
               </div>

               <div className="space-y-3">
                  <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <MessageSquare className="w-4 h-4 text-blue-600" /> Justificativa do Pedido
                  </h4>
                  <div className="p-5 bg-white rounded-3xl border border-blue-200 text-sm text-slate-800 leading-relaxed font-semibold italic shadow-sm">
                    "{selectedRequest.observation || "Nenhuma observação informada pelo solicitante."}"
                  </div>
               </div>
            </div>

            <div className="p-6 border-t border-slate-200 bg-slate-50 flex flex-col gap-3">
               <div className="flex flex-col gap-2">
                 {selectedRequest.status === 'Pendente' && (
                   <button 
                    onClick={() => handleStatusChange('Aprovado')}
                    disabled={!selectedRequest.itemFulfillments || selectedRequest.itemFulfillments.length === 0}
                    className="w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-100 uppercase tracking-widest text-xs"
                   >
                     <Check className="w-5 h-5" />
                     Aprovar e Avançar para Preparação
                   </button>
                 )}

                 {selectedRequest.status === 'Aprovado' && (
                    <button 
                      onClick={() => handleStatusChange('Preparando')}
                      className="w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all bg-indigo-600 text-white hover:bg-indigo-700 shadow-xl shadow-indigo-100 uppercase tracking-widest text-xs"
                    >
                      <Wrench className="w-5 h-5" />
                      Iniciar Preparação Técnica
                    </button>
                 )}

                 {(selectedRequest.status === 'Aprovado' || selectedRequest.status === 'Preparando') && (
                    <button 
                      onClick={() => handleStatusChange('Entregue')}
                      disabled={selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !(f.isPurchaseOrder && f.purchaseStatus === 'Comprado'))}
                      className={`w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all uppercase tracking-widest text-xs ${
                        selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !(f.isPurchaseOrder && f.purchaseStatus === 'Comprado'))
                          ? 'bg-slate-200 text-slate-500 cursor-not-allowed border border-slate-300'
                          : 'bg-emerald-600 text-white hover:bg-emerald-700 shadow-xl shadow-emerald-100'
                      }`}
                    >
                      <Truck className="w-5 h-5" />
                      Finalizar Entrega ao Colaborador
                    </button>
                 )}

                 {selectedRequest.status === 'Entregue' && (
                    <button 
                      onClick={() => setShowTermModal(true)}
                      className="w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all bg-slate-900 text-white hover:bg-black shadow-xl uppercase tracking-widest text-xs"
                    >
                      <FileDown className="w-5 h-5" />
                      Gerar Termo de Responsabilidade
                    </button>
                 )}
               </div>

               {selectedRequest.status === 'Entregue' && (
                 <div className="p-4 bg-emerald-100 rounded-2xl border border-emerald-300 flex items-center gap-3 text-emerald-800 font-black justify-center uppercase tracking-widest text-[10px]">
                    <CheckCircle className="w-5 h-5" />
                    Requisição Finalizada com Sucesso
                 </div>
               )}

               {selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !f.isPurchaseOrder) && selectedRequest.status === 'Pendente' && (
                 <p className="text-[10px] text-center text-rose-700 font-black uppercase tracking-tight">Atenção: Existem itens pendentes de triagem/vínculo.</p>
               )}
            </div>
          </div>
        </div>
      )}

      {/* MODAL DO TERMO DE RESPONSABILIDADE */}
      {showTermModal && selectedRequest && (
        <div className="fixed inset-0 z-[200] flex flex-col bg-slate-900/90 backdrop-blur-md animate-in fade-in duration-300 print:bg-white print:p-0">
          <div className="h-20 bg-slate-800 border-b border-slate-700 flex items-center justify-between px-8 text-white shadow-2xl print:hidden">
            <div className="flex items-center gap-4">
               <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center">
                  <ShieldCheck className="w-6 h-6" />
               </div>
               <div>
                  <h3 className="font-black tracking-tight">Termo de Responsabilidade</h3>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Protocolo: {selectedRequest.id}</p>
               </div>
            </div>
            <div className="flex items-center gap-3">
               <button onClick={() => setShowTermModal(false)} className="px-6 py-2.5 rounded-xl font-bold text-slate-400 hover:text-white transition-all">Fechar</button>
               <button onClick={handlePrintTerm} className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-black flex items-center gap-2 shadow-xl transition-all">
                 <Printer className="w-5 h-5" /> Imprimir Documento
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-auto p-12 flex justify-center bg-slate-900/50 print:p-0 print:bg-white">
             <div className="w-full max-w-[210mm] bg-white shadow-2xl p-16 text-slate-900 min-h-[297mm] flex flex-col border border-slate-200 print:shadow-none print:border-none print:p-8">
                {/* Cabeçalho do Documento */}
                <div className="flex justify-between items-start border-b-2 border-slate-900 pb-8 mb-10">
                   <div>
                      <h1 className="text-3xl font-black uppercase tracking-tighter">AssetTrack Pro</h1>
                      <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Gestão Inteligente de Ativos TI</p>
                   </div>
                   <div className="text-right">
                      <h2 className="text-xl font-black uppercase">Termo de Responsabilidade</h2>
                      <p className="text-xs font-bold text-slate-500">Documento Interno ID: {selectedRequest.id}</p>
                   </div>
                </div>

                {/* Conteúdo do Termo */}
                <div className="flex-1 space-y-10">
                   <div className="space-y-4">
                      <p className="text-sm font-medium leading-relaxed text-justify">
                         Pelo presente instrumento, o colaborador abaixo identificado declara ter recebido da empresa, em perfeitas condições de uso e funcionamento, o(s) equipamento(s) de TI discriminado(s) neste termo, assumindo total responsabilidade pela guarda, conservação e uso adequado dos mesmos exclusivamente para fins profissionais.
                      </p>
                   </div>

                   {/* Dados do Colaborador */}
                   <div className="grid grid-cols-2 gap-8 bg-slate-50 p-6 border border-slate-200 rounded-lg">
                      <div>
                         <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Colaborador</p>
                         <p className="text-sm font-black">{getEmployeeName(selectedRequest.employeeId)}</p>
                      </div>
                      <div>
                         <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Setor / Departamento</p>
                         <p className="text-sm font-black">{getEmployeeSector(selectedRequest.employeeId)}</p>
                      </div>
                      <div>
                         <p className="text-[10px] font-black uppercase text-slate-400 mb-1">CPF</p>
                         <p className="text-sm font-black">{getEmployee(selectedRequest.employeeId)?.cpf || 'N/A'}</p>
                      </div>
                      <div>
                         <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Data de Recebimento</p>
                         <p className="text-sm font-black">{new Date().toLocaleDateString('pt-BR')}</p>
                      </div>
                   </div>

                   {/* Tabela de Equipamentos */}
                   <div className="space-y-4">
                      <h4 className="text-xs font-black uppercase border-b border-slate-900 pb-2">Equipamentos Entregues</h4>
                      <table className="w-full text-left border-collapse">
                         <thead>
                            <tr className="bg-slate-100 border-b border-slate-900">
                               <th className="p-3 text-[10px] font-black uppercase">Tipo</th>
                               <th className="p-3 text-[10px] font-black uppercase">Marca/Modelo</th>
                               <th className="p-3 text-[10px] font-black uppercase">ID Patrimonial</th>
                            </tr>
                         </thead>
                         <tbody>
                            {selectedRequest.itemFulfillments?.map((f, i) => {
                               const assetInfo = getLinkedAssetInfo(f.linkedAssetId);
                               return (
                                  <tr key={i} className="border-b border-slate-200">
                                     <td className="p-3 text-sm font-bold">{f.type}</td>
                                     <td className="p-3 text-sm">{assetInfo ? `${assetInfo.brand} ${assetInfo.model}` : 'N/A'}</td>
                                     <td className="p-3 text-sm font-mono font-black">{f.linkedAssetId || 'Aguardando'}</td>
                                  </tr>
                               );
                            })}
                         </tbody>
                      </table>
                   </div>

                   {/* Cláusulas de Compromisso */}
                   <div className="space-y-4 pt-4">
                      <h4 className="text-xs font-black uppercase border-b border-slate-900 pb-2">Cláusulas de Uso</h4>
                      <ol className="list-decimal pl-5 space-y-3 text-[11px] font-medium text-slate-700 leading-tight">
                         <li>O colaborador compromete-se a zelar pelo equipamento, mantendo-o em local seguro e adequado.</li>
                         <li>É expressamente proibido a instalação de softwares não autorizados ou alteração de hardware sem prévia anuência do departamento de TI.</li>
                         <li>Em caso de dano por negligência, perda ou extravio do equipamento, o colaborador poderá ser responsabilizado pelos custos de reparo ou reposição, conforme legislação vigente.</li>
                         <li>Em caso de desligamento da empresa, o equipamento deve ser devolvido imediatamente ao departamento de TI no mesmo estado de conservação em que foi recebido.</li>
                         <li>O uso dos equipamentos deve seguir estritamente as políticas de segurança da informação e código de conduta da organização.</li>
                      </ol>
                   </div>
                </div>

                {/* Assinaturas */}
                <div className="mt-20 grid grid-cols-2 gap-20">
                   <div className="text-center space-y-2">
                      <div className="border-t border-slate-900 pt-2">
                         <p className="text-[10px] font-black uppercase">Assinatura do Colaborador</p>
                         <p className="text-[8px] text-slate-400 font-bold uppercase">{getEmployeeName(selectedRequest.employeeId)}</p>
                      </div>
                   </div>
                   <div className="text-center space-y-2">
                      <div className="border-t border-slate-900 pt-2">
                         <p className="text-[10px] font-black uppercase">Responsável pela Entrega (Empresa)</p>
                         <p className="text-[8px] text-slate-400 font-bold uppercase">{currentUser.name} — {currentUser.sector}</p>
                      </div>
                   </div>
                </div>

                <div className="mt-auto pt-10 text-center">
                   <p className="text-[8px] text-slate-400 font-black uppercase tracking-[0.2em]">Documento Gerado pelo Módulo de Requisições v2.5 • {new Date().toLocaleDateString('pt-BR')} {new Date().toLocaleTimeString('pt-BR')}</p>
                </div>
             </div>
          </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }

        @media print {
          body, html { margin: 0; padding: 0; background: white; }
          #root { display: none; }
          .print-container { display: block !important; }
          @page { size: portrait; margin: 1cm; }
        }
      `}</style>
    </div>
  );
};

export default RequestsManager;

export type AssetType = 
  | 'Desktop' 
  | 'Notebook' 
  | 'Mouse' 
  | 'Cabo' 
  | 'Monitor' 
  | 'Teclado' 
  | 'Headset' 
  | 'Suporte Notebook';

export type AssetStatus = 'Disponível' | 'Em Uso' | 'Manutenção' | 'Baixado' | 'Pendente Documentos';

export interface HistoryEntry {
  id: string;
  date: string;
  type: 'Manutenção' | 'Atribuição' | 'Status' | 'Criação' | 'Observação';
  description: string;
  performedBy?: string;
  userContext?: string; // Nome do colaborador envolvido, se houver
}

export interface Department {
  id: string;
  name: string;
  costCenter?: string;
  createdAt: string;
}

export interface Asset {
  id: string;
  departmentId: string; // Vínculo com o departamento
  type: AssetType;
  brand: string;
  model: string;
  ram?: string;
  storage?: string;
  processor?: string;
  screenSize?: string;
  caseModel?: string; 
  isWireless?: boolean; 
  monitorInputs?: string[]; 
  isAbnt?: boolean; 
  hasNumericKeypad?: boolean; 
  observations: string;
  photos: string[];
  status: AssetStatus;
  assignedTo?: string; // Employee ID
  qrCode: string;
  createdAt: string;
  history: HistoryEntry[]; // Novo campo para rastreio
}

export interface Employee {
  id: string;
  departmentId: string; // Vínculo com o departamento
  name: string;
  sector: string;
  role: string;
  cpf: string;
}

export type AppModule = 
  | 'dashboard' 
  | 'departments'
  | 'assets' 
  | 'employees' 
  | 'requests' 
  | 'purchase-orders' 
  | 'printing' 
  | 'user-management' 
  | 'inventory-check'
  | 'maintenance';

export interface UserAccount {
  id: string;
  name: string;
  username: string;
  password?: string;
  sector: string;
  modules: AppModule[];
  employeeId?: string; // Vínculo obrigatório com Colaborador
}

export interface Quotation {
  url: string;
  price?: number;
  deliveryPrediction: string;
}

export interface ItemFulfillment {
  type: AssetType;
  linkedAssetId?: string;
  isPurchaseOrder: boolean;
  purchaseStatus?: 'Pendente' | 'Cotação Aprovada' | 'Pedido Autorizado' | 'Comprado';
  quotations?: Quotation[];
  approvedQuotationIndex?: number;
  deliveryForecastDate?: string;
  isDelivered?: boolean;
}

export interface EquipmentRequest {
  id: string;
  requesterId: string;
  employeeId: string;
  items: AssetType[];
  itemFulfillments?: ItemFulfillment[];
  observation?: string;
  status: 'Pendente' | 'Aprovado' | 'Preparando' | 'Entregue' | 'Cancelado' | 'Confronto';
  createdAt: string;
  type?: 'Padrao' | 'Divergencia';
}

export type AuditStatus = 'Bom' | 'Regular' | 'Ruim' | 'Não Encontrado';

export interface AuditEntry {
  assetId: string;
  status: AuditStatus;
  checkedAt: string;
  observation?: string;
}

export interface AuditSession {
  id: string;
  sector: string;
  createdAt: string;
  entries: AuditEntry[];
  isFinished: boolean;
  generatedRequestId?: string;
}

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, Department, AuditSession, HistoryEntry } from './types';
import { db } from './services/supabase';
import { Loader2, AlertCircle, Package } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const [depts, assts, emps, reqs, audits, userList] = await Promise.all([
        db.departments.list().catch(() => []),
        db.assets.list().catch(() => []),
        db.employees.list().catch(() => []),
        db.requests.list().catch(() => []),
        db.auditSessions.list().catch(() => []),
        db.users.list().catch(() => [])
      ]);

      setDepartments(depts);
      setAssets(assts);
      setEmployees(emps);
      setRequests(reqs);
      setAuditSessions(audits);

      if (userList.length === 0) {
        setUsers(MOCK_USERS);
      } else {
        setUsers(userList);
      }
    } catch (err) {
      setError("Erro ao conectar com o banco de dados Supabase.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleLogin = async (user: UserAccount) => {
    const isInDatabase = users.some(u => u.username === user.username && u.id === user.id);

    if (!isInDatabase) {
      try {
        await db.users.upsert(user);
        const userList = await db.users.list();
        setUsers(userList);
      } catch (e) {
        console.warn("Aviso: Não foi possível salvar o perfil do usuário no banco. Verifique as políticas de RLS.");
      }
    }

    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 9000) + 1000}`;
    const initialHistory: HistoryEntry[] = assetData.history || [
      {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Criação',
        description: 'Ativo registrado no inventário.',
        performedBy: currentUser?.name || 'Sistema'
      }
    ];

    const newAsset: Asset = { 
      ...assetData, 
      id, 
      qrCode: `QR-${id}`,
      createdAt: new Date().toISOString(),
      history: initialHistory,
      observations: assetData.observations || ''
    };

    setAssets(prev => [newAsset, ...prev]);
    await db.assets.upsert(newAsset);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    setAssets(prev => prev.map(a => a.id === updated.id ? updated : a));
    await db.assets.upsert(updated);
  };

  const handleRemoveAsset = async (id: string) => {
    setAssets(prev => prev.filter(a => a.id !== id));
    await db.assets.remove(id);
  };

  const handleAddRequest = async (reqData: any) => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const newReq: EquipmentRequest = { 
      ...reqData, 
      id, 
      status: 'Pendente',
      createdAt: new Date().toISOString()
    };
    setRequests(prev => [newReq, ...prev]);
    await db.requests.upsert(newReq);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    setRequests(prev => prev.map(r => r.id === req.id ? req : r));
    await db.requests.upsert(req);
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    setAuditSessions(prev => prev.map(old => old.id === session.id ? session : old));
    await db.auditSessions.upsert(session);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
            <Package className="text-white w-10 h-10" />
          </div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">AssetTrack Pro</h1>
        </div>
        <div className="flex items-center gap-3">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Sincronizando com Supabase...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <AlertCircle className="w-16 h-16 text-rose-500 mb-4" />
        <h3 className="text-xl font-black text-slate-800 mb-2">Falha Crítica</h3>
        <p className="text-slate-500 max-w-sm mb-6">{error}</p>
        <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase text-[10px] tracking-widest">Tentar Reconectar</button>
      </div>
    );
  }

  if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} requests={requests}>
      {(() => {
        switch (activeTab) {
          case 'dashboard': 
            return <Dashboard assets={assets} requests={requests} employees={employees} />;

          case 'departments': 
            return <CompanyManager 
              companies={departments} 
              assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                setDepartments(prev => [...prev, newD]); 
                await db.departments.upsert(newD); 
              }} 
              onUpdateCompany={async (updated) => { 
                setDepartments(prev => prev.map(d => d.id === updated.id ? updated : d)); 
                await db.departments.upsert(updated); 
              }} 
              onRemoveCompany={async (id) => { 
                setDepartments(prev => prev.filter(d => d.id !== id)); 
                await db.departments.remove(id); 
              }} 
            />;

          case 'assets': 
            return <AssetManager 
              assets={assets} 
              employees={employees} 
              companies={departments} 
              onAdd={handleAddAsset} 
              onUpdate={handleUpdateAsset} 
              onRemove={handleRemoveAsset} 
            />;

          case 'employees': 
            return <EmployeeManager 
              employees={employees} 
              departments={departments} 
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`}; 
                setEmployees(prev => [...prev, newE]); 
                await db.employees.upsert(newE); 
              }} 
            />;

          case 'requests': 
            return <RequestsManager 
              requests={requests} 
              employees={employees} 
              assets={assets} 
              currentUser={currentUser}
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { 
                const req = requests.find(r => r.id === id); 
                if(!req) return;

                // Lógica de finalização de entrega com efeito cascata nos ativos
                if (status === 'Entregue') {
                  const employee = employees.find(e => e.id === req.employeeId);
                  if (employee) {
                    const fulfillments = req.itemFulfillments || [];
                    for (const f of fulfillments) {
                      if (f.linkedAssetId) {
                        const asset = assets.find(a => a.id === f.linkedAssetId);
                        if (asset) {
                          const historyEntry: HistoryEntry = {
                            id: Math.random().toString(),
                            date: new Date().toISOString(),
                            type: 'Atribuição',
                            description: `Entrega técnica concluída via protocolo ${req.id}. Ativo alocado ao colaborador ${employee.name} e transferido para o setor ${employee.sector}.`,
                            performedBy: currentUser?.name || 'Sistema',
                            userContext: employee.name
                          };

                          // Atualiza o ativo para o novo proprietário e departamento
                          await handleUpdateAsset({
                            ...asset,
                            status: 'Em Uso',
                            assignedTo: employee.id,
                            departmentId: employee.departmentId,
                            history: [...(asset.history || []), historyEntry]
                          });
                        }
                      }
                    }
                  }
                }

                // Finalmente atualiza o status da requisição
                await handleUpdateRequest({...req, status}); 
              }} 
            />;

          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={employees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                setAuditSessions(prev => [s, ...prev]); 
                await db.auditSessions.upsert(s); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, assetIds) => 
                handleAddRequest({ 
                  requesterId: currentUser?.id, 
                  employeeId: employees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => assetIds.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência de auditoria no setor ${sector}` 
                })
              } 
            />;

          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} 
              employees={employees} 
              companies={departments} 
              onUpdateAsset={handleUpdateAsset} 
            />;

          case 'purchase-orders': 
            return <PurchaseOrderManager 
              requests={requests} 
              employees={employees} 
              onUpdateRequest={handleUpdateRequest} 
              onAssetCreated={handleAddAsset} 
              onAddRequest={handleAddRequest}
            />;

          case 'printing': 
            return <PrintManager assets={assets} />;

          case 'user-management': 
            return <UserManager 
              users={users} 
              employees={employees}
              onAddUser={async (u) => { 
                const newU = {...u, id: Date.now().toString()}; 
                setUsers(prev => [...prev, newU]); 
                await db.users.upsert(newU); 
              }} 
              onUpdateUser={async (u) => { 
                setUsers(prev => prev.map(old => old.id === u.id ? u : old)); 
                await db.users.upsert(u); 
              }} 
              onRemoveUser={async (id) => { 
                setUsers(prev => prev.filter(u => u.id !== id)); 
                await db.users.remove(id); 
              }} 
            />;

          default: 
            return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { UserPlus, Search, Trash2, Shield, User as UserIcon, X, Check, Edit2, Key, LayoutGrid, Star, Users, Briefcase } from 'lucide-react';
import { UserAccount, AppModule, Employee } from '../types';
import { ALL_MODULES } from '../constants';

interface UserManagerProps {
  users: UserAccount[];
  employees: Employee[];
  onAddUser: (user: Omit<UserAccount, 'id'>) => void;
  onUpdateUser: (user: UserAccount) => void;
  onRemoveUser: (id: string) => void;
}

const UserManager: React.FC<UserManagerProps> = ({ users, employees, onAddUser, onUpdateUser, onRemoveUser }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingUser, setEditingUser] = useState<UserAccount | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [formData, setFormData] = useState<Omit<UserAccount, 'id'>>({
    name: '',
    username: '',
    password: '',
    sector: '',
    modules: [],
    employeeId: ''
  });

  const handleOpenCreate = () => {
    setEditingUser(null);
    setFormData({ name: '', username: '', password: '', sector: '', modules: [], employeeId: '' });
    setShowForm(true);
  };

  const handleOpenEdit = (user: UserAccount) => {
    setEditingUser(user);
    setFormData({ 
      name: user.name, 
      username: user.username, 
      password: '', 
      sector: user.sector, 
      modules: user.modules,
      employeeId: user.employeeId || ''
    });
    setShowForm(true);
  };

  const handleEmployeeChange = (employeeId: string) => {
    const emp = employees.find(e => e.id === employeeId);
    if (emp) {
      setFormData(prev => ({
        ...prev,
        employeeId,
        name: emp.name,
        sector: emp.sector
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        employeeId: '',
        name: '',
        sector: ''
      }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.employeeId && !editingUser?.username.includes('admin')) {
      alert("É obrigatório vincular um colaborador para criar uma conta de usuário.");
      return;
    }

    if (editingUser) {
      const updatedUser: UserAccount = {
        ...editingUser,
        ...formData,
        password: formData.password || editingUser.password 
      };
      onUpdateUser(updatedUser);
    } else {
      onAddUser(formData);
    }
    setShowForm(false);
  };

  const toggleModule = (moduleId: AppModule) => {
    // Impede remover a gestão de usuários do admin principal
    if (editingUser?.username === 'admin' && moduleId === 'user-management') return;

    setFormData(prev => ({
      ...prev,
      modules: prev.modules.includes(moduleId)
        ? prev.modules.filter(m => m !== moduleId)
        : [...prev.modules, moduleId]
    }));
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.username.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center gap-4">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por nome ou usuário..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={handleOpenCreate}
          className="bg-slate-900 hover:bg-black text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 transition-all shadow-lg"
        >
          <UserPlus className="w-5 h-5" />
          <span>Novo Usuário</span>
        </button>
      </div>

      <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Usuário</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Setor Oficial</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Acesso</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredUsers.map(user => (
              <tr 
                key={user.id} 
                className="hover:bg-slate-50/50 transition-colors cursor-pointer group"
                onClick={() => handleOpenEdit(user)}
              >
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-blue-50 flex items-center justify-center text-blue-600 font-bold">
                      {user.name.charAt(0)}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="font-bold text-slate-800 leading-none group-hover:text-blue-600 transition-colors">{user.name}</p>
                        {user.username === 'admin' && (
                          <span className="bg-amber-100 text-amber-700 text-[8px] px-1.5 py-0.5 rounded-full font-black uppercase flex items-center gap-1">
                            <Star className="w-2 h-2 fill-current" /> Master
                          </span>
                        )}
                      </div>
                      <p className="text-xs text-slate-400 font-medium">@{user.username} {user.employeeId ? '• Vinculado ao RH' : '• Usuário Externo'}</p>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4">
                   <span className="text-sm text-slate-600 font-medium">{user.sector}</span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex flex-wrap gap-1">
                    {user.modules.length > 0 ? (
                      user.modules.slice(0, 3).map(m => (
                        <span key={m} className={`px-2 py-0.5 rounded text-[9px] font-bold uppercase ${
                          m === 'user-management' ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'
                        }`}>
                          {ALL_MODULES.find(mod => mod.id === m)?.label.split(' ')[0]}
                        </span>
                      ))
                    ) : (
                      <span className="text-[10px] text-slate-400 font-bold uppercase">Nenhum</span>
                    )}
                    {user.modules.length > 3 && (
                      <span className="px-2 py-0.5 bg-blue-50 text-blue-500 rounded text-[9px] font-bold uppercase">
                        +{user.modules.length - 3}
                      </span>
                    )}
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-1" onClick={e => e.stopPropagation()}>
                    <button 
                      onClick={() => handleOpenEdit(user)}
                      className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => onRemoveUser(user.id)}
                      disabled={user.username === 'admin'}
                      className={`p-2 transition-colors ${user.username === 'admin' ? 'text-slate-200 cursor-not-allowed' : 'text-slate-400 hover:text-rose-600'}`}
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center mb-8 shrink-0">
               <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
                    {editingUser ? <Edit2 className="w-6 h-6" /> : <UserPlus className="w-6 h-6" />}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-800 tracking-tight">
                      {editingUser ? 'Editar Perfil' : 'Novo Usuário do Sistema'}
                    </h3>
                    <p className="text-sm text-slate-500">Vincule um colaborador para relatórios auditáveis.</p>
                  </div>
               </div>
               <button onClick={() => setShowForm(false)} className="p-2 hover:bg-slate-100 rounded-full">
                 <X className="w-6 h-6 text-slate-400" />
               </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6 overflow-y-auto pr-2 custom-scrollbar">
              <div className="bg-blue-50 p-6 rounded-[2rem] border border-blue-100 space-y-4">
                <div className="flex items-center gap-2 text-blue-700">
                   <Users className="w-5 h-5" />
                   <label className="text-xs font-black uppercase tracking-widest">Vincular Colaborador (Obrigatório)</label>
                </div>
                <div className="relative">
                   <select 
                     className="w-full p-4 rounded-xl bg-white border border-blue-200 outline-none font-bold text-slate-800 appearance-none shadow-sm focus:ring-2 focus:ring-blue-500"
                     value={formData.employeeId}
                     onChange={(e) => handleEmployeeChange(e.target.value)}
                     required={!editingUser?.username.includes('admin')}
                   >
                     <option value="">Selecione o funcionário no RH...</option>
                     {employees.map(emp => (
                       <option key={emp.id} value={emp.id}>{emp.name} — {emp.role} ({emp.sector})</option>
                     ))}
                   </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 opacity-60 pointer-events-none">
                <div className="space-y-1.5">
                  <label className="text-xs font-black text-slate-700 uppercase tracking-widest block">Nome Completo (RH)</label>
                  <div className="relative">
                    <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-slate-50 outline-none font-bold"
                      value={formData.name}
                      readOnly
                    />
                  </div>
                </div>

                <div className="space-y-1.5">
                  <label className="text-xs font-black text-slate-700 uppercase tracking-widest block">Setor (RH)</label>
                  <div className="relative">
                    <Briefcase className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-slate-50 outline-none font-bold"
                      value={formData.sector}
                      readOnly
                    />
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1.5">
                  <label className="text-sm font-black text-slate-700 uppercase tracking-widest block">Login / Usuário</label>
                  <input 
                    className="w-full p-4 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm font-bold"
                    value={formData.username}
                    onChange={e => setFormData({...formData, username: e.target.value})}
                    placeholder="Ex: joao.silva"
                    required
                    disabled={editingUser?.username === 'admin'}
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-black text-slate-700 uppercase tracking-widest block">
                    {editingUser ? 'Alterar Senha (Opcional)' : 'Senha de Acesso'}
                  </label>
                  <div className="relative">
                    <Key className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      type="password"
                      className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm font-bold"
                      value={formData.password}
                      onChange={e => setFormData({...formData, password: e.target.value})}
                      placeholder={editingUser ? "•••••••• (Vazio = manter)" : "••••••••"}
                      required={!editingUser}
                    />
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="text-sm font-black text-slate-700 uppercase tracking-widest flex items-center gap-2">
                    <Shield className="w-4 h-4 text-blue-600" /> Permissões de Módulo
                  </label>
                  <span className="text-[10px] text-slate-400 font-bold">{formData.modules.length} módulos ativos</span>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 bg-white p-4 rounded-3xl border border-slate-200">
                  {ALL_MODULES.map(module => {
                    const isAdminMasterModule = editingUser?.username === 'admin' && module.id === 'user-management';

                    return (
                      <button
                        key={module.id}
                        type="button"
                        onClick={() => toggleModule(module.id)}
                        disabled={isAdminMasterModule}
                        className={`flex items-center justify-between p-3 rounded-xl border transition-all text-left ${
                          formData.modules.includes(module.id)
                            ? 'bg-blue-600 border-blue-600 text-white shadow-md shadow-blue-100'
                            : 'bg-white border-slate-100 text-slate-600 hover:border-blue-300'
                        } ${isAdminMasterModule ? 'opacity-80 cursor-not-allowed border-blue-200' : ''}`}
                      >
                        <div className="flex items-center gap-2">
                          <LayoutGrid className={`w-3.5 h-3.5 ${formData.modules.includes(module.id) ? 'text-white' : 'text-slate-300'}`} />
                          <div>
                            <span className="text-xs font-bold block leading-none">{module.label}</span>
                            {isAdminMasterModule && <span className="text-[8px] opacity-70">Obrigatório para Master</span>}
                          </div>
                        </div>
                        {formData.modules.includes(module.id) && <Check className="w-4 h-4" />}
                      </button>
                    );
                  })}
                </div>
              </div>

              <div className="flex justify-end gap-3 mt-4 pt-6 border-t border-slate-100 shrink-0">
                <button type="button" onClick={() => setShowForm(false)} className="px-8 py-4 font-bold text-slate-500 hover:bg-slate-50 rounded-2xl transition-all">Cancelar</button>
                <button type="submit" className="px-12 py-4 font-black bg-slate-900 text-white rounded-2xl shadow-xl hover:bg-black transition-all">
                  {editingUser ? 'Salvar Alterações' : 'Criar Conta Vinculada'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #e2e8f0;
          border-radius: 10px;
        }
      `}</style>
    </div>
  );
};

export default UserManager;

export type AssetType = 
  | 'Desktop' 
  | 'Notebook' 
  | 'Mouse' 
  | 'Cabo' 
  | 'Monitor' 
  | 'Teclado' 
  | 'Headset' 
  | 'Suporte Notebook';

export type AssetStatus = 'Disponível' | 'Em Uso' | 'Manutenção' | 'Baixado' | 'Pendente Documentos';

export interface HistoryEntry {
  id: string;
  date: string;
  type: 'Manutenção' | 'Atribuição' | 'Status' | 'Criação' | 'Observação';
  description: string;
  performedBy?: string;
  userContext?: string; // Nome do colaborador envolvido, se houver
}

export interface Department {
  id: string;
  name: string;
  costCenter?: string;
  createdAt: string;
}

export interface Asset {
  id: string;
  serialNumber?: string; // Novo: Número de série do fabricante
  departmentId: string; // Vínculo com o departamento
  type: AssetType;
  brand: string;
  model: string;
  ram?: string;
  storage?: string;
  processor?: string;
  screenSize?: string;
  caseModel?: string; 
  isWireless?: boolean; 
  monitorInputs?: string[]; 
  isAbnt?: boolean; 
  hasNumericKeypad?: boolean; 
  observations: string;
  photos: string[];
  status: AssetStatus;
  assignedTo?: string; // Employee ID
  qrCode: string;
  createdAt: string;
  history: HistoryEntry[]; 
}

export interface Employee {
  id: string;
  departmentId: string; // Vínculo com o departamento
  name: string;
  sector: string;
  role: string;
  cpf: string;
}

export type AppModule = 
  | 'dashboard' 
  | 'departments'
  | 'assets' 
  | 'employees' 
  | 'requests' 
  | 'purchase-orders' 
  | 'printing' 
  | 'user-management' 
  | 'inventory-check'
  | 'maintenance';

export interface UserAccount {
  id: string;
  name: string;
  username: string;
  password?: string;
  sector: string;
  modules: AppModule[];
  employeeId?: string; // Vínculo obrigatório com Colaborador
}

export interface Quotation {
  url: string;
  price?: number;
  deliveryPrediction: string;
}

export interface ItemFulfillment {
  type: AssetType;
  linkedAssetId?: string;
  isPurchaseOrder: boolean;
