                   <label className="text-[10px] font-black uppercase text-slate-400 ml-1 flex items-center gap-2">
                     <Camera className="w-3 h-3" /> Anexar Fotos do Equipamento
                   </label>
                   <div className="grid grid-cols-4 gap-3">
                      {newAsset.photos?.map((photo, idx) => (
                        <div key={idx} className="relative group aspect-video">
                          <img src={photo} className="w-full h-full object-cover rounded-xl border border-slate-200" />
                          <button 
                            type="button" 
                            onClick={() => removePhoto(idx)}
                            className="absolute -top-1 -right-1 bg-rose-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
                          >
                            <X className="w-3 h-3" />
                          </button>
                        </div>
                      ))}
                      <button 
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        className="aspect-video rounded-xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400 hover:border-blue-400 hover:text-blue-500 transition-all bg-slate-50"
                      >
                         <Plus className="w-5 h-5 mb-1" />
                         <span className="text-[8px] font-black uppercase">Foto</span>
                      </button>
                   </div>
                   <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    multiple 
                    accept="image/*"
                    onChange={handleFileChange}
                   />
                </div>

                <div className="space-y-1">
                   <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Observações e Estado Físico</label>
                   <textarea 
                    className="w-full p-5 rounded-3xl bg-slate-50 border-none outline-none font-medium h-32 resize-none text-slate-700" 
                    placeholder="Ex: Item novo, sem riscos. Bateria 100% saúde. Inclui carregador original."
                    value={newAsset.observations}
                    onChange={e => setNewAsset({...newAsset, observations: e.target.value})}
                   />
                </div>

                <div className="flex gap-4 pt-4 border-t border-slate-100">
                   <button type="button" onClick={() => setShowForm(false)} className="flex-1 py-4 font-black text-slate-400 uppercase tracking-widest text-xs">Descartar</button>
                   <button type="submit" className="flex-[2] py-4 bg-slate-900 text-white rounded-2xl font-black shadow-xl uppercase tracking-widest text-xs hover:bg-black transition-all">Salvar Ativo</button>
                </div>
             </form>
          </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default AssetManager;

import React, { useState } from 'react';
import { Users, Plus, Search, Trash2, Edit2, Building2, X } from 'lucide-react';
import { Employee, Department } from '../types';

interface EmployeeManagerProps {
  employees: Employee[];
  departments: Department[];
  onAdd: (employee: Omit<Employee, 'id'>) => void;
  onUpdate: (employee: Employee) => void;
  onRemove: (id: string) => void;
}

const EmployeeManager: React.FC<EmployeeManagerProps> = ({ employees, departments, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [formData, setFormData] = useState<Omit<Employee, 'id'>>({
    name: '', sector: '', role: '', cpf: '', departmentId: ''
  });

  const handleOpenCreate = () => {
    setEditingEmployee(null);
    setFormData({ name: '', sector: '', role: '', cpf: '', departmentId: '' });
    setShowForm(true);
  };

  const handleOpenEdit = (emp: Employee) => {
    setEditingEmployee(emp);
    setFormData({
      name: emp.name,
      sector: emp.sector,
      role: emp.role,
      cpf: emp.cpf,
      departmentId: emp.departmentId
    });
    setShowForm(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.departmentId) {
      alert("Selecione um departamento para o colaborador.");
      return;
    }

    // O setor agora é automaticamente o nome do departamento selecionado
    const selectedDept = departments.find(d => d.id === formData.departmentId);
    const finalData = {
      ...formData,
      sector: selectedDept?.name || 'Geral'
    };

    if (editingEmployee) {
      onUpdate({ ...finalData, id: editingEmployee.id });
    } else {
      onAdd(finalData);
    }

    setShowForm(false);
    setEditingEmployee(null);
  };

  const getDepartmentName = (id: string) => departments.find(d => d.id === id)?.name || 'N/A';

  const filteredEmployees = employees.filter(emp => 
    emp.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.cpf.includes(searchTerm) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center gap-4">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por nome, cargo ou CPF..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={handleOpenCreate}
          className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 transition-all shadow-lg shadow-blue-200"
        >
          <Plus className="w-5 h-5" />
          <span>Cadastrar Colaborador</span>
        </button>
      </div>

      <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Nome</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Departamento Oficial</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Função</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">CPF</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredEmployees.map(emp => (
              <tr key={emp.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-6 py-4 font-bold text-slate-800">{emp.name}</td>
                <td className="px-6 py-4">
                  <div className="flex flex-col">
                    <span className="text-slate-700 font-bold">{getDepartmentName(emp.departmentId)}</span>
                    <span className="text-[10px] text-slate-400 font-black uppercase tracking-tighter">Vinculado ao RH</span>
                  </div>
                </td>
                <td className="px-6 py-4 text-slate-600 font-medium">{emp.role}</td>
                <td className="px-6 py-4 text-slate-500 text-sm font-mono">{emp.cpf}</td>
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-2">
                    <button 
                      onClick={() => handleOpenEdit(emp)}
                      className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                      title="Editar Colaborador"
                    >
                      <Edit2 className="w-5 h-5" />
                    </button>
                    <button 
                      onClick={() => { if(confirm(`Remover colaborador ${emp.name}?`)) onRemove(emp.id) }}
                      className="p-2 text-slate-400 hover:text-rose-600 transition-colors"
                      title="Remover"
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
            {filteredEmployees.length === 0 && (
              <tr>
                <td colSpan={5} className="py-12 text-center text-slate-400 font-medium italic">Nenhum colaborador encontrado.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {showForm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800 flex items-center gap-2 tracking-tight">
                <Users className="w-7 h-7 text-blue-600" />
                {editingEmployee ? 'Editar Colaborador' : 'Novo Colaborador'}
              </h3>
              <button onClick={() => setShowForm(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400 hover:text-slate-900">
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label>
                <input 
                  className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-blue-500 shadow-sm font-bold"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  placeholder="Nome do colaborador"
                  required
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">CPF</label>
                <input 
                  className="w-full p-4 rounded-2xl border border-slate-200 bg-white outline-none focus:ring-2 focus:ring-blue-500 shadow-sm font-bold"
                  placeholder="000.000.000-00"
                  value={formData.cpf}
                  onChange={e => setFormData({...formData, cpf: e.target.value})}
                  required
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Departamento de Alocação</label>
                <div className="relative">
                   <Building2 className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                   <select 
                    className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-white outline-none focus:ring-2 focus:ring-blue-500 shadow-sm font-bold appearance-none"
                    value={formData.departmentId}
                    onChange={e => setFormData({...formData, departmentId: e.target.value})}
                    required
                   >
                     <option value="">Selecione um Departamento...</option>
                     {departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                   </select>
                </div>
                <p className="text-[10px] text-slate-400 mt-1 italic ml-1">O setor do colaborador será sincronizado com o nome do departamento.</p>
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Função / Cargo</label>
                <input 
                  className="w-full p-4 rounded-2xl border border-slate-200 bg-white outline-none focus:ring-2 focus:ring-blue-500 shadow-sm font-bold"
                  value={formData.role}
                  onChange={e => setFormData({...formData, role: e.target.value})}
                  placeholder="Ex: Desenvolvedor Senior"
                  required
                />
              </div>

              <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-slate-100">
                <button type="button" onClick={() => setShowForm(false)} className="px-6 py-4 font-bold text-slate-500 hover:bg-slate-50 rounded-2xl transition-all">Cancelar</button>
                <button type="submit" className="px-12 py-4 font-black bg-blue-600 text-white rounded-2xl shadow-xl shadow-blue-100 uppercase text-xs tracking-widest transition-all active:scale-95">
                  {editingEmployee ? 'Salvar Alterações' : 'Salvar Colaborador'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default EmployeeManager;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, Department, AuditSession, HistoryEntry } from './types';
import { db } from './services/supabase';
import { Loader2, AlertCircle, Package } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [departments, setDepartments] = useState<Department[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const [depts, assts, emps, reqs, audits, userList] = await Promise.all([
        db.departments.list().catch(() => []),
        db.assets.list().catch(() => []),
        db.employees.list().catch(() => []),
        db.requests.list().catch(() => []),
        db.auditSessions.list().catch(() => []),
        db.users.list().catch(() => [])
      ]);

      setDepartments(depts);
      setAssets(assts);
      setEmployees(emps);
      setRequests(reqs);
      setAuditSessions(audits);

      if (userList.length === 0) {
        setUsers(MOCK_USERS);
      } else {
        setUsers(userList);
      }
    } catch (err) {
      setError("Erro ao conectar com o banco de dados Supabase.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleLogin = async (user: UserAccount) => {
    const isInDatabase = users.some(u => u.username === user.username && u.id === user.id);

    if (!isInDatabase) {
      try {
        await db.users.upsert(user);
        const userList = await db.users.list();
        setUsers(userList);
      } catch (e) {
        console.warn("Aviso: Não foi possível salvar o perfil do usuário no banco. Verifique as políticas de RLS.");
      }
    }

    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 9000) + 1000}`;
    const initialHistory: HistoryEntry[] = assetData.history || [
      {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Criação',
        description: 'Ativo registrado no inventário.',
        performedBy: currentUser?.name || 'Sistema'
      }
    ];

    const newAsset: Asset = { 
      ...assetData, 
      id, 
      qrCode: `QR-${id}`,
      createdAt: new Date().toISOString(),
      history: initialHistory,
      observations: assetData.observations || ''
    };

    setAssets(prev => [newAsset, ...prev]);
    await db.assets.upsert(newAsset);
  };

  const handleUpdateAsset = async (updated: Asset) => {
    setAssets(prev => prev.map(a => a.id === updated.id ? updated : a));
    await db.assets.upsert(updated);
  };

  const handleRemoveAsset = async (id: string) => {
    setAssets(prev => prev.filter(a => a.id !== id));
    await db.assets.remove(id);
  };

  const handleAddRequest = async (reqData: any) => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const newReq: EquipmentRequest = { 
      ...reqData, 
      id, 
      status: 'Pendente',
      createdAt: new Date().toISOString()
    };
    setRequests(prev => [newReq, ...prev]);
    await db.requests.upsert(newReq);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    setRequests(prev => prev.map(r => r.id === req.id ? req : r));
    await db.requests.upsert(req);
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    setAuditSessions(prev => prev.map(old => old.id === session.id ? session : old));
    await db.auditSessions.upsert(session);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
            <Package className="text-white w-10 h-10" />
          </div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">AssetTrack Pro</h1>
        </div>
        <div className="flex items-center gap-3">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Sincronizando com Supabase...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <AlertCircle className="w-16 h-16 text-rose-500 mb-4" />
        <h3 className="text-xl font-black text-slate-800 mb-2">Falha Crítica</h3>
        <p className="text-slate-500 max-w-sm mb-6">{error}</p>
        <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase text-[10px] tracking-widest">Tentar Reconectar</button>
      </div>
    );
  }

  if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} requests={requests}>
      {(() => {
        switch (activeTab) {
          case 'dashboard': 
            return <Dashboard assets={assets} requests={requests} employees={employees} />;

          case 'departments': 
            return <CompanyManager 
              companies={departments} 
              assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                setDepartments(prev => [...prev, newD]); 
                await db.departments.upsert(newD); 
              }} 
              onUpdateCompany={async (updated) => { 
                setDepartments(prev => prev.map(d => d.id === updated.id ? updated : d)); 
                await db.departments.upsert(updated); 
              }} 
              onRemoveCompany={async (id) => { 
                setDepartments(prev => prev.filter(d => d.id !== id)); 
                await db.departments.remove(id); 
              }} 
            />;

          case 'assets': 
            return <AssetManager 
              assets={assets} 
              employees={employees} 
              companies={departments} 
              onAdd={handleAddAsset} 
              onUpdate={handleUpdateAsset} 
              onRemove={handleRemoveAsset} 
            />;

          case 'employees': 
            return <EmployeeManager 
              employees={employees} 
              departments={departments} 
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`}; 
                setEmployees(prev => [...prev, newE]); 
                await db.employees.upsert(newE); 
              }} 
              onUpdate={async (updated) => {
                setEmployees(prev => prev.map(e => e.id === updated.id ? updated : e));
                await db.employees.upsert(updated);
              }}
              onRemove={async (id) => {
                setEmployees(prev => prev.filter(e => e.id !== id));
                await db.employees.remove(id);
              }}
            />;

          case 'requests': 
            return <RequestsManager 
              requests={requests} 
              employees={employees} 
              assets={assets} 
              currentUser={currentUser}
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { 
                const req = requests.find(r => r.id === id); 
                if(!req) return;

                // Lógica de finalização de entrega com efeito cascata nos ativos
                if (status === 'Entregue') {
                  const employee = employees.find(e => e.id === req.employeeId);
                  if (employee) {
                    const fulfillments = req.itemFulfillments || [];
                    for (const f of fulfillments) {
                      if (f.linkedAssetId) {
                        const asset = assets.find(a => a.id === f.linkedAssetId);
                        if (asset) {
                          const historyEntry: HistoryEntry = {
                            id: Math.random().toString(),
                            date: new Date().toISOString(),
                            type: 'Atribuição',
                            description: `Entrega técnica concluída via protocolo ${req.id}. Ativo alocado ao colaborador ${employee.name} e transferido para o setor ${employee.sector}.`,
                            performedBy: currentUser?.name || 'Sistema',
                            userContext: employee.name
                          };

                          // Atualiza o ativo para o novo proprietário e departamento
                          await handleUpdateAsset({
                            ...asset,
                            status: 'Em Uso',
                            assignedTo: employee.id,
                            departmentId: employee.departmentId,
                            history: [...(asset.history || []), historyEntry]
                          });
                        }
                      }
                    }
                  }
                }

                // Finalmente atualiza o status da requisição
                await handleUpdateRequest({...req, status}); 
              }} 
            />;

          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={employees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                setAuditSessions(prev => [s, ...prev]); 
                await db.auditSessions.upsert(s); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, assetIds) => 
                handleAddRequest({ 
                  requesterId: currentUser?.id, 
                  employeeId: employees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => assetIds.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência de auditoria no setor ${sector}` 
                })
              } 
            />;

          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} 
              employees={employees} 
              companies={departments} 
              onUpdateAsset={handleUpdateAsset} 
            />;

          case 'purchase-orders': 
            return <PurchaseOrderManager 
              requests={requests} 
              employees={employees} 
              onUpdateRequest={handleUpdateRequest} 
              onAssetCreated={handleAddAsset} 
              onAddRequest={handleAddRequest}
            />;

          case 'printing': 
            return <PrintManager assets={assets} />;

          case 'user-management': 
            return <UserManager 
              users={users} 
              employees={employees}
              onAddUser={async (u) => { 
                const newU = {...u, id: Date.now().toString()}; 
                setUsers(prev => [...prev, newU]); 
                await db.users.upsert(newU); 
              }} 
              onUpdateUser={async (u) => { 
                setUsers(prev => prev.map(old => old.id === u.id ? u : old)); 
                await db.users.upsert(u); 
              }} 
              onRemoveUser={async (id) => { 
                setUsers(prev => prev.filter(u => u.id !== id)); 
                await db.users.remove(id); 
              }} 
            />;

          default: 
            return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

