  Trash2,
  X,
  Cpu,
  Layers,
  Monitor,
  Wifi,
  Usb,
  Zap,
  Type,
  History,
  Clock,
  User,
  Wrench,
  CheckCircle2,
  Tag,
  ArrowRight,
