                      {asset.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button onClick={(e) => { e.stopPropagation(); openEditModal(asset); }} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
