    ram: '',
    storage: '',
    processor: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: [],
    isAbnt: true,
    hasNumericKeypad: true
  });

  useEffect(() => {
    if (companies.length > 0 && !formData.departmentId && !editingAsset) {
      setFormData(prev => ({ ...prev, departmentId: companies[0].id }));
      setBulkEntries([{ 
        tempId: '1', departmentId: companies[0].id, type: 'Notebook', brand: '', model: '', serialNumber: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' 
      }]);
    }
  }, [companies, showForm, showBulkModal, editingAsset]);

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';
  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'Em Estoque';

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    (Array.from(files) as File[]).forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({
          ...prev,
          photos: [...(prev.photos || []), reader.result as string]
        }));
      };
      reader.readAsDataURL(file);
    });
  };

  const removePhoto = (index: number) => {
    setFormData(prev => ({
      ...prev,
      photos: prev.photos?.filter((_, i) => i !== index)
    }));
  };

  const openEditModal = (asset: Asset) => {
    setEditingAsset(asset);
    setFormData({ ...asset });
    setShowForm(true);
    setDetailAsset(null);
  };

  const handleDepartmentChange = async (newDeptId: string) => {
    if (!detailAsset || newDeptId === detailAsset.departmentId) return;

    setIsUpdatingDept(true);
    try {
      const oldDeptName = getDepartmentName(detailAsset.departmentId);
      const newDeptName = getDepartmentName(newDeptId);

      const transferLog: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Status',
        description: `Transferência de departamento: de "${oldDeptName}" para "${newDeptName}".`,
        performedBy: 'Gestor de Ativos'
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        departmentId: newDeptId,
        history: [...(detailAsset.history || []), transferLog]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err: any) {
      alert(`Erro ao transferir departamento: ${err.message || 'Erro desconhecido'}`);
    } finally {
      setIsUpdatingDept(false);
    }
  };

  const handleEmployeeChange = async (newEmployeeId: string) => {
    if (!detailAsset) return;
    if (newEmployeeId === detailAsset.assignedTo) return;

    setIsUpdatingEmployee(true);
    try {
      const oldEmpName = getEmployeeName(detailAsset.assignedTo);
      const newEmp = employees.find(e => e.id === newEmployeeId);
      const newEmpName = newEmp?.name || 'Estoque';

      const historyEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Atribuição',
        description: `Responsável alterado manualmente: de "${oldEmpName}" para "${newEmpName}".`,
        performedBy: 'Gestor de Ativos',
        userContext: newEmpName
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        assignedTo: newEmployeeId || undefined,
        departmentId: newEmp?.departmentId || detailAsset.departmentId,
        status: newEmployeeId ? 'Em Uso' : 'Disponível',
        history: [...(detailAsset.history || []), historyEntry]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err: any) {
      alert(`Erro ao alterar colaborador: ${err.message || 'Erro desconhecido'}`);
    } finally {
      setIsUpdatingEmployee(false);
    }
  };

  const handleAddManualLog = async () => {
    if (!detailAsset || !manualLog.trim()) return;

    try {
      const newEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Observação',
        description: manualLog,
        performedBy: 'Gestor de TI'
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        history: [...(detailAsset.history || []), newEntry]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
      setManualLog('');
    } catch (err: any) {
      alert("Falha ao salvar log manual.");
    }
  };

  const handleStatusChangeManual = async (newStatus: AssetStatus) => {
    if (!detailAsset) return;

    try {
      const newEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Status',
        description: `Status alterado manualmente de ${detailAsset.status} para ${newStatus}.`,
        performedBy: 'Gestor de TI'
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        status: newStatus,
        assignedTo: newStatus === 'Disponível' ? undefined : detailAsset.assignedTo,
        history: [...(detailAsset.history || []), newEntry]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err: any) {
      alert("Falha ao atualizar status.");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.departmentId) {
      alert("Selecione ou crie um departamento primeiro.");
      return;
    }

    setIsSaving(true);
    try {
      if (editingAsset) {
        const historyEntry: HistoryEntry = {
          id: Math.random().toString(),
          date: new Date().toISOString(),
          type: 'Observação',
          description: 'Informações do ativo atualizadas manualmente via formulário de edição.',
          performedBy: 'Gestor de Ativos'
        };
        const updated: Asset = {
          ...editingAsset,
          ...(formData as Asset),
          history: [...(editingAsset.history || []), historyEntry]
        };
        await onUpdate(updated);
        setEditingAsset(null);
      } else {
        await onAdd(formData as any);
      }
      setShowForm(false);
      resetFormData();
    } catch (err: any) {
      console.error("Erro no handleSubmit:", err);
      alert(`Erro ao salvar ativo: ${err.message || 'Certifique-se que o ID não está duplicado.'}`);
    } finally {
      setIsSaving(false);
    }
  };

  const resetFormData = () => {
    setFormData({ 
      id: '',
      type: 'Notebook', 
      status: 'Disponível', 
      serialNumber: '', 
      observations: '', 
      photos: [], 
      departmentId: companies[0]?.id || '', 
      ram: '', 
      storage: '', 
      processor: '',
      screenSize: '', 
      caseModel: '', 
      isWireless: false, 
      monitorInputs: [], 
      isAbnt: true, 
      hasNumericKeypad: true 
    });
    setEditingAsset(null);
  };

  const handleBulkAddRow = () => {
    setBulkEntries([...bulkEntries, { 
      tempId: Math.random().toString(), 
      departmentId: companies[0]?.id || '', 
      type: 'Notebook', 
      brand: '', 
      model: '', 
      serialNumber: '',
      ram: '',
      storage: '',
      screenSize: '',
      caseModel: '',
      isWireless: false,
      monitorInputs: [],
      isAbnt: true,
      hasNumericKeypad: true,
      id: '', 
      assignedTo: '', 
      observations: '' 
    }]);
  };

  const handleBulkSave = async () => {
    if (companies.length === 0) {
      alert("Erro: Você precisa cadastrar pelo menos um Departamento antes.");
      return;
    }

    setIsSavingBulk(true);
    try {
      for (const entry of bulkEntries) {
        if (!entry.id) continue;
        await onAdd({
          id: entry.id,
          serialNumber: entry.serialNumber,
          departmentId: entry.departmentId || companies[0].id,
          type: entry.type,
          brand: entry.brand,
          model: entry.model,
          ram: entry.ram,
          storage: entry.storage,
          screenSize: entry.screenSize,
          caseModel: entry.caseModel,
          isWireless: entry.isWireless,
          monitorInputs: entry.monitorInputs,
          isAbnt: entry.isAbnt,
          hasNumericKeypad: entry.hasNumericKeypad,
          observations: entry.observations,
          photos: [],
          status: entry.assignedTo ? 'Em Uso' : 'Disponível',
          assignedTo: entry.assignedTo || undefined,
        });
      }
      setShowBulkModal(false);
      setBulkEntries([{ tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', serialNumber: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' }]);
    } catch (err: any) {
      alert(`Erro no salvamento em lote: ${err.message || 'Verifique se há IDs duplicados'}`);
    } finally {
      setIsSavingBulk(false);
    }
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.serialNumber?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || a.type === filterType;
    return matchesSearch && matchesType;
  });

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 print:hidden">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por modelo, serial, marca ou ID..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-300 bg-white focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm font-semibold placeholder:text-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
          <button onClick={() => setShowBulkModal(true)} className="flex items-center gap-2 px-4 py-3 text-xs font-black text-slate-800 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all uppercase tracking-widest">
            <FileSpreadsheet className="w-4 h-4 text-emerald-600" />
            Lançar Levantamento
          </button>
          <button onClick={() => { resetFormData(); setShowForm(true); }} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black transition-all shadow-lg uppercase tracking-widest text-xs">
            <Plus className="w-5 h-5" />
            <span>Novo Ativo</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden print:hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Ativo / Serial</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Tipo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Marca/Modelo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredAssets.map((asset) => (
                <tr 
                  key={asset.id} 
                  onClick={() => setDetailAsset(asset)}
                  className="hover:bg-blue-50/50 transition-colors cursor-pointer group"
                >
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                      <span className="font-black text-slate-900 group-hover:text-blue-700">{asset.id}</span>
                      <span className="text-[10px] text-slate-400 font-mono flex items-center gap-1">
                        <ScanBarcode className="w-3 h-3" /> {asset.serialNumber || 'SEM SERIAL'}
                      </span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="text-xs font-black text-slate-800">{asset.type}</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="font-bold text-slate-900">{asset.brand}</span>
                    <span className="text-sm text-slate-700 ml-2 font-medium">{asset.model}</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${
                      asset.status === 'Disponível' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' :
                      asset.status === 'Em Uso' ? 'bg-blue-50 text-blue-700 border-blue-200' :
                      asset.status === 'Manutenção' ? 'bg-amber-50 text-amber-700 border-amber-200' : 'bg-slate-50 text-slate-700 border-slate-200'
                    }`}>
                      {asset.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button onClick={(e) => { e.stopPropagation(); openEditModal(asset); }} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
                        <Edit2 className="w-4 h-4" />
                      </button>
                      <button onClick={async (e) => {e.stopPropagation(); if(confirm("Remover este ativo?")) await onRemove(asset.id)}} className="p-2 text-slate-400 hover:text-rose-600 transition-colors">
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredAssets.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-20 text-center">
                    <div className="flex flex-col items-center justify-center space-y-3 opacity-30">
                       <Package className="w-12 h-12" />
                       <p className="font-black uppercase tracking-widest text-xs">Nenhum ativo registrado.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {detailAsset && (
        <div className="fixed inset-0 z-[150] flex items-center justify-end p-0 md:p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-2xl h-full md:h-auto md:max-h-[90vh] md:rounded-[3rem] shadow-2xl flex flex-col animate-in slide-in-from-right duration-300 overflow-hidden">
              <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl">
                       <Tag className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-2xl font-black text-slate-900 tracking-tight">{detailAsset.id}</h3>
                       <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Serial: {detailAsset.serialNumber || 'N/A'}</p>
                    </div>
                 </div>
                 <div className="flex items-center gap-2">
                    <button onClick={() => openEditModal(detailAsset)} className="flex items-center gap-2 px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">
                       <Edit2 className="w-4 h-4" /> Editar Informações
                    </button>
                    <button onClick={() => {setDetailAsset(null); setManualLog('');}} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                       <X className="w-6 h-6 text-slate-400" />
                    </button>
                 </div>
              </div>

              <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                 {detailAsset.photos && detailAsset.photos.length > 0 && (
                   <div className="space-y-4">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Galeria de Fotos</p>
                      <div className="flex gap-4 overflow-x-auto pb-4 custom-scrollbar">
                         {detailAsset.photos.map((photo, idx) => (
                           <img 
                            key={idx} 
                            src={photo} 
                            alt={`Ativo ${idx}`} 
                            className="w-48 h-32 object-cover rounded-2xl border border-slate-200 shadow-sm flex-shrink-0" 
                           />
                         ))}
                      </div>
                   </div>
                 )}

                 <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-200">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 text-center">Gestão de Status</p>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                       {(['Disponível', 'Em Uso', 'Manutenção', 'Baixado'] as AssetStatus[]).map(s => (
                          <button 
                            key={s}
                            onClick={() => handleStatusChangeManual(s)}
                            className={`py-2 text-[9px] font-black uppercase rounded-xl border transition-all ${
                               detailAsset.status === s ? 'bg-blue-600 text-white border-blue-700 shadow-md' : 'bg-white text-slate-500 border-slate-200 hover:border-blue-300'
                            }`}
                          >
                             {s}
                          </button>
                       ))}
                    </div>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 relative group">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Departamento / Setor</p>
                       <div className="flex items-center gap-3">
                          <Building2 className={`w-5 h-5 ${isUpdatingDept ? 'text-blue-400 animate-spin' : 'text-blue-600'}`} />
                          <div className="relative flex-1">
                             <select 
                               className="w-full bg-transparent font-bold text-slate-800 outline-none appearance-none cursor-pointer hover:text-blue-600 transition-colors pr-6 disabled:opacity-50"
                               value={detailAsset.departmentId}
                               onChange={(e) => handleDepartmentChange(e.target.value)}
                               disabled={isUpdatingDept || detailAsset.status === 'Em Uso'}
                             >
                                {companies.map(c => (
                                   <option key={c.id} value={c.id}>{c.name}</option>
                                ))}
                             </select>
                             {detailAsset.status !== 'Em Uso' && <ArrowLeftRight className="w-3.5 h-3.5 absolute right-0 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none group-hover:text-blue-400" />}
                          </div>
                       </div>
                    </div>

                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 relative group">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Responsável Atual</p>
                       <div className="flex items-center gap-3">
                          <User className={`w-5 h-5 ${isUpdatingEmployee ? 'text-blue-400 animate-spin' : 'text-blue-600'}`} />
                          <div className="relative flex-1">
                            {detailAsset.status === 'Em Uso' || detailAsset.status === 'Disponível' ? (
                               <>
                                <select 
                                  className="w-full bg-transparent font-bold text-slate-800 outline-none appearance-none cursor-pointer hover:text-blue-600 transition-colors pr-6"
                                  value={detailAsset.assignedTo || ''}
                                  onChange={(e) => handleEmployeeChange(e.target.value)}
                                  disabled={isUpdatingEmployee}
                                >
                                   <option value="">Estoque (Disponível)</option>
                                   {employees.map(emp => (
                                      <option key={emp.id} value={emp.id}>{emp.name}</option>
                                   ))}
                                </select>
                                <ArrowLeftRight className="w-3.5 h-3.5 absolute right-0 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none group-hover:text-blue-400" />
                               </>
                            ) : (
                               <p className="font-bold text-slate-800">{getEmployeeName(detailAsset.assignedTo)}</p>
                            )}
                          </div>
                       </div>
                    </div>
                 </div>

                 {/* Especificações Técnicas */}
                 <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                       <p className="text-[9px] font-black text-slate-400 uppercase mb-1">CPU</p>
                       <div className="flex items-center gap-2">
                          <Microchip className="w-3.5 h-3.5 text-blue-500" />
                          <span className="text-xs font-bold text-slate-800">{detailAsset.processor || 'N/A'}</span>
                       </div>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                       <p className="text-[9px] font-black text-slate-400 uppercase mb-1">RAM</p>
                       <div className="flex items-center gap-2">
                          <Cpu className="w-3.5 h-3.5 text-blue-500" />
                          <span className="text-xs font-bold text-slate-800">{detailAsset.ram || 'N/A'}</span>
                       </div>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                       <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Disco</p>
                       <div className="flex items-center gap-2">
                          <HardDrive className="w-3.5 h-3.5 text-blue-500" />
                          <span className="text-xs font-bold text-slate-800">{detailAsset.storage || 'N/A'}</span>
                       </div>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                       <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Tela</p>
                       <div className="flex items-center gap-2">
                          <Monitor className="w-3.5 h-3.5 text-blue-500" />
                          <span className="text-xs font-bold text-slate-800">{detailAsset.screenSize || 'N/A'}</span>
                       </div>
                    </div>
                 </div>

                 <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Observações do Ativo</p>
                    <p className="text-sm text-slate-700 font-medium whitespace-pre-wrap leading-relaxed">
                      {detailAsset.observations || 'Nenhuma observação técnica registrada.'}
                    </p>
                 </div>

                 <div className="space-y-6">
                    <div className="flex items-center justify-between">
                       <div className="flex items-center gap-2">
                          <History className="w-5 h-5 text-blue-600" />
                          <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Linha do Tempo</h4>
                       </div>
                    </div>

                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 space-y-4">
                       <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Adicionar Log Manual</p>
                       <div className="flex gap-2">
                          <input 
                            type="text"
                            placeholder="Descreva um evento..."
                            className="flex-1 p-3 rounded-xl border border-slate-200 text-sm font-medium outline-none focus:ring-2 focus:ring-blue-600"
                            value={manualLog}
                            onChange={(e) => setManualLog(e.target.value)}
                          />
                          <button onClick={handleAddManualLog} className="bg-slate-900 text-white p-3 rounded-xl hover:bg-black transition-colors shadow-lg">
                            <MessageSquarePlus className="w-5 h-5" />
                          </button>
                       </div>
                    </div>

                    <div className="relative pl-8 space-y-8 before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[2px] before:bg-slate-100">
                       {detailAsset.history?.length > 0 ? (
                         [...detailAsset.history].reverse().map((entry) => (
                           <div key={entry.id} className="relative group">
                              <div className={`absolute -left-[30px] top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm flex items-center justify-center ${
                                entry.type === 'Manutenção' ? 'bg-amber-500' :
                                entry.type === 'Atribuição' ? 'bg-blue-600' :
                                entry.type === 'Criação' ? 'bg-emerald-500' : 'bg-slate-400'
                              }`}>
                                {entry.type === 'Manutenção' && <Wrench className="w-3 h-3 text-white" />}
                                {entry.type === 'Atribuição' && <User className="w-3 h-3 text-white" />}
                                {entry.type === 'Criação' && <CheckCircle2 className="w-3 h-3 text-white" />}
