export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

export const db = {
  assets: {
    list: async () => {
      const { data, error } = await supabase.from('assets').select('*').order('createdAt', { ascending: false });
      if (error) { console.error("Erro ao listar assets:", error.message); throw error; }
      return data as Asset[];
    },
    upsert: async (asset: Asset) => {
      // FIX: Remove fields that don't exist in the physical Supabase schema to prevent PGRST204 errors.
      // We extract these fields to avoid the "column not found" error.
      const { 
        serialNumber, 
        ram, 
        storage, 
        processor, 
        screenSize, 
        caseModel, 
        isWireless, 
        monitorInputs, 
        isAbnt, 
        hasNumericKeypad, 
        ...dbAsset 
      } = asset;

      // As we can't change the DB schema, we append the technical data to 'observations' 
      // so the information is preserved as text and the save operation succeeds.
      let technicalSummary = '';
      if (serialNumber) technicalSummary += `\nS/N: ${serialNumber}`;
      if (processor) technicalSummary += `\nCPU: ${processor}`;
      if (ram) technicalSummary += `\nRAM: ${ram}`;
      if (storage) technicalSummary += `\nDisco: ${storage}`;
      if (screenSize) technicalSummary += `\nTela: ${screenSize}`;

      if (technicalSummary) {
        // Only append if it's not already there to avoid duplicates on multiple edits
        const marker = '\n[DADOS TÉCNICOS ADICIONAIS]';
        if (!dbAsset.observations.includes(marker)) {
          dbAsset.observations = (dbAsset.observations || '') + marker + technicalSummary;
        }
      }

      const { error } = await supabase.from('assets').upsert(dbAsset);
      if (error) { 
        console.error("Erro detalhado ao upsert asset:", error.message); 
        throw error; 
      }
    },
    remove: async (id: string) => {
      const { error } = await supabase.from('assets').delete().eq('id', id);
