};

export default RequestsManager;

import React, { useState } from 'react';
import { 
  FileText, 
  Plus, 
  X, 
  Clock, 
  ChevronRight, 
  CheckCircle, 
  ShoppingCart, 
  Link as LinkIcon, 
  Search, 
  AlertCircle,
  User,
  Calendar,
  Package,
  Check,
  Ban,
  Truck,
  MessageSquare,
  CheckSquare,
  Wrench,
  UserPlus,
  Loader2,
  Printer,
  ShieldCheck,
  FileDown,
  Cpu,
  HardDrive,
  ScanBarcode,
  Download
} from 'lucide-react';
import { EquipmentRequest, Employee, Asset, AssetType, ItemFulfillment, UserAccount } from '../types';
import { ASSET_TYPES } from '../constants';

interface RequestsManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  assets: Asset[];
  currentUser: UserAccount;
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  onUpdateStatus: (id: string, status: EquipmentRequest['status']) => Promise<void>;
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
}

const RequestsManager: React.FC<RequestsManagerProps> = ({ requests, employees, assets, currentUser, onAddRequest, onUpdateStatus, onUpdateRequest }) => {
  const [showModal, setShowModal] = useState(false);
  const [showTermModal, setShowTermModal] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<EquipmentRequest | null>(null);
  const [itemToLink, setItemToLink] = useState<{ index: number; type: AssetType } | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newReq, setNewReq] = useState<Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>>({
    requesterId: currentUser.id, 
    employeeId: '',
    items: [],
    observation: ''
  });

  const getEmployee = (id: string) => employees.find(e => e.id === id);
  const getEmployeeName = (id: string) => getEmployee(id)?.name || 'Desconhecido';
  const getEmployeeSector = (id: string) => getEmployee(id)?.sector || 'Setor não informado';

  const getLinkedAssetInfo = (assetId?: string) => {
    if (!assetId) return null;
    return assets.find(a => a.id === assetId);
  };

  const toggleItem = (type: AssetType) => {
    setNewReq(prev => ({
      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newReq.items.length === 0) {
      alert("Selecione pelo menos um item.");
      return;
    }
    if (!newReq.employeeId) {
      alert("Selecione o colaborador destinatário.");
      return;
    }

    setIsSubmitting(true);
    try {
      await onAddRequest({
        ...newReq,
        itemFulfillments: newReq.items.map(type => ({
          type,
          isPurchaseOrder: false
        }))
      });
      setShowModal(false);
      setNewReq({ requesterId: currentUser.id, employeeId: '', items: [], observation: '' });
    } catch (err) {
      alert("Erro ao criar requisição.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleLinkAsset = async (index: number, assetId: string) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: assetId,
      isPurchaseOrder: false
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleMarkForPurchase = async (index: number) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: undefined,
      isPurchaseOrder: true,
      purchaseStatus: 'Pendente'
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
  };

  const handleStatusChange = async (status: EquipmentRequest['status']) => {
    if (selectedRequest) {
      await onUpdateStatus(selectedRequest.id, status);
      setSelectedRequest(prev => prev ? { ...prev, status } : null);
    }
  };

  const availableAssetsByType = (type: AssetType) => {
    return assets.filter(a => a.type === type && a.status === 'Disponível');
  };

  const handleDownloadTerm = () => {
    if (!selectedRequest) return;

    const employeeName = getEmployeeName(selectedRequest.employeeId);
    const employeeSector = getEmployeeSector(selectedRequest.employeeId);
    const employeeCpf = getEmployee(selectedRequest.employeeId)?.cpf || 'N/A';

    // Preparar lista de equipamentos para o HTML
    const assetsRows = selectedRequest.itemFulfillments?.map((f) => {
      const assetInfo = getLinkedAssetInfo(f.linkedAssetId);
      let specs = "";
      if (assetInfo) {
        if (assetInfo.processor) specs += `CPU: ${assetInfo.processor}; `;
        if (assetInfo.ram) specs += `RAM: ${assetInfo.ram}; `;
        if (assetInfo.storage) specs += `Disco: ${assetInfo.storage}; `;
        if (!specs && assetInfo.observations?.includes('[DADOS TÉCNICOS ADICIONAIS]')) {
          specs = assetInfo.observations.split('[DADOS TÉCNICOS ADICIONAIS]')[1].replace(/\n/g, ' ').trim();
        }
      }
      return `
        <tr>
          <td style="padding: 10px; border: 1px solid #ddd;">
            <strong>${f.type}</strong><br>
            <small style="color: #2563eb; font-family: monospace;">${f.linkedAssetId || 'N/A'}</small>
          </td>
          <td style="padding: 10px; border: 1px solid #ddd;">${assetInfo ? `${assetInfo.brand} ${assetInfo.model}` : 'N/A'}</td>
          <td style="padding: 10px; border: 1px solid #ddd; font-family: monospace; font-size: 11px;">${assetInfo?.serialNumber || 'SEM SÉRIE'}</td>
          <td style="padding: 10px; border: 1px solid #ddd; font-size: 11px;">${specs || 'Configuração padrão'}</td>
        </tr>
      `;
    }).join('') || '';

    const htmlContent = `
      <!DOCTYPE html>
      <html lang="pt-BR">
      <head>
        <meta charset="UTF-8">
        <title>Termo de Responsabilidade - ${selectedRequest.id}</title>
        <style>
          body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; line-height: 1.6; color: #333; margin: 0; padding: 40px; background: #fff; }
          .container { max-width: 800px; margin: 0 auto; border: 1px solid #eee; padding: 40px; }
          .header { display: flex; justify-content: space-between; border-bottom: 3px solid #000; padding-bottom: 20px; margin-bottom: 30px; }
          .header h1 { margin: 0; text-transform: uppercase; font-size: 24px; letter-spacing: -1px; }
          .header p { margin: 0; font-size: 12px; color: #666; font-weight: bold; }
          .info-box { display: grid; grid-template-cols: 1fr 1fr; gap: 20px; background: #f9f9f9; padding: 20px; border-radius: 8px; margin-bottom: 30px; border: 1px solid #eee; }
          .info-item label { display: block; font-size: 10px; text-transform: uppercase; color: #888; font-weight: black; }
          .info-item p { margin: 0; font-weight: bold; font-size: 14px; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 30px; }
          th { background: #f2f2f2; text-align: left; font-size: 10px; text-transform: uppercase; padding: 10px; border: 1px solid #ddd; }
          .clauses { font-size: 12px; text-align: justify; margin-bottom: 40px; }
          .clauses ol { padding-left: 20px; }
          .clauses li { margin-bottom: 10px; }
          .signatures { display: grid; grid-template-cols: 1fr 1fr; gap: 40px; margin-top: 60px; }
          .sig-box { border-top: 1px solid #000; text-align: center; padding-top: 10px; }
          .sig-box span { display: block; font-size: 10px; text-transform: uppercase; font-weight: bold; }
          .footer { text-align: center; font-size: 9px; color: #aaa; margin-top: 50px; text-transform: uppercase; letter-spacing: 2px; }
          @media print { body { padding: 0; } .container { border: none; } }
        </style>
      </head>
      <body>
        <div class="container">
          <div class="header">
            <div>
              <h1>AssetTrack Pro</h1>
              <p>Gestão Inteligente de Ativos TI</p>
            </div>
            <div style="text-align: right">
              <h2 style="margin:0; font-size: 18px;">Termo de Responsabilidade</h2>
              <p>Protocolo: ${selectedRequest.id}</p>
            </div>
          </div>

          <p style="font-size: 13px; text-align: justify; margin-bottom: 25px;">
            Pelo presente instrumento, o colaborador abaixo identificado declara ter recebido da empresa, em perfeitas condições de uso e funcionamento, o(s) equipamento(s) de TI discriminado(s) neste termo, assumindo total responsabilidade pela guarda, conservação e uso adequado dos mesmos exclusivamente para fins profissionais.
          </p>

          <div class="info-box">
            <div class="info-item"><label>Colaborador</label><p>${employeeName}</p></div>
            <div class="info-item"><label>Setor / Departamento</label><p>${employeeSector}</p></div>
            <div class="info-item"><label>CPF</label><p>${employeeCpf}</p></div>
            <div class="info-item"><label>Data de Recebimento</label><p>${new Date().toLocaleDateString('pt-BR')}</p></div>
          </div>

          <h3 style="font-size: 12px; text-transform: uppercase; border-bottom: 1px solid #000; padding-bottom: 5px;">Equipamentos Entregues</h3>
          <table>
            <thead>
              <tr>
                <th>Tipo / Patrimônio</th>
                <th>Marca / Modelo</th>
                <th>S/N (Série)</th>
                <th>Especificações Técnicas</th>
              </tr>
            </thead>
            <tbody>
              ${assetsRows}
            </tbody>
          </table>

          <div class="clauses">
            <h3 style="font-size: 12px; text-transform: uppercase; border-bottom: 1px solid #000; padding-bottom: 5px;">Cláusulas de Compromisso</h3>
            <ol>
              <li>O colaborador compromete-se a zelar pelo equipamento, mantendo-o em local seguro e adequado.</li>
              <li>É expressamente proibido a instalação de softwares não autorizados ou alteração de hardware sem prévia anuência do departamento de TI.</li>
              <li>Em caso de dano por negligência, perda ou extravio do equipamento, o colaborador poderá ser responsabilizado pelos custos de reparo ou reposição, conforme legislação vigente.</li>
              <li>Em caso de desligamento da empresa, o equipamento deve ser devolvido imediatamente ao departamento de TI no mesmo estado de conservação em que foi recebido.</li>
              <li>O uso dos equipamentos deve seguir estritamente as políticas de segurança da informação e código de conduta da organização.</li>
            </ol>
          </div>

          <div class="signatures">
            <div class="sig-box">
              <span>Assinatura do Colaborador</span>
              <small style="font-size: 8px; color: #888;">${employeeName}</small>
            </div>
            <div class="sig-box">
              <span>Responsável pela Entrega</span>
              <small style="font-size: 8px; color: #888;">${currentUser.name}</small>
            </div>
          </div>

          <div class="footer">
            Documento Gerado via AssetTrack Pro Enterprise • ${new Date().toLocaleString('pt-BR')}
          </div>
        </div>
      </body>
      </html>
    `;

    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Termo_Responsabilidade_${selectedRequest.id}_${employeeName.replace(/\s+/g, '_')}.html`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 relative">
      <div className="lg:col-span-2 space-y-4 print:hidden">
        <h3 className="text-lg font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight">
          <Clock className="w-5 h-5 text-blue-600" /> Fluxo de Atendimento
        </h3>

        {requests.map(req => (
          <div 
            key={req.id} 
            onClick={() => setSelectedRequest(req)}
            className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between hover:shadow-md transition-all group cursor-pointer border-l-4 border-l-transparent hover:border-l-blue-600"
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${
                req.status === 'Pendente' ? 'bg-amber-100 text-amber-700' :
