                      <>
                        <CheckCircle className="w-5 h-5" /> Abrir Protocolo de Requisição
                      </>
                    )}
                 </button>
              </form>
           </div>
        </div>
      )}

      {selectedRequest && (
        <div className="fixed inset-0 z-[100] flex justify-end print:hidden">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => { setSelectedRequest(null); setItemToLink(null); }} />
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300 border-l border-slate-200">
