          <div className="flex-1 overflow-auto p-12 flex justify-center bg-slate-900/50 print:p-0 print:bg-white">
             <div className="w-full max-w-[210mm] bg-white shadow-2xl p-16 text-slate-900 min-h-[297mm] flex flex-col border border-slate-200 print:shadow-none print:border-none print:p-8">
