                <div className="flex justify-between items-start border-b-2 border-slate-900 pb-8 mb-10">
                   <div>
                      <h1 className="text-3xl font-black uppercase tracking-tighter text-blue-600">AssetTrack Pro</h1>
                      <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Gestão Inteligente de Ativos TI</p>
                   </div>
                   <div className="text-right">
                      <h2 className="text-xl font-black uppercase">Termo de Responsabilidade</h2>
                      <p className="text-xs font-bold text-slate-500">Documento Interno ID: {selectedRequest.id}</p>
                   </div>
                </div>

                {/* Conteúdo do Termo */}
                <div className="flex-1 space-y-10">
                   <div className="space-y-4">
                      <p className="text-sm font-medium leading-relaxed text-justify">
                         Pelo presente instrumento, o colaborador abaixo identificado declara ter recebido da empresa, em perfeitas condições de uso e funcionamento, o(s) equipamento(s) de TI discriminado(s) neste termo, assumindo total responsabilidade pela guarda, conservação e uso adequado dos mesmos exclusivamente para fins profissionais.
                      </p>
                   </div>

                   {/* Dados do Colaborador */}
                   <div className="grid grid-cols-2 gap-8 bg-slate-50 p-6 border border-slate-200 rounded-lg">
                      <div>
                         <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Colaborador</p>
                         <p className="text-sm font-black">{getEmployeeName(selectedRequest.employeeId)}</p>
                      </div>
                      <div>
                         <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Setor / Departamento</p>
                         <p className="text-sm font-black">{getEmployeeSector(selectedRequest.employeeId)}</p>
                      </div>
                      <div>
                         <p className="text-[10px] font-black uppercase text-slate-400 mb-1">CPF</p>
                         <p className="text-sm font-black">{getEmployee(selectedRequest.employeeId)?.cpf || 'N/A'}</p>
                      </div>
                      <div>
                         <p className="text-[10px] font-black uppercase text-slate-400 mb-1">Data de Recebimento</p>
                         <p className="text-sm font-black">{new Date().toLocaleDateString('pt-BR')}</p>
                      </div>
                   </div>

                   {/* Tabela de Equipamentos */}
                   <div className="space-y-4">
                      <h4 className="text-xs font-black uppercase border-b border-slate-900 pb-2">Equipamentos Entregues</h4>
                      <table className="w-full text-left border-collapse">
                         <thead>
                            <tr className="bg-slate-100 border-b-2 border-slate-900">
                               <th className="p-3 text-[10px] font-black uppercase">Tipo / Patrimônio</th>
                               <th className="p-3 text-[10px] font-black uppercase">Marca / Modelo</th>
                               <th className="p-3 text-[10px] font-black uppercase">S/N (Série)</th>
                               <th className="p-3 text-[10px] font-black uppercase">Especificações Técnicas</th>
                            </tr>
                         </thead>
                         <tbody>
                            {selectedRequest.itemFulfillments?.map((f, i) => {
                               const assetInfo = getLinkedAssetInfo(f.linkedAssetId);

                               // Lógica para extrair especificações se estiverem no campo observations
                               let specs = "";
                               if (assetInfo) {
                                  if (assetInfo.processor) specs += `CPU: ${assetInfo.processor}; `;
                                  if (assetInfo.ram) specs += `RAM: ${assetInfo.ram}; `;
                                  if (assetInfo.storage) specs += `Disco: ${assetInfo.storage}; `;

                                  // Se as specs estiverem embutidas no observations via sistema legível
                                  if (!specs && assetInfo.observations?.includes('[DADOS TÉCNICOS ADICIONAIS]')) {
                                     specs = assetInfo.observations.split('[DADOS TÉCNICOS ADICIONAIS]')[1].replace(/\n/g, ' ').trim();
                                  }
                               }

                               return (
                                  <tr key={i} className="border-b border-slate-200">
                                     <td className="p-3 text-sm">
                                        <p className="font-bold">{f.type}</p>
                                        <p className="text-[10px] font-mono font-black text-blue-700">{f.linkedAssetId || 'N/A'}</p>
                                     </td>
                                     <td className="p-3 text-sm">{assetInfo ? `${assetInfo.brand} ${assetInfo.model}` : 'N/A'}</td>
                                     <td className="p-3 text-[10px] font-mono">{assetInfo?.serialNumber || 'SEM SÉRIE'}</td>
                                     <td className="p-3 text-[10px] font-medium leading-tight">
                                        {specs || 'Configuração padrão de fábrica'}
                                        {assetInfo?.observations && !assetInfo.observations.includes('[DADOS TÉCNICOS]') && (
                                           <p className="mt-1 text-[8px] italic text-slate-400">Obs: {assetInfo.observations.substring(0, 50)}...</p>
                                        )}
                                     </td>
                                  </tr>
                               );
                            })}
                         </tbody>
                      </table>
                   </div>

                   {/* Cláusulas de Compromisso */}
                   <div className="space-y-4 pt-4">
                      <h4 className="text-xs font-black uppercase border-b border-slate-900 pb-2">Cláusulas de Uso</h4>
                      <ol className="list-decimal pl-5 space-y-3 text-[11px] font-medium text-slate-700 leading-tight">
                         <li>O colaborador compromete-se a zelar pelo equipamento, mantendo-o em local seguro e adequado.</li>
                         <li>É expressamente proibido a instalação de softwares não autorizados ou alteração de hardware sem prévia anuência do departamento de TI.</li>
                         <li>Em caso de dano por negligência, perda ou extravio do equipamento, o colaborador poderá ser responsabilizado pelos custos de reparo ou reposição, conforme legislação vigente.</li>
                         <li>Em caso de desligamento da empresa, o equipamento deve ser devolvido imediatamente ao departamento de TI no mesmo estado de conservação em que foi recebido.</li>
                         <li>O uso dos equipamentos deve seguir estritamente as políticas de segurança da informação e código de conduta da organização.</li>
                      </ol>
                   </div>
                </div>

                {/* Assinaturas */}
                <div className="mt-20 grid grid-cols-2 gap-20">
                   <div className="text-center space-y-2">
                      <div className="border-t border-slate-900 pt-2">
                         <p className="text-[10px] font-black uppercase">Assinatura do Colaborador</p>
                         <p className="text-[8px] text-slate-400 font-bold uppercase">{getEmployeeName(selectedRequest.employeeId)}</p>
                      </div>
                   </div>
                   <div className="text-center space-y-2">
                      <div className="border-t border-slate-900 pt-2">
                         <p className="text-[10px] font-black uppercase">Responsável pela Entrega (Empresa)</p>
                         <p className="text-[8px] text-slate-400 font-bold uppercase">{currentUser.name} — {currentUser.sector}</p>
                      </div>
                   </div>
                </div>

                <div className="mt-auto pt-10 text-center">
                   <p className="text-[8px] text-slate-400 font-black uppercase tracking-[0.2em]">Documento Gerado pelo Módulo de Requisições v3.5 • {new Date().toLocaleDateString('pt-BR')} {new Date().toLocaleTimeString('pt-BR')}</p>
                </div>
             </div>
          </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }

        @media print {
          body, html { margin: 0; padding: 0; background: white; }
          #root { display: none; }
          .print-container { display: block !important; }
          @page { size: portrait; margin: 1cm; }
        }
      `}</style>
    </div>
  );
};

export default RequestsManager;

import React, { useState } from 'react';
import { 
  FileText, 
  Plus, 
  X, 
  Clock, 
  ChevronRight, 
  CheckCircle, 
  ShoppingCart, 
  Link as LinkIcon, 
  Search, 
  AlertCircle,
  User,
  Calendar,
  Package,
  Check,
  Ban,
  Truck,
  MessageSquare,
  CheckSquare,
  Wrench,
  UserPlus,
  Loader2,
  Printer,
  ShieldCheck,
  FileDown,
  Cpu,
  HardDrive,
  ScanBarcode,
  Download,
  FileJson,
  ImageIcon,
  FileSearch
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';
import { EquipmentRequest, Employee, Asset, AssetType, ItemFulfillment, UserAccount } from '../types';
import { ASSET_TYPES } from '../constants';

// Estendendo o tipo jsPDF para incluir o plugin autotable
interface jsPDFWithAutoTable extends jsPDF {
  autoTable: (options: any) => jsPDF;
}

interface RequestsManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  assets: Asset[];
  currentUser: UserAccount;
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  onUpdateStatus: (id: string, status: EquipmentRequest['status']) => Promise<void>;
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
}

const RequestsManager: React.FC<RequestsManagerProps> = ({ requests, employees, assets, currentUser, onAddRequest, onUpdateStatus, onUpdateRequest }) => {
  const [showModal, setShowModal] = useState(false);
  const [showTermModal, setShowTermModal] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<EquipmentRequest | null>(null);
  const [itemToLink, setItemToLink] = useState<{ index: number; type: AssetType } | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newReq, setNewReq] = useState<Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>>({
    requesterId: currentUser.id, 
    employeeId: '',
    items: [],
    observation: ''
  });

  const getEmployee = (id: string) => employees.find(e => e.id === id);
  const getEmployeeName = (id: string) => getEmployee(id)?.name || 'Desconhecido';
  const getEmployeeSector = (id: string) => getEmployee(id)?.sector || 'Setor não informado';

  const getLinkedAssetInfo = (assetId?: string) => {
    if (!assetId) return null;
    return assets.find(a => a.id === assetId);
  };

  const toggleItem = (type: AssetType) => {
    setNewReq(prev => ({
      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newReq.items.length === 0) {
      alert("Selecione pelo menos um item.");
      return;
    }
    if (!newReq.employeeId) {
      alert("Selecione o colaborador destinatário.");
      return;
    }

    setIsSubmitting(true);
    try {
      await onAddRequest({
        ...newReq,
        itemFulfillments: newReq.items.map(type => ({
          type,
          isPurchaseOrder: false
        }))
      });
      setShowModal(false);
      setNewReq({ requesterId: currentUser.id, employeeId: '', items: [], observation: '' });
    } catch (err) {
      alert("Erro ao criar requisição.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleLinkAsset = async (index: number, assetId: string) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: assetId,
      isPurchaseOrder: false
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleMarkForPurchase = async (index: number) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      type: selectedRequest.items[index],
      linkedAssetId: undefined,
      isPurchaseOrder: true,
      purchaseStatus: 'Pendente'
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
  };

  const handleStatusChange = async (status: EquipmentRequest['status']) => {
    if (selectedRequest) {
      await onUpdateStatus(selectedRequest.id, status);
      setSelectedRequest(prev => prev ? { ...prev, status } : null);
    }
  };

  const availableAssetsByType = (type: AssetType) => {
    return assets.filter(a => a.type === type && a.status === 'Disponível');
  };

  const handleDownloadTerm = (includePhotos: boolean = false) => {
    if (!selectedRequest) return;

    const doc = new jsPDF() as any;
    const employee = getEmployee(selectedRequest.employeeId);
    const employeeName = employee?.name || 'Desconhecido';
    const employeeSector = employee?.sector || 'N/A';
    const employeeCpf = employee?.cpf || 'N/A';

    // Configurações Iniciais
    doc.setFont("helvetica", "bold");
    doc.setFontSize(22);
    doc.setTextColor(37, 99, 235); // Blue-600
    doc.text("AssetTrack Pro", 20, 20);

    doc.setFontSize(8);
    doc.setTextColor(100, 116, 139);
    doc.text("GESTÃO INTELIGENTE DE ATIVOS TI", 20, 25);

    doc.setFontSize(14);
    doc.setTextColor(0, 0, 0);
    doc.text("Termo de Responsabilidade", 130, 20);
    doc.setFontSize(9);
    doc.text(`Protocolo: ${selectedRequest.id}`, 130, 25);

    doc.setLineWidth(0.5);
    doc.line(20, 30, 190, 30);

    // Texto Introdutório
    doc.setFont("helvetica", "normal");
    doc.setFontSize(10);
    const introText = "Pelo presente instrumento, o colaborador abaixo identificado declara ter recebido da empresa, em perfeitas condições de uso e funcionamento, o(s) equipamento(s) de TI discriminado(s) neste termo, assumindo total responsabilidade pela guarda, conservação e uso adequado dos mesmos exclusivamente para fins profissionais.";
    const splitIntro = doc.splitTextToSize(introText, 170);
    doc.text(splitIntro, 20, 40);

    // Quadro de Dados do Colaborador
    doc.setFillColor(248, 250, 252);
    doc.rect(20, 55, 170, 25, "F");
    doc.setDrawColor(226, 232, 240);
    doc.rect(20, 55, 170, 25, "S");

    doc.setFont("helvetica", "bold");
    doc.setFontSize(8);
    doc.setTextColor(100, 116, 139);
    doc.text("COLABORADOR", 25, 62);
    doc.text("SETOR / DEPARTAMENTO", 110, 62);
    doc.text("CPF", 25, 72);
    doc.text("DATA DE RECEBIMENTO", 110, 72);

    doc.setFontSize(10);
    doc.setTextColor(0, 0, 0);
    doc.text(employeeName, 25, 67);
    doc.text(employeeSector, 110, 67);
    doc.text(employeeCpf, 25, 77);
    doc.text(new Date().toLocaleDateString('pt-BR'), 110, 77);

    // Tabela de Itens
    const tableBody = selectedRequest.itemFulfillments?.map((f) => {
      const assetInfo = getLinkedAssetInfo(f.linkedAssetId);
      let specs = "Configuração padrão";
      if (assetInfo) {
        let specArr = [];
        if (assetInfo.processor) specArr.push(`CPU: ${assetInfo.processor}`);
        if (assetInfo.ram) specArr.push(`RAM: ${assetInfo.ram}`);
        if (assetInfo.storage) specArr.push(`Disco: ${assetInfo.storage}`);
        if (specArr.length > 0) specs = specArr.join("; ");
      }

      return [
        { content: `${f.type}\nID: ${f.linkedAssetId || 'N/A'}`, styles: { fontStyle: 'bold' } },
        assetInfo ? `${assetInfo.brand} ${assetInfo.model}` : 'N/A',
        assetInfo?.serialNumber || 'N/A',
        specs
      ];
    }) || [];

    doc.autoTable({
      startY: 85,
      head: [['Tipo / Patrimônio', 'Marca / Modelo', 'S/N (Série)', 'Especificações Técnicas']],
      body: tableBody,
      theme: 'grid',
      headStyles: { fillColor: [15, 23, 42], textColor: [255, 255, 255], fontSize: 8, fontStyle: 'bold' },
      bodyStyles: { fontSize: 8, textColor: [51, 65, 85] },
      columnStyles: {
        0: { cellWidth: 40 },
        1: { cellWidth: 40 },
        2: { cellWidth: 35 },
        3: { cellWidth: 55 }
      }
    });

    let finalY = (doc as any).lastAutoTable.finalY + 10;

    // Cláusulas
    doc.setFont("helvetica", "bold");
    doc.setFontSize(9);
    doc.text("CLÁUSULAS DE COMPROMISSO E USO", 20, finalY);
    doc.line(20, finalY + 2, 80, finalY + 2);

    doc.setFont("helvetica", "normal");
    doc.setFontSize(8);
    const clauses = [
      "1. O colaborador compromete-se a zelar pelo equipamento, mantendo-o em local seguro.",
      "2. É proibida a instalação de softwares não autorizados ou alteração de hardware sem anuência do TI.",
      "3. Em caso de dano por negligência, perda ou extravio, o colaborador poderá ser responsabilizado pelos custos.",
      "4. Em caso de desligamento, o equipamento deve ser devolvido imediatamente no mesmo estado de conservação.",
      "5. O uso deve seguir as políticas de segurança da informação e código de conduta da organização."
    ];

    let clauseY = finalY + 8;
    clauses.forEach(clause => {
      doc.text(clause, 20, clauseY);
      clauseY += 5;
    });

    // Assinaturas
    const sigY = clauseY + 20;
    doc.line(20, sigY, 90, sigY);
