        if (assetInfo && assetInfo.photos && assetInfo.photos.length > 0) {
          assetInfo.photos.forEach((photo) => {
            // Verifica se a foto cabe na página atual
            if (photoY + photoHeight > 270) {
              doc.addPage();
              photoY = 20;
            }

            try {
              doc.addImage(photo, 'JPEG', photoX, photoY, photoWidth, photoHeight);
              doc.setFontSize(7);
              doc.setTextColor(150, 150, 150);
              doc.text(`Patrimônio: ${assetInfo.id} - ${assetInfo.type}`, photoX, photoY + photoHeight + 5);

              // Alterna coluna
