const SUPABASE_ANON_KEY = 'sb_publishable_5GUfPGtwRSMJHjNqocwqwA_GUm6U0PE';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

const localDB = {
  save: (key: string, data: any) => localStorage.setItem(`assettrack_${key}`, JSON.stringify(data)),
  get: (key: string) => {
    const val = localStorage.getItem(`assettrack_${key}`);
    return val ? JSON.parse(val) : null;
  }
};

const DATA_MARKER = '--- [SISTEMA-DATA-V1] ---';

// Utilitários para Ativos
const deflateAsset = (asset: Asset) => {
  const { 
    serialNumber, ram, storage, processor, screenSize, 
    caseModel, isWireless, monitorInputs, isAbnt, hasNumericKeypad, 
    ...dbReady 
  } = asset;

  const virtualFields = {
    serialNumber, ram, storage, processor, screenSize, 
    caseModel, isWireless, monitorInputs, isAbnt, hasNumericKeypad
  };

  const cleanObs = (dbReady.observations || '').split(DATA_MARKER)[0].trim();
  const encodedData = btoa(JSON.stringify(virtualFields));
  dbReady.observations = `${cleanObs}\n\n${DATA_MARKER}\n${encodedData}`;

  return dbReady;
};

const inflateAsset = (dbAsset: any): Asset => {
  if (!dbAsset.observations || !dbAsset.observations.includes(DATA_MARKER)) {
    return dbAsset as Asset;
  }
  try {
    const parts = dbAsset.observations.split(DATA_MARKER);
    const cleanObs = parts[0].trim();
    const encodedData = parts[1].trim();
    const virtualFields = JSON.parse(atob(encodedData));
    return { ...dbAsset, ...virtualFields, observations: cleanObs } as Asset;
  } catch (e) {
    return dbAsset as Asset;
  }
};

// Utilitários para Usuários (Resolve o erro de criação)
const deflateUser = (user: UserAccount) => {
  const { employeeId, password, modules, ...dbReady } = user;
  const virtualFields = { employeeId, password, modules };

  const cleanSector = (dbReady.sector || '').split(DATA_MARKER)[0].trim();
  const encodedData = btoa(JSON.stringify(virtualFields));
  dbReady.sector = `${cleanSector} ${DATA_MARKER}${encodedData}`;

  return dbReady;
};

const inflateUser = (dbUser: any): UserAccount => {
  if (!dbUser || !dbUser.sector || !dbUser.sector.includes(DATA_MARKER)) {
    return dbUser as UserAccount;
  }
  try {
    const parts = dbUser.sector.split(DATA_MARKER);
    const cleanSector = parts[0].trim();
    const encodedData = parts[1].trim();
    const virtualFields = JSON.parse(atob(encodedData));
    return { ...dbUser, ...virtualFields, sector: cleanSector } as UserAccount;
  } catch (e) {
    return dbUser as UserAccount;
  }
};

export const db = {
  assets: {
    list: async () => {
      try {
        const { data, error } = await supabase.from('assets').select('*').order('createdAt', { ascending: false });
        if (error) throw error;
        const inflated = (data || []).map(inflateAsset);
        localDB.save('assets', inflated);
        return inflated;
      } catch (err) {
        return localDB.get('assets') || [];
      }
    },
    upsert: async (asset: Asset) => {
      try {
        const dbReady = deflateAsset(asset);
        const { error } = await supabase.from('assets').upsert(dbReady);
        if (error) throw error;
      } catch (err: any) {
        const current = localDB.get('assets') || [];
        const index = current.findIndex((a: any) => a.id === asset.id);
        if (index >= 0) current[index] = asset; else current.push(asset);
        localDB.save('assets', current);
        if (err.message === 'Failed to fetch') return;
        throw err;
      }
    },
    remove: async (id: string) => {
      const { error } = await supabase.from('assets').delete().eq('id', id);
      if (error) throw error;
    }
  },
  departments: {
    list: async () => {
      try {
        const { data, error } = await supabase.from('departments').select('*');
        if (error) throw error;
        localDB.save('departments', data);
        return data as Department[];
      } catch (err) {
        return localDB.get('departments') || [];
      }
    },
    upsert: async (dept: Department) => {
      const { error } = await supabase.from('departments').upsert(dept);
      if (error) throw error;
    },
    remove: async (id: string) => {
      const { error } = await supabase.from('departments').delete().eq('id', id);
      if (error) throw error;
    }
  },
  employees: {
    list: async () => {
      try {
        const { data, error } = await supabase.from('employees').select('*');
        if (error) throw error;
        localDB.save('employees', data);
        return data as Employee[];
      } catch (err) {
        return localDB.get('employees') || [];
      }
    },
    upsert: async (emp: Employee) => {
      const { error } = await supabase.from('employees').upsert(emp);
      if (error) throw error;
    },
    remove: async (id: string) => {
      const { error } = await supabase.from('employees').delete().eq('id', id);
      if (error) throw error;
    }
  },
  requests: {
    list: async () => {
      try {
        const { data, error } = await supabase.from('requests').select('*').order('createdAt', { ascending: false });
        if (error) throw error;
        localDB.save('requests', data);
        return data as EquipmentRequest[];
      } catch (err) {
        return localDB.get('requests') || [];
      }
    },
    upsert: async (req: EquipmentRequest) => {
      const { error } = await supabase.from('requests').upsert(req);
      if (error) throw error;
    }
  },
  auditSessions: {
    list: async () => {
      try {
        const { data, error } = await supabase.from('audit_sessions').select('*').order('createdAt', { ascending: false });
        if (error) throw error;
        localDB.save('audit_sessions', data);
        return data as AuditSession[];
      } catch (err) {
        return localDB.get('audit_sessions') || [];
      }
    },
    upsert: async (session: AuditSession) => {
      const { error } = await supabase.from('audit_sessions').upsert(session);
      if (error) throw error;
    }
  },
  users: {
    list: async () => {
      try {
        const { data, error } = await supabase.from('users').select('*');
        if (error) throw error;
        const inflated = (data || []).map(inflateUser);
        localDB.save('users', inflated);
        return inflated;
      } catch (err) {
        return (localDB.get('users') || []).map(inflateUser);
      }
    },
    getForAuth: async (username: string) => {
      try {
        const { data, error } = await supabase
          .from('users')
          .select('*')
          .eq('username', username.toLowerCase())
          .single();

        if (error) throw error;
        return inflateUser(data);
      } catch (err: any) {
        const cached = localDB.get('users') || [];
        const user = cached.find((u: any) => u.username === username.toLowerCase());
        return user ? inflateUser(user) : null;
      }
    },
    upsert: async (user: UserAccount) => {
      const dbReady = deflateUser(user);
      const { error } = await supabase.from('users').upsert(dbReady);
      if (error) throw error;
    },
    remove: async (id: string) => {
      const { error } = await supabase.from('users').delete().eq('id', id);
      if (error) throw error;
    }
  }
};

