  };

  const handleAddRequest = async (reqData: any) => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const newReq: EquipmentRequest = { ...reqData, id, status: 'Pendente', createdAt: new Date().toISOString() };
    await db.requests.upsert(newReq);
    setRequests(prev => [newReq, ...prev]);
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    await db.requests.upsert(req);
    setRequests(prev => prev.map(r => r.id === req.id ? req : r));
  };

  const handleRemoveRequest = async (id: string) => {
    await db.requests.remove(id);
    setRequests(prev => prev.filter(r => r.id !== id));
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    await db.auditSessions.upsert(session);
    setAuditSessions(prev => prev.map(old => old.id === session.id ? session : old));
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
          <Package className="text-white w-10 h-10" />
        </div>
        <div className="flex flex-col items-center gap-2">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Sincronizando Banco de Dados...</p>
        </div>
      </div>
    );
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser || MOCK_USERS[0]} onLogout={handleLogout} requests={requests}>
      {isOffline && (
        <div className="mb-6 bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-3 text-amber-800">
           <WifiOff className="w-5 h-5" />
           <p className="text-xs font-black uppercase tracking-tight">Modo Offline Ativo.</p>
        </div>
      )}

      {(() => {
        if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

        switch (activeTab) {
          case 'dashboard': return <Dashboard assets={assets} requests={requests} employees={employees} />;
          case 'departments': 
            return <CompanyManager 
              companies={departments} assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                await db.departments.upsert(newD); 
                setDepartments(prev => [...prev, newD]); 
              }} 
              onUpdateCompany={async (u) => { await db.departments.upsert(u); setDepartments(prev => prev.map(d => d.id === u.id ? u : d)); }} 
              onRemoveCompany={async (id) => { await db.departments.remove(id); setDepartments(prev => prev.filter(d => d.id !== id)); }} 
            />;
          case 'assets': return <AssetManager assets={assets} employees={employees} companies={departments} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={handleRemoveAsset} />;
          case 'employees': 
            return <EmployeeManager 
              employees={employees} departments={departments} assets={assets} users={users} requests={requests}
              onAdd={async (e) => { const newE = {...e, id: `EMP-${Date.now()}`}; await db.employees.upsert(newE); setEmployees(prev => [...prev, newE]); }} 
              onUpdate={async (u) => { await db.employees.upsert(u); setEmployees(prev => prev.map(e => e.id === u.id ? u : e)); }}
              onRemove={async (id) => { 
                const hasAssets = assets.some(a => a.assignedTo === id);
                const hasUser = users.some(u => u.employeeId === id);
                const hasRequests = requests.some(r => r.employeeId === id);

                if (hasAssets) { alert("Bloqueado: Colaborador com ativos vinculados."); return; }
                if (hasUser) { alert("Bloqueado: Colaborador com conta de usuário ativa."); return; }
                if (hasRequests) { alert("Bloqueado: Colaborador possui histórico de requisições. Você deve remover as requisições vinculadas antes de excluir o colaborador."); return; }

                try {
                  await db.employees.remove(id); 
                  setEmployees(prev => prev.filter(e => e.id !== id)); 
                } catch (e: any) {
                  alert("Erro do Banco: Não foi possível excluir. Verifique se existem outros vínculos no sistema.");
                }
              }}
            />;
          case 'requests': 
            return <RequestsManager 
              requests={requests} employees={employees} assets={assets} currentUser={currentUser} 
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if(req) await handleUpdateRequest({...req, status}); }} 
              onRemoveRequest={handleRemoveRequest}
            />;
          case 'inventory-check': return <InventoryCheckManager assets={assets} employees={employees} auditSessions={auditSessions} onAddAuditSession={async (s) => { await db.auditSessions.upsert(s); setAuditSessions(prev => [s, ...prev]); }} onUpdateAuditSession={handleUpdateAuditSession} onGenerateDivergenceRequest={(sector, ids) => handleAddRequest({ requesterId: currentUser.id, employeeId: employees.find(e => e.sector === sector)?.id || '', items: assets.filter(a => ids.includes(a.id)).map(a => a.type), type: 'Divergencia', observation: `Divergência Auditoria: ${sector}` })} />;
          case 'maintenance': return <MaintenanceManager assets={assets} employees={employees} companies={departments} onUpdateAsset={handleUpdateAsset} />;
          case 'purchase-orders': return <PurchaseOrderManager requests={requests} employees={employees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} onAddRequest={handleAddRequest} />;
          case 'printing': return <PrintManager assets={assets} />;
          case 'user-management': 
            return <UserManager 
              users={users} employees={employees}
              onAddUser={async (u) => { 
                const newU = { ...u, id: `USR-${Math.floor(Math.random() * 9000) + 1000}` }; 
                try {
                  await db.users.upsert(newU); 
                  setUsers(prev => [...prev, newU]); 
                } catch(e: any) { alert(`Falha ao salvar usuário.`); }
              }} 
              onUpdateUser={async (u) => { await db.users.upsert(u); setUsers(prev => prev.map(old => old.id === u.id ? u : old)); }} 
              onRemoveUser={async (id) => { await db.users.remove(id); setUsers(prev => prev.filter(u => u.id !== id)); }} 
            />;
          default: return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Users, Plus, Search, Trash2, Edit2, Building2, X, Package, Shield, FileText, AlertCircle } from 'lucide-react';
import { Employee, Department, Asset, UserAccount, EquipmentRequest } from '../types';

interface EmployeeManagerProps {
  employees: Employee[];
  departments: Department[];
  assets: Asset[];
  users: UserAccount[];
  requests: EquipmentRequest[];
  onAdd: (employee: Omit<Employee, 'id'>) => void;
  onUpdate: (employee: Employee) => void;
  onRemove: (id: string) => void;
}

const EmployeeManager: React.FC<EmployeeManagerProps> = ({ employees, departments, assets, users, requests, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [formData, setFormData] = useState<Omit<Employee, 'id'>>({
    name: '', sector: '', role: '', cpf: '', departmentId: ''
  });

  const handleOpenCreate = () => {
    setEditingEmployee(null);
    setFormData({ name: '', sector: '', role: '', cpf: '', departmentId: '' });
    setShowForm(true);
  };

  const handleOpenEdit = (emp: Employee) => {
    setEditingEmployee(emp);
    setFormData({
      name: emp.name,
      sector: emp.sector,
      role: emp.role,
      cpf: emp.cpf,
      departmentId: emp.departmentId
    });
    setShowForm(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.departmentId) {
      alert("Selecione um departamento.");
      return;
    }
    const selectedDept = departments.find(d => d.id === formData.departmentId);
    const finalData = { ...formData, sector: selectedDept?.name || 'Geral' };
    if (editingEmployee) onUpdate({ ...finalData, id: editingEmployee.id });
    else onAdd(finalData);
    setShowForm(false);
    setEditingEmployee(null);
  };

  const getDepartmentName = (id: string) => departments.find(d => d.id === id)?.name || 'N/A';

  const filteredEmployees = employees.filter(emp => 
    emp.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.cpf.includes(searchTerm) ||
    emp.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center gap-4">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por nome, cargo ou CPF..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={handleOpenCreate}
          className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 transition-all shadow-lg"
        >
          <Plus className="w-5 h-5" />
          <span>Cadastrar Colaborador</span>
        </button>
      </div>

      <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Nome</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-center">Dependências</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Departamento</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Função</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredEmployees.map(emp => {
              const hasAssets = assets.some(a => a.assignedTo === emp.id);
              const hasUser = users.some(u => u.employeeId === emp.id);
              const hasRequests = requests.some(r => r.employeeId === emp.id);
              const isLocked = hasAssets || hasUser || hasRequests;

              return (
                <tr key={emp.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-800">{emp.name}</span>
                      <span className="text-[10px] text-slate-400 font-mono">{emp.cpf}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center justify-center gap-3">
                      <Package className={`w-4 h-4 ${hasAssets ? 'text-blue-500' : 'text-slate-200'}`} title={hasAssets ? "Possui Ativos" : ""} />
                      <Shield className={`w-4 h-4 ${hasUser ? 'text-indigo-500' : 'text-slate-200'}`} title={hasUser ? "Possui Usuário" : ""} />
                      <FileText className={`w-4 h-4 ${hasRequests ? 'text-amber-500' : 'text-slate-200'}`} title={hasRequests ? "Possui Histórico de Requisições" : ""} />
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-slate-700 font-bold">{getDepartmentName(emp.departmentId)}</span>
                  </td>
                  <td className="px-6 py-4 text-slate-600 font-medium">{emp.role}</td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => handleOpenEdit(emp)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
                        <Edit2 className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={() => {
                          if (isLocked) {
                            let motivos = [];
                            if (hasAssets) motivos.push("Possui equipamentos vinculados");
                            if (hasUser) motivos.push("Possui conta de usuário");
                            if (hasRequests) motivos.push("Possui histórico de requisições");
                            alert(`Não é possível excluir: ${motivos.join(', ')}. Remova os vínculos primeiro.`);
                            return;
                          }
                          if(confirm(`Remover colaborador ${emp.name}?`)) onRemove(emp.id) 
                        }}
                        className={`p-2 transition-colors ${isLocked ? 'text-slate-200 cursor-not-allowed' : 'text-slate-400 hover:text-rose-600'}`}
                        title={isLocked ? "Exclusão Bloqueada (Vínculos Ativos)" : "Remover"}
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {showForm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800 flex items-center gap-2">
                <Users className="w-7 h-7 text-blue-600" />
                {editingEmployee ? 'Editar Colaborador' : 'Novo Colaborador'}
              </h3>
              <button onClick={() => setShowForm(false)} className="p-2 hover:bg-slate-100 rounded-full text-slate-400"><X className="w-6 h-6" /></button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label>
                <input className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 outline-none font-bold" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="Nome do colaborador" required />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">CPF</label>
                <input className="w-full p-4 rounded-2xl border border-slate-200 bg-white outline-none font-bold" placeholder="000.000.000-00" value={formData.cpf} onChange={e => setFormData({...formData, cpf: e.target.value})} required />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Departamento</label>
                <div className="relative">
                   <Building2 className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                   <select className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-white outline-none font-bold appearance-none" value={formData.departmentId} onChange={e => setFormData({...formData, departmentId: e.target.value})} required>
                     <option value="">Selecione...</option>
                     {departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                   </select>
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Função / Cargo</label>
                <input className="w-full p-4 rounded-2xl border border-slate-200 bg-white outline-none font-bold" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value})} placeholder="Ex: Desenvolvedor Senior" required />
              </div>
              <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-slate-100">
                <button type="button" onClick={() => setShowForm(false)} className="px-6 py-4 font-bold text-slate-500">Cancelar</button>
                <button type="submit" className="px-12 py-4 font-black bg-blue-600 text-white rounded-2xl shadow-xl uppercase text-xs tracking-widest">
                  {editingEmployee ? 'Salvar' : 'Salvar Colaborador'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default EmployeeManager;

import React, { useState } from 'react';
import { 
  FileText, Plus, X, Clock, ChevronRight, CheckCircle, ShoppingCart, Link as LinkIcon, 
  Search, AlertCircle, User, Calendar, Package, Check, Ban, Truck, MessageSquare, 
  CheckSquare, Wrench, UserPlus, Loader2, ShieldCheck, Edit2, Trash2, Download, ImageIcon
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';
import { EquipmentRequest, Employee, Asset, AssetType, UserAccount } from '../types';
import { ASSET_TYPES } from '../constants';

interface RequestsManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  assets: Asset[];
  currentUser: UserAccount;
  onAddRequest: (req: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => Promise<void>;
  onUpdateStatus: (id: string, status: EquipmentRequest['status']) => Promise<void>;
  onUpdateRequest: (req: EquipmentRequest) => Promise<void>;
  onRemoveRequest?: (id: string) => Promise<void>;
}

const RequestsManager: React.FC<RequestsManagerProps> = ({ requests, employees, assets, currentUser, onAddRequest, onUpdateStatus, onUpdateRequest, onRemoveRequest }) => {
  const [showModal, setShowModal] = useState(false);
  const [showTermModal, setShowTermModal] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<EquipmentRequest | null>(null);
  const [itemToLink, setItemToLink] = useState<{ index: number; type: AssetType } | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newReq, setNewReq] = useState<Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>>({
    requesterId: currentUser.id, 
    employeeId: '',
    items: [],
    observation: ''
  });

  const getEmployee = (id: string) => employees.find(e => e.id === id);
  const getEmployeeName = (id: string) => getEmployee(id)?.name || 'Desconhecido';
  const getEmployeeSector = (id: string) => getEmployee(id)?.sector || 'Setor não informado';

  const getLinkedAssetInfo = (assetId?: string) => {
    if (!assetId) return null;
    return assets.find(a => a.id === assetId);
  };

  const toggleItem = (type: AssetType) => {
    setNewReq(prev => ({
      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newReq.items.length === 0 || !newReq.employeeId) {
      alert("Preencha todos os campos.");
      return;
    }
    setIsSubmitting(true);
    try {
      await onAddRequest({
        ...newReq,
        itemFulfillments: newReq.items.map(type => ({ type, isPurchaseOrder: false }))
      });
      setShowModal(false);
      setNewReq({ requesterId: currentUser.id, employeeId: '', items: [], observation: '' });
    } catch (err) { alert("Erro ao criar requisição."); }
    finally { setIsSubmitting(false); }
  };

  const handleLinkAsset = async (index: number, assetId: string) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = { type: selectedRequest.items[index], linkedAssetId: assetId, isPurchaseOrder: false };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleMarkForPurchase = async (index: number) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = { type: selectedRequest.items[index], linkedAssetId: undefined, isPurchaseOrder: true, purchaseStatus: 'Pendente' };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    await onUpdateRequest(updated);
    setSelectedRequest(updated);
  };

  const handleStatusChange = async (status: EquipmentRequest['status']) => {
    if (selectedRequest) {
      await onUpdateStatus(selectedRequest.id, status);
      setSelectedRequest(prev => prev ? { ...prev, status } : null);
    }
  };

  const handleRemove = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!onRemoveRequest) return;
    if (confirm("Tem certeza que deseja excluir permanentemente esta requisição?")) {
      try {
        await onRemoveRequest(id);
        if (selectedRequest?.id === id) setSelectedRequest(null);
      } catch (err) { alert("Falha ao excluir requisição."); }
    }
  };

  const availableAssetsByType = (type: AssetType) => {
    return assets.filter(a => a.type === type && a.status === 'Disponível');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 relative">
      <div className="lg:col-span-2 space-y-4 print:hidden">
        <h3 className="text-lg font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight">
          <Clock className="w-5 h-5 text-blue-600" /> Fluxo de Atendimento
        </h3>

        {requests.map(req => (
          <div 
            key={req.id} 
            onClick={() => setSelectedRequest(req)}
            className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between hover:shadow-md transition-all group cursor-pointer border-l-4 border-l-transparent hover:border-l-blue-600"
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${
                req.status === 'Pendente' ? 'bg-amber-100 text-amber-700' :
                req.status === 'Aprovado' ? 'bg-blue-100 text-blue-700' :
                req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-700' :
                req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'
              }`}>
                {req.status === 'Preparando' ? <Wrench className="w-6 h-6" /> : req.status === 'Entregue' ? <ShieldCheck className="w-6 h-6" /> : <FileText className="w-6 h-6" />}
              </div>
              <div>
                <p className="font-black text-slate-900">{req.id}</p>
                <p className="text-sm text-slate-600 font-semibold">Para: {getEmployeeName(req.employeeId)}</p>
              </div>
            </div>

            <div className="flex items-center gap-4">
               <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-tight ${
                 req.status === 'Pendente' ? 'bg-amber-100 text-amber-800 border-amber-200' : 
                 req.status === 'Aprovado' ? 'bg-blue-100 text-blue-800 border-blue-200' :
                 req.status === 'Preparando' ? 'bg-indigo-100 text-indigo-800 border-indigo-200' :
                 req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-800 border-emerald-200' : 'bg-rose-100 text-rose-800 border-rose-200'
               }`}>
                 {req.status}
               </span>
               <button onClick={(e) => handleRemove(e, req.id)} className="p-2 text-slate-300 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100">
                 <Trash2 className="w-5 h-5" />
               </button>
               <ChevronRight className="w-5 h-5 text-slate-400 group-hover:text-blue-600 transition-transform group-hover:translate-x-1" />
            </div>
          </div>
        ))}

        {requests.length === 0 && (
          <div className="bg-white p-16 rounded-[2.5rem] border border-dashed border-slate-300 text-center space-y-4">
             <p className="text-slate-600 font-black uppercase tracking-widest text-xs">Nenhuma solicitação encontrada.</p>
          </div>
        )}
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-xl h-fit space-y-6 sticky top-24 print:hidden">
        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-slate-900 hover:bg-black text-white font-black py-5 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-2 uppercase tracking-widest text-xs"
        >
          <Plus className="w-5 h-5" />
          <span>Nova Requisição</span>
        </button>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
              <div className="bg-slate-900 p-8 text-white flex items-center justify-between">
                 <h3 className="text-xl font-black uppercase tracking-tight">Nova Requisição</h3>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full"><X className="w-6 h-6" /></button>
              </div>
              <form onSubmit={handleSubmit} className="p-10 space-y-8 overflow-y-auto flex-1">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</label>
                    <select className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none font-bold" value={newReq.employeeId} onChange={e => setNewReq({...newReq, employeeId: e.target.value})} required>
                       <option value="">Selecione...</option>
                       {employees.map(emp => <option key={emp.id} value={emp.id}>{emp.name}</option>)}
                    </select>
                 </div>
                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Itens</label>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                       {ASSET_TYPES.map(type => (
                         <button key={type} type="button" onClick={() => toggleItem(type as AssetType)} className={`p-3 rounded-xl border text-[10px] font-black uppercase ${newReq.items.includes(type as AssetType) ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-600 hover:border-blue-300'}`}>
                           {type}
                         </button>
                       ))}
                    </div>
                 </div>
                 <button type="submit" disabled={isSubmitting} className="w-full bg-blue-600 text-white font-black py-5 rounded-[2rem] shadow-xl uppercase tracking-widest text-xs disabled:bg-slate-300">
                    {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : "Abrir Requisição"}
                 </button>
              </form>
           </div>
        </div>
      )}

      {selectedRequest && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => { setSelectedRequest(null); setItemToLink(null); }} />
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl flex flex-col border-l border-slate-200">
            <div className="p-6 border-b border-slate-200 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-black text-slate-900">{selectedRequest.id}</h3>
                <p className="text-sm text-slate-600 font-bold">Destino: {getEmployeeName(selectedRequest.employeeId)}</p>
              </div>
              <div className="flex items-center gap-2">
                 <button onClick={(e) => handleRemove(e, selectedRequest.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full transition-colors" title="Excluir Requisição">
                   <Trash2 className="w-5 h-5" />
                 </button>
                 <button onClick={() => { setSelectedRequest(null); setItemToLink(null); }} className="p-2 hover:bg-slate-100 rounded-full text-slate-500"><X className="w-6 h-6" /></button>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-6">
               {selectedRequest.items.map((itemType, idx) => {
                  const fulfillment = selectedRequest.itemFulfillments?.[idx];
                  const isLinked = !!fulfillment?.linkedAssetId;
                  return (
                    <div key={idx} className={`p-5 rounded-3xl border ${isLinked ? 'bg-emerald-50 border-emerald-200' : 'bg-white border-slate-200'}`}>
                      <div className="flex items-center justify-between mb-4">
                        <span className="font-black text-slate-900">{itemType}</span>
                        {isLinked && <span className="text-[10px] font-black uppercase text-emerald-800">Vinculado: {fulfillment.linkedAssetId}</span>}
                      </div>
                      {!isLinked && (
                        <button onClick={() => setItemToLink({ index: idx, type: itemType })} className="w-full py-2 bg-slate-100 rounded-xl text-[10px] font-black uppercase hover:bg-blue-600 hover:text-white transition-all">
                          Vincular Ativo
                        </button>
                      )}
                      {itemToLink?.index === idx && (
                        <div className="mt-4 p-4 bg-slate-100 rounded-2xl border border-slate-300">
                           <div className="space-y-2">
                              {availableAssetsByType(itemType).map(asset => (
                                <button key={asset.id} onClick={() => handleLinkAsset(idx, asset.id)} className="w-full text-left p-3 bg-white border border-slate-300 rounded-xl hover:border-blue-600">
                                   <p className="text-xs font-black">{asset.id} - {asset.brand} {asset.model}</p>
                                </button>
                              ))}
                           </div>
                        </div>
                      )}
                    </div>
                  );
               })}
            </div>

            <div className="p-8 border-t border-slate-200 flex flex-col gap-2">
               {selectedRequest.status === 'Pendente' && <button onClick={() => handleStatusChange('Aprovado')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs">Aprovar Pedido</button>}
               {selectedRequest.status === 'Aprovado' && <button onClick={() => handleStatusChange('Preparando')} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Iniciar Preparação</button>}
               {selectedRequest.status === 'Preparando' && <button onClick={() => handleStatusChange('Entregue')} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs">Confirmar Entrega</button>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RequestsManager;

