  get: (key: string) => {
    const val = localStorage.getItem(`assettrack_${key}`);
    return val ? JSON.parse(val) : null;
  }
};

const DATA_MARKER = '--- [SISTEMA-DATA-V1] ---';

const toB64 = (str: string) => {
  try {
    return btoa(encodeURIComponent(str).replace(/%([0-9A-F]{2})/g, (match, p1) => {
      return String.fromCharCode(parseInt(p1, 16));
    }));
  } catch (e) {
    console.error("Erro na codificação Base64:", e);
    return "";
  }
};

const fromB64 = (str: string) => {
  try {
    return decodeURIComponent(Array.prototype.map.call(atob(str), (c: string) => {
      return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
    }).join(''));
  } catch (e) {
    console.error("Erro na decodificação Base64:", e);
    return "";
  }
};

const deflateAsset = (asset: Asset) => {
  const { 
    serialNumber, ram, storage, processor, screenSize, 
    caseModel, isWireless, monitorInputs, isAbnt, hasNumericKeypad, 
    ...dbReady 
  } = asset;

  const virtualFields = {
    serialNumber, ram, storage, processor, screenSize, 
    caseModel, isWireless, monitorInputs, isAbnt, hasNumericKeypad
  };

  const cleanObs = (dbReady.observations || '').split(DATA_MARKER)[0].trim();
  const encodedData = toB64(JSON.stringify(virtualFields));
  dbReady.observations = `${cleanObs}\n\n${DATA_MARKER}\n${encodedData}`;

  return dbReady;
};

const inflateAsset = (dbAsset: any): Asset => {
  if (!dbAsset.observations || !dbAsset.observations.includes(DATA_MARKER)) {
    return dbAsset as Asset;
  }
  try {
    const parts = dbAsset.observations.split(DATA_MARKER);
    const cleanObs = parts[0].trim();
    const encodedData = parts[1].trim();
    const decodedStr = fromB64(encodedData);
    if (!decodedStr) return dbAsset as Asset;
    const virtualFields = JSON.parse(decodedStr);
    return { ...dbAsset, ...virtualFields, observations: cleanObs } as Asset;
  } catch (e) {
    return dbAsset as Asset;
  }
};

const deflateUser = (user: UserAccount) => {
  const { employeeId, password, modules, ...rest } = user;

  const dbReady: any = {
    id: rest.id,
    name: rest.name,
    username: (rest.username || '').toLowerCase().trim(),
    sector: (rest.sector || '').split(DATA_MARKER)[0].trim(),
    password: password || 'admin123'
  };

  const virtualFields = { employeeId, password: dbReady.password, modules };
  const encodedData = toB64(JSON.stringify(virtualFields));

  dbReady.sector = `${dbReady.sector} ${DATA_MARKER}${encodedData}`;

  return dbReady;
};

const inflateUser = (dbUser: any): UserAccount => {
  if (!dbUser || !dbUser.sector || !dbUser.sector.includes(DATA_MARKER)) {
    return dbUser as UserAccount;
  }
  try {
    const parts = dbUser.sector.split(DATA_MARKER);
    const cleanSector = parts[0].trim();
    const encodedData = parts[1].trim();
    const decodedStr = fromB64(encodedData);
    if (!decodedStr) return dbUser as UserAccount;
    const virtualFields = JSON.parse(decodedStr);
    return { ...dbUser, ...virtualFields, sector: cleanSector, password: virtualFields.password || dbUser.password } as UserAccount;
  } catch (e) {
    return dbUser as UserAccount;
  }
};

export const db = {
  assets: {
    list: async () => {
      try {
        const { data, error } = await supabase.from('assets').select('*').order('createdAt', { ascending: false });
        if (error) throw error;
        const inflated = (data || []).map(inflateAsset);
        localDB.save('assets', inflated);
        return inflated;
      } catch (err) {
        return localDB.get('assets') || [];
      }
    },
    upsert: async (asset: Asset) => {
      try {
        const dbReady = deflateAsset(asset);
        const { error } = await supabase.from('assets').upsert(dbReady);
        if (error) throw error;
      } catch (err: any) {
        const current = localDB.get('assets') || [];
        const index = current.findIndex((a: any) => a.id === asset.id);
        if (index >= 0) current[index] = asset; else current.push(asset);
        localDB.save('assets', current);
        throw err;
      }
    },
    remove: async (id: string) => {
      const { error } = await supabase.from('assets').delete().eq('id', id);
      if (error) throw error;
    }
  },
  departments: {
