        <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl animate-pulse mb-4">
          <Package className="text-white w-10 h-10" />
        </div>
        <div className="flex flex-col items-center gap-2">
          <Loader2 className="w-5 h-5 text-blue-600 animate-spin" />
          <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Sincronizando Banco de Dados...</p>
        </div>
      </div>
    );
  }

  const activeEmployees = employees.filter(e => e.isActive !== false);

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser || MOCK_USERS[0]} 
      onLogout={handleLogout} 
      requests={requests}
      notifications={notifications}
      onMarkAsRead={markNotificationAsRead}
      onClearAll={clearNotifications}
    >
      {isOffline && (
        <div className="mb-6 bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-3 text-amber-800">
           <WifiOff className="w-5 h-5" />
           <p className="text-xs font-black uppercase tracking-tight">Modo Offline Ativo.</p>
        </div>
      )}

      {(() => {
        if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={users} />;

        switch (activeTab) {
          case 'dashboard': return <Dashboard assets={assets} requests={requests} employees={activeEmployees} />;
          case 'departments': 
            return <CompanyManager 
              companies={departments} assets={assets} 
              onAddCompany={async (d) => { 
                const newD = {...d, id: `DEPT-${Date.now()}`, createdAt: new Date().toISOString()}; 
                await db.departments.upsert(newD); 
                setDepartments(prev => [...prev, newD]); 
              }} 
              onUpdateCompany={async (u) => { await db.departments.upsert(u); setDepartments(prev => prev.map(d => d.id === u.id ? u : d)); }} 
              onRemoveCompany={async (id) => { await db.departments.remove(id); setDepartments(prev => prev.filter(d => d.id !== id)); }} 
            />;
          case 'assets': return <AssetManager assets={assets} employees={activeEmployees} companies={departments} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={handleRemoveAsset} />;
          case 'employees': 
            return <EmployeeManager 
              employees={activeEmployees} departments={departments} assets={assets} users={users} requests={requests}
              onAdd={async (e) => { 
                const newE = {...e, id: `EMP-${Date.now()}`, isActive: true}; 
                await db.employees.upsert(newE); 
                setEmployees(prev => [...prev, newE]); 
              }} 
              onUpdate={async (u) => { await db.employees.upsert(u); setEmployees(prev => prev.map(e => e.id === u.id ? u : e)); }}
              onRemove={async (id) => { 
                setEmployees(prev => {
                  const target = prev.find(e => e.id === id);
                  if (!target) return prev;
                  const updatedEmployee = { ...target, isActive: false };
                  db.employees.upsert(updatedEmployee).catch(err => {
                    console.error("Falha ao salvar arquivamento no banco:", err);
                    alert("Erro ao salvar no banco. Recarregando dados...");
                    loadData();
                  });
                  return prev.map(e => e.id === id ? updatedEmployee : e);
                });
              }}
            />;
          case 'requests': 
            return <RequestsManager 
              requests={requests} employees={activeEmployees} assets={assets} currentUser={currentUser} 
              onAddRequest={handleAddRequest} 
              onUpdateRequest={handleUpdateRequest} 
              onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if(req) await handleUpdateRequest({...req, status}); }} 
              onRemoveRequest={handleRemoveRequest}
            />;
          case 'inventory-check': 
            return <InventoryCheckManager 
              assets={assets} 
              employees={activeEmployees} 
              auditSessions={auditSessions} 
              onAddAuditSession={async (s) => { 
                await db.auditSessions.upsert(s); 
                setAuditSessions(prev => [s, ...prev]); 
              }} 
              onUpdateAuditSession={handleUpdateAuditSession} 
              onGenerateDivergenceRequest={(sector, ids) => {
                // Fix: wrapped handleAddRequest call to return void
                handleAddRequest({ 
                  requesterId: currentUser.id, 
                  employeeId: activeEmployees.find(e => e.sector === sector)?.id || '', 
                  items: assets.filter(a => ids.includes(a.id)).map(a => a.type), 
                  type: 'Divergencia', 
                  observation: `Divergência Auditoria: ${sector}` 
                });
              }} 
            />;
          case 'maintenance': 
            return <MaintenanceManager 
              assets={assets} employees={activeEmployees} companies={departments} 
              currentUser={currentUser}
              onUpdateAsset={handleUpdateAsset} 
              onAddNotification={addNotification}
              onAddRequest={handleAddRequest}
            />;
          case 'purchase-orders': return <PurchaseOrderManager requests={requests} employees={activeEmployees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} onAddRequest={handleAddRequest} />;
          case 'printing': return <PrintManager assets={assets} />;
          case 'user-management': 
            return <UserManager 
              users={users} employees={activeEmployees}
              onAddUser={async (u) => { 
                const newU = { ...u, id: `USR-${Math.floor(Math.random() * 9000) + 1000}` }; 
                try {
                  await db.users.upsert(newU); 
                  setUsers(prev => [...prev, newU]); 
                } catch(e: any) { alert(`Falha ao salvar usuário.`); }
              }} 
              onUpdateUser={async (u) => { await db.users.upsert(u); setUsers(prev => prev.map(old => old.id === u.id ? u : old)); }} 
              onRemoveUser={async (id) => { await db.users.remove(id); setUsers(prev => prev.filter(u => u.id !== id)); }} 
            />;
          default: return <div className="p-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Módulo em Desenvolvimento</div>;
        }
      })()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  Wrench, 
  Search, 
  Plus, 
  X, 
  Activity, 
  CheckCircle2, 
  Package, 
  AlertCircle,
  Building2,
  Clock,
  ChevronRight,
  Info,
  Layers,
  ArrowRight,
  User,
  Settings2,
  ShoppingCart,
  Trash2,
  FileText,
  Zap,
  Loader2,
  History
} from 'lucide-react';
import { Asset, HistoryEntry, Employee, Department, AppNotification, EquipmentRequest, AssetType, UserAccount } from '../types';
import { ASSET_TYPES } from '../constants';

interface MaintenanceManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  currentUser: UserAccount;
  onUpdateAsset: (asset: Asset) => void;
  onAddNotification: (notif: Omit<AppNotification, 'id' | 'createdAt' | 'isRead'>) => void;
  onAddRequest: (req: any) => Promise<void>;
}

const MaintenanceManager: React.FC<MaintenanceManagerProps> = ({ assets, employees, companies, currentUser, onUpdateAsset, onAddNotification, onAddRequest }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [selectedAssetId, setSelectedAssetId] = useState('');
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);

  const [maintenanceType, setMaintenanceType] = useState<'Preventiva' | 'Corretiva'>('Preventiva');
  const [maintenanceScope, setMaintenanceScope] = useState<'Interna' | 'Externa'>('Interna');
  const [reason, setReason] = useState('');

  // Estados para o formulário de detalhe/conclusão
  const [finalDiagnosis, setFinalDiagnosis] = useState('');
  const [isSubmittingPO, setIsSubmittingPO] = useState(false);
  const [showPOForm, setShowPOForm] = useState(false);
  const [poType, setPoType] = useState<AssetType>('Mouse');

  const assetsInMaintenance = useMemo(() => 
    assets.filter(a => a.status === 'Manutenção')
  , [assets]);

  const availableForMaintenance = useMemo(() => 
    assets.filter(a => a.status !== 'Manutenção' && a.status !== 'Baixado')
  , [assets]);

  const filteredAvailable = availableForMaintenance.filter(a => 
    a.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
    a.model.toLowerCase().includes(searchTerm.toLowerCase()) ||
    a.brand.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleOpenMaintenance = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAssetId) return;

    const asset = assets.find(a => a.id === selectedAssetId);
    if (!asset) return;

    const historyEntry: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Manutenção',
      description: `Início de manutenção ${maintenanceType} (${maintenanceScope}). Motivo/Diagnóstico de Entrada: ${reason}`,
      performedBy: currentUser.name,
      userContext: getEmployeeName(asset.assignedTo)
    };

    const updatedAsset: Asset = {
      ...asset,
      status: 'Manutenção',
      observations: reason, // O campo observations guarda o diagnóstico inicial durante o reparo
      history: [...(asset.history || []), historyEntry]
    };

    onUpdateAsset(updatedAsset);

    onAddNotification({
      title: 'Nova Manutenção Iniciada',
      message: `O Ativo ${asset.id} (${asset.type} ${asset.brand}) entrou em manutenção ${maintenanceType.toLowerCase()}.`,
      type: 'maintenance',
      targetModule: 'maintenance'
    });

    setShowModal(false);
    setSelectedAssetId('');
    setReason('');
    setSearchTerm('');
  };

  const handleConcludeMaintenance = () => {
    if (!detailAsset) return;

    const historyEntry: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Manutenção',
      description: `Manutenção concluída. Diagnóstico de Entrada: "${detailAsset.observations}". Laudo Técnico Final: "${finalDiagnosis || 'Equipamento revisado e retornado ao estoque.'}"`,
      performedBy: currentUser.name
    };

    const updatedAsset: Asset = {
      ...detailAsset,
      status: 'Disponível',
      assignedTo: undefined,
      observations: `Manutenção preventiva/corretiva finalizada em ${new Date().toLocaleDateString('pt-BR')}.`,
      history: [...(detailAsset.history || []), historyEntry]
    };

    onUpdateAsset(updatedAsset);

    onAddNotification({
      title: 'Manutenção Concluída',
      message: `O Ativo ${detailAsset.id} já está disponível no estoque para novo uso.`,
      type: 'info',
      targetModule: 'maintenance'
    });

    setShowDetailModal(false);
    setDetailAsset(null);
    setFinalDiagnosis('');
  };

  const handleRetireAsset = () => {
    if (!detailAsset) return;
    if (!finalDiagnosis.trim()) {
      alert("Para dar baixa, é obrigatório preencher o Laudo Técnico Final justificando o sucateamento.");
      return;
    }

    if (!confirm("Deseja realmente dar baixa permanente (sucatear) neste equipamento? Esta ação não pode ser desfeita.")) return;

    const historyEntry: HistoryEntry = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      type: 'Status',
      description: `Ativo BAIXADO permanentemente. Motivo Entrada: "${detailAsset.observations}". Justificativa da Baixa: "${finalDiagnosis}"`,
      performedBy: currentUser.name
    };

    const updatedAsset: Asset = {
      ...detailAsset,
      status: 'Baixado',
      assignedTo: undefined,
      observations: `BAIXADO em ${new Date().toLocaleDateString('pt-BR')}. Laudo: ${finalDiagnosis}`,
      history: [...(detailAsset.history || []), historyEntry]
    };

    onUpdateAsset(updatedAsset);

    onAddNotification({
      title: 'Ativo Baixado do Inventário',
      message: `O Ativo ${detailAsset.id} foi retirado de circulação permanentemente por razões técnicas.`,
      type: 'alert',
      targetModule: 'maintenance'
    });

    setShowDetailModal(false);
    setDetailAsset(null);
    setFinalDiagnosis('');
  };

  const handleCreatePurchaseOrder = async () => {
    if (!detailAsset) return;
    setIsSubmittingPO(true);

    try {
      const observation = `Pedido de ${poType} vinculado à manutenção do Ativo ${detailAsset.id}. Motivo técnico: Diagnóstico de reparo em andamento.`;

      await onAddRequest({
        requesterId: currentUser.id,
        employeeId: '', // Estoque TI
        items: [poType],
        observation,
        itemFulfillments: [{
          type: poType,
          isPurchaseOrder: true,
          purchaseStatus: 'Pendente'
        }]
      });

      onAddNotification({
        title: 'Peça Solicitada para Manutenção',
        message: `Foi gerado um pedido de ${poType} para o ativo ${detailAsset.id} em manutenção.`,
        type: 'delivery',
        targetModule: 'purchase-orders'
      });

      alert("Requisição de compra gerada e enviada ao financeiro!");
      setShowPOForm(false);
    } catch (e) {
      alert("Falha ao gerar pedido de compra.");
    } finally {
      setIsSubmittingPO(false);
    }
  };

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';
  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'N/A';

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-2xl font-black text-slate-800 tracking-tight">Centro de Manutenção</h3>
          <p className="text-slate-500 font-medium italic">Gestão técnica e histórico de reparos.</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-amber-600 hover:bg-amber-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-amber-100 flex items-center gap-2 transition-all transform active:scale-95"
        >
          <Wrench className="w-5 h-5" />
          Nova Entrada de Reparo
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {assetsInMaintenance.map(asset => (
          <div 
            key={asset.id} 
            onClick={() => {
              setDetailAsset(asset);
              setFinalDiagnosis(''); // Inicia vazio para o técnico preencher a saída
              setShowDetailModal(true);
            }}
            className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm hover:shadow-xl hover:border-amber-400 transition-all group flex flex-col cursor-pointer active:scale-95"
          >
            <div className="flex justify-between items-start mb-6">
              <div className="w-14 h-14 bg-amber-50 rounded-2xl flex items-center justify-center text-amber-600 group-hover:bg-amber-600 group-hover:text-white transition-all duration-500 shadow-sm">
                <Activity className="w-7 h-7" />
              </div>
              <div className="flex flex-col items-end">
                 <span className="bg-amber-600 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest mb-1 shadow-lg shadow-amber-100">
                    Laboratório TI
                 </span>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter font-mono">{asset.id}</p>
              </div>
            </div>

            <div className="space-y-1 mb-6">
              <h4 className="text-xl font-black text-slate-800 tracking-tight leading-none group-hover:text-amber-600 transition-colors">{asset.type}</h4>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{asset.brand} {asset.model}</p>
              <div className="flex items-center gap-1 text-[10px] text-slate-400 font-bold uppercase pt-2">
                <Layers className="w-3 h-3" /> {getDepartmentName(asset.departmentId)}
              </div>
            </div>

            <div className="bg-amber-50/50 p-4 rounded-2xl border border-amber-100 mb-6 flex-1">
               <div className="flex items-center gap-2 text-amber-600 mb-2">
                  <Info className="w-4 h-4" />
                  <span className="text-[10px] font-black uppercase tracking-widest">Entrada: Diagnóstico Inicial</span>
               </div>
               <p className="text-xs text-slate-600 font-medium leading-relaxed italic line-clamp-3">
                 "{asset.observations}"
               </p>
            </div>

            <div className="flex items-center justify-between text-amber-600 font-black text-[10px] uppercase tracking-widest pt-2 border-t border-amber-100">
               <span>Gerenciar O.S.</span>
               <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
            </div>
          </div>
        ))}

        {assetsInMaintenance.length === 0 && (
          <div className="col-span-full py-32 bg-slate-50 rounded-[3rem] border border-dashed border-slate-200 flex flex-col items-center justify-center text-center space-y-4">
             <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-sm">
                <Settings2 className="w-10 h-10 text-slate-200" />
             </div>
             <div>
                <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Sem Ativos em Manutenção</p>
                <p className="text-[10px] text-slate-300 font-bold uppercase mt-1">Nenhum equipamento aguarda reparo no momento.</p>
             </div>
          </div>
        )}
      </div>

      {/* MODAL 1: ABRIR MANUTENÇÃO (ENTRADA) */}
      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-300">
              <div className="p-8 border-b border-slate-100 bg-amber-600 text-white flex items-center justify-between">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center">
                       <Wrench className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-2xl font-black tracking-tight">Entrada de Ativo em Reparo</h3>
                       <p className="text-amber-100 text-[10px] font-black uppercase tracking-widest">Registro de O.S. Inicial</p>
                    </div>
                 </div>
                 <button onClick={() => setShowModal(false)} className="p-2 hover:bg-white/10 rounded-full">
                    <X className="w-6 h-6" />
                 </button>
              </div>

              <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                 <div className="w-full lg:w-1/2 border-r border-slate-100 flex flex-col p-8 bg-slate-50/50">
                    <div className="relative mb-6">
                       <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                       <input 
                         type="text"
                         placeholder="Buscar por Patrimônio..."
                         className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-white outline-none font-bold shadow-sm"
                         value={searchTerm}
                         onChange={(e) => setSearchTerm(e.target.value)}
                       />
                    </div>
                    <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
                       {filteredAvailable.map(asset => (
                         <button 
                          key={asset.id}
                          onClick={() => setSelectedAssetId(asset.id)}
                          className={`w-full p-4 rounded-2xl border transition-all flex items-center justify-between group ${
                            selectedAssetId === asset.id 
                              ? 'bg-amber-600 border-amber-600 text-white shadow-xl' 
                              : 'bg-white border-slate-200 text-slate-800 hover:border-amber-300'
                          }`}
                         >
                            <div className="flex items-center gap-3">
                               <Package className={`w-5 h-5 ${selectedAssetId === asset.id ? 'text-white' : 'text-slate-400'}`} />
                               <div className="text-left">
                                  <p className="text-xs font-black uppercase tracking-tight">{asset.type}</p>
                                  <p className={`text-[10px] font-bold ${selectedAssetId === asset.id ? 'text-amber-100' : 'text-slate-500'}`}>
                                    {asset.brand} {asset.model} • {asset.id}
                                  </p>
                               </div>
                            </div>
                            <ArrowRight className={`w-4 h-4 transition-transform ${selectedAssetId === asset.id ? 'translate-x-1' : 'opacity-0 group-hover:opacity-100'}`} />
                         </button>
                       ))}
                    </div>
                 </div>
                 <div className="flex-1 p-8 bg-white overflow-y-auto custom-scrollbar">
                    <form onSubmit={handleOpenMaintenance} className="space-y-8">
                       <div className="grid grid-cols-2 gap-4">
                          <div className="space-y-2">
                             <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Modalidade</label>
                             <div className="flex bg-slate-100 p-1 rounded-xl">
                                <button type="button" onClick={() => setMaintenanceType('Preventiva')} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-lg transition-all ${maintenanceType === 'Preventiva' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'}`}>Prev.</button>
                                <button type="button" onClick={() => setMaintenanceType('Corretiva')} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-lg transition-all ${maintenanceType === 'Corretiva' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'}`}>Corr.</button>
                             </div>
                          </div>
                          <div className="space-y-2">
                             <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Localização</label>
                             <div className="flex bg-slate-100 p-1 rounded-xl">
                                <button type="button" onClick={() => setMaintenanceScope('Interna')} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-lg transition-all ${maintenanceScope === 'Interna' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'}`}>Interna</button>
                                <button type="button" onClick={() => setMaintenanceScope('Externa')} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-lg transition-all ${maintenanceScope === 'Externa' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'}`}>Externa</button>
                             </div>
                          </div>
                       </div>
                       <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Diagnóstico Inicial / Motivo</label>
                          <textarea 
                            className="w-full p-5 rounded-[2rem] border border-slate-200 bg-slate-50 outline-none resize-none h-40 font-medium text-slate-700 placeholder:text-slate-400"
                            placeholder="Descreva detalhadamente o problema reportado ou a necessidade técnica..."
                            value={reason}
                            onChange={(e) => setReason(e.target.value)}
                            required
                          />
                       </div>
                       <button 
                        type="submit"
                        disabled={!selectedAssetId}
                        className={`w-full py-5 rounded-[2rem] font-black shadow-xl transition-all uppercase tracking-widest text-xs flex items-center justify-center gap-3 ${
                          selectedAssetId ? 'bg-amber-600 hover:bg-amber-700 text-white' : 'bg-slate-100 text-slate-300 cursor-not-allowed'
                        }`}
                       >
                          <Wrench className="w-5 h-5" /> Registrar Entrada Laboratório
                       </button>
                    </form>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* MODAL 2: GESTÃO TÉCNICA (DETALHE E SAÍDA) */}
      {showDetailModal && detailAsset && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95">
              <div className="p-8 bg-slate-900 text-white flex items-center justify-between">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-amber-600 rounded-2xl flex items-center justify-center">
                       <Settings2 className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-2xl font-black tracking-tight">{detailAsset.id}</h3>
                       <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Gerenciamento de Ordem de Serviço</p>
                    </div>
                 </div>
                 <button onClick={() => setShowDetailModal(false)} className="p-2 hover:bg-white/10 rounded-full">
                    <X className="w-6 h-6" />
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto p-10 space-y-8 custom-scrollbar">
                 {/* Diagnóstico de Entrada (IMUTÁVEL) */}
                 <div className="space-y-3">
                    <div className="flex items-center justify-between">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                          <History className="w-4 h-4 text-amber-500" /> Diagnóstico de Entrada (Imutável)
                       </label>
                       <span className="text-[9px] font-black text-slate-400 uppercase">
