                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-4 border-t border-slate-100">
                    <button 
                      onClick={() => setShowPOForm(!showPOForm)}
                      className="w-full p-5 rounded-2xl border-2 border-slate-100 hover:border-blue-600 hover:bg-blue-50/30 transition-all flex items-center justify-between group"
                    >
                       <div className="flex items-center gap-3">
                          <ShoppingCart className="w-5 h-5 text-blue-600" />
                          <div className="text-left">
                             <p className="text-[11px] font-black uppercase tracking-widest text-slate-700 leading-none">Peças/Suprimentos</p>
                             <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase">Abrir Pedido de Compra</p>
                          </div>
                       </div>
                       <ChevronRight className="w-4 h-4 text-slate-300 group-hover:translate-x-1 transition-all" />
                    </button>

                    <button 
                      onClick={handleRetireAsset}
                      className="w-full p-5 rounded-2xl border-2 border-slate-100 hover:border-rose-600 hover:bg-rose-50/30 transition-all flex items-center justify-between group"
                    >
                       <div className="flex items-center gap-3">
                          <Trash2 className="w-5 h-5 text-rose-500" />
                          <div className="text-left">
                             <p className="text-[11px] font-black uppercase tracking-widest text-slate-700 leading-none">Baixa Patrimonial</p>
                             <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase">Inviabilizar e Sucatear</p>
                          </div>
                       </div>
                       <ChevronRight className="w-4 h-4 text-slate-300 group-hover:translate-x-1 transition-all" />
                    </button>
                 </div>

                 {showPOForm && (
                    <div className="bg-blue-50 p-8 rounded-[2rem] border-2 border-blue-100 animate-in slide-in-from-top-4 duration-300">
                       <div className="flex items-center gap-3 mb-6">
                          <Zap className="w-5 h-5 text-blue-600" />
                          <h4 className="text-sm font-black text-blue-900 uppercase tracking-tight">Requisitar Peça ao Financeiro</h4>
                       </div>
                       <div className="space-y-4">
                          <div className="space-y-1">
                             <label className="text-[10px] font-black text-blue-400 uppercase tracking-widest ml-1">Tipo de Componente</label>
                             <select 
                                className="w-full p-4 rounded-xl bg-white border border-blue-200 font-bold outline-none text-slate-700 shadow-sm"
                                value={poType}
                                onChange={(e) => setPoType(e.target.value as AssetType)}
                             >
                                {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                             </select>
                          </div>
                          <button 
                             onClick={handleCreatePurchaseOrder}
                             disabled={isSubmittingPO}
                             className="w-full bg-blue-600 text-white font-black py-4 rounded-xl shadow-lg shadow-blue-200 flex items-center justify-center gap-2 uppercase tracking-widest text-[10px] hover:bg-blue-700 transition-all active:scale-95"
                          >
                             {isSubmittingPO ? <Loader2 className="w-4 h-4 animate-spin" /> : <ShoppingCart className="w-4 h-4" />}
                             Confirmar Solicitação de Peça
                          </button>
                       </div>
                    </div>
                 )}

                 <div className="pt-6">
                    <button 
                      onClick={handleConcludeMaintenance}
                      className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-6 rounded-[2rem] font-black uppercase tracking-widest text-xs shadow-xl shadow-emerald-50 transition-all flex items-center justify-center gap-3 active:scale-95"
                    >
                       <CheckCircle2 className="w-6 h-6" />
                       Concluir Reparo e Liberar para Uso
                    </button>
                 </div>
              </div>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }
      `}</style>
    </div>
  );
};

