import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, 
  Search, 
  Trash2,
  X,
  Cpu,
  Layers,
  Monitor,
  Wifi,
  Usb,
  Zap,
  Type,
  History,
  Clock,
  User,
  Wrench,
  CheckCircle2,
  Tag,
  ArrowRight,
  ShieldCheck,
  FileSpreadsheet,
  PlusCircle,
  Save,
  MessageSquarePlus,
  AlertCircle,
  Loader2,
  Building2,
  Package,
  ArrowLeftRight,
  Camera,
  Image as ImageIcon,
  ScanBarcode,
  Edit2,
  HardDrive,
  Microchip
} from 'lucide-react';
import { Asset, AssetType, Employee, Department, HistoryEntry, AssetStatus } from '../types';
import { ASSET_TYPES } from '../constants';

interface AssetManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  onAdd: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode' | 'history'> & { id?: string }) => Promise<void>;
  onUpdate: (asset: Asset) => Promise<void>;
  onRemove: (id: string) => Promise<void>;
}

interface BulkAssetEntry {
  tempId: string;
  departmentId: string;
  type: AssetType;
  brand: string;
  model: string;
  serialNumber: string;
  ram: string;
  storage: string;
  screenSize: string;
  caseModel: string;
  isWireless: boolean;
  monitorInputs: string[];
  isAbnt: boolean;
  hasNumericKeypad: boolean;
  id: string; 
  assignedTo: string;
  observations: string;
}

const AssetManager: React.FC<AssetManagerProps> = ({ assets, employees, companies, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Asset | null>(null);
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<string>('all');
  const [isSaving, setIsSaving] = useState(false);
  const [isSavingBulk, setIsSavingBulk] = useState(false);
  const [manualLog, setManualLog] = useState('');
  const [isUpdatingDept, setIsUpdatingDept] = useState(false);
  const [isUpdatingEmployee, setIsUpdatingEmployee] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const [bulkEntries, setBulkEntries] = useState<BulkAssetEntry[]>([]);
  const [formData, setFormData] = useState<Partial<Asset>>({
    id: '',
    type: 'Notebook',
    status: 'Disponível',
    serialNumber: '',
    observations: '',
    photos: [],
    departmentId: '',
    ram: '',
    storage: '',
    processor: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: [],
    isAbnt: true,
    hasNumericKeypad: true
  });

  useEffect(() => {
    if (companies.length > 0 && !formData.departmentId && !editingAsset) {
      setFormData(prev => ({ ...prev, departmentId: companies[0].id }));
      setBulkEntries([{ 
        tempId: '1', departmentId: companies[0].id, type: 'Notebook', brand: '', model: '', serialNumber: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' 
      }]);
    }
  }, [companies, showForm, showBulkModal, editingAsset]);

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'N/A';
  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'Em Estoque';

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    (Array.from(files) as File[]).forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({
          ...prev,
          photos: [...(prev.photos || []), reader.result as string]
        }));
      };
      reader.readAsDataURL(file);
    });
  };

  const removePhoto = (index: number) => {
    setFormData(prev => ({
      ...prev,
      photos: prev.photos?.filter((_, i) => i !== index)
    }));
  };

  const openEditModal = (asset: Asset) => {
    setEditingAsset(asset);
    setFormData({ ...asset });
    setShowForm(true);
    setDetailAsset(null);
  };

  const handleDepartmentChange = async (newDeptId: string) => {
    if (!detailAsset || newDeptId === detailAsset.departmentId) return;

    setIsUpdatingDept(true);
    try {
      const oldDeptName = getDepartmentName(detailAsset.departmentId);
      const newDeptName = getDepartmentName(newDeptId);

      const transferLog: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Status',
        description: `Transferência de departamento: de "${oldDeptName}" para "${newDeptName}".`,
        performedBy: 'Gestor de Ativos'
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        departmentId: newDeptId,
        history: [...(detailAsset.history || []), transferLog]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err: any) {
      alert(`Erro ao transferir departamento: ${err.message || 'Erro desconhecido'}`);
    } finally {
      setIsUpdatingDept(false);
    }
  };

  const handleEmployeeChange = async (newEmployeeId: string) => {
    if (!detailAsset) return;
    if (newEmployeeId === detailAsset.assignedTo) return;

    setIsUpdatingEmployee(true);
    try {
      const oldEmpName = getEmployeeName(detailAsset.assignedTo);
      const newEmp = employees.find(e => e.id === newEmployeeId);
      const newEmpName = newEmp?.name || 'Estoque';

      const historyEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Atribuição',
        description: `Responsável alterado manualmente: de "${oldEmpName}" para "${newEmpName}".`,
        performedBy: 'Gestor de Ativos',
        userContext: newEmpName
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        assignedTo: newEmployeeId || undefined,
        departmentId: newEmp?.departmentId || detailAsset.departmentId,
        status: newEmployeeId ? 'Em Uso' : 'Disponível',
        history: [...(detailAsset.history || []), historyEntry]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err: any) {
      alert(`Erro ao alterar colaborador: ${err.message || 'Erro desconhecido'}`);
    } finally {
      setIsUpdatingEmployee(false);
    }
  };

  const handleAddManualLog = async () => {
    if (!detailAsset || !manualLog.trim()) return;

    try {
      const newEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Observação',
        description: manualLog,
        performedBy: 'Gestor de TI'
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        history: [...(detailAsset.history || []), newEntry]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
      setManualLog('');
    } catch (err: any) {
      alert("Falha ao salvar log manual.");
    }
  };

  const handleStatusChangeManual = async (newStatus: AssetStatus) => {
    if (!detailAsset) return;

    try {
      const newEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Status',
        description: `Status alterado manualmente de ${detailAsset.status} para ${newStatus}.`,
        performedBy: 'Gestor de TI'
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        status: newStatus,
        assignedTo: newStatus === 'Disponível' ? undefined : detailAsset.assignedTo,
        history: [...(detailAsset.history || []), newEntry]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err: any) {
      alert("Falha ao atualizar status.");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.departmentId) {
      alert("Selecione ou crie um departamento primeiro.");
      return;
    }

    setIsSaving(true);
    try {
      if (editingAsset) {
        const historyEntry: HistoryEntry = {
          id: Math.random().toString(),
          date: new Date().toISOString(),
          type: 'Observação',
          description: 'Informações do ativo atualizadas manualmente via formulário de edição.',
          performedBy: 'Gestor de Ativos'
        };
        const updated: Asset = {
          ...editingAsset,
          ...(formData as Asset),
          history: [...(editingAsset.history || []), historyEntry]
        };
        await onUpdate(updated);
        setEditingAsset(null);
      } else {
        // Se o ID estiver vazio, o App.tsx handleAddAsset irá gerar um automático
        await onAdd(formData as any);
      }
      setShowForm(false);
      resetFormData();
    } catch (err: any) {
      console.error("Erro no handleSubmit:", err);
      alert(`Erro ao salvar ativo: ${err.message || 'Certifique-se que o ID não está duplicado.'}`);
    } finally {
      setIsSaving(false);
    }
  };

  const resetFormData = () => {
    setFormData({ 
      id: '',
      type: 'Notebook', 
      status: 'Disponível', 
      serialNumber: '', 
      observations: '', 
      photos: [], 
      departmentId: companies[0]?.id || '', 
      ram: '', 
      storage: '', 
      processor: '',
      screenSize: '', 
      caseModel: '', 
      isWireless: false, 
      monitorInputs: [], 
      isAbnt: true, 
      hasNumericKeypad: true 
    });
    setEditingAsset(null);
  };

  const handleBulkAddRow = () => {
    setBulkEntries([...bulkEntries, { 
      tempId: Math.random().toString(), 
      departmentId: companies[0]?.id || '', 
      type: 'Notebook', 
      brand: '', 
      model: '', 
      serialNumber: '',
      ram: '',
      storage: '',
      screenSize: '',
      caseModel: '',
      isWireless: false,
      monitorInputs: [],
      isAbnt: true,
      hasNumericKeypad: true,
      id: '', 
      assignedTo: '', 
      observations: '' 
    }]);
  };

  const handleBulkSave = async () => {
    if (companies.length === 0) {
      alert("Erro: Você precisa cadastrar pelo menos um Departamento antes.");
      return;
    }

    setIsSavingBulk(true);
    try {
      for (const entry of bulkEntries) {
        // Se o ID estiver vazio, deixamos passar para o handleAdd do App.tsx gerar um. 
        // Mas em bulk, geralmente queremos IDs específicos ou deixamos o sistema gerar.
        await onAdd({
          id: entry.id || undefined,
          serialNumber: entry.serialNumber,
          departmentId: entry.departmentId || companies[0].id,
          type: entry.type,
          brand: entry.brand,
          model: entry.model,
          ram: entry.ram,
          storage: entry.storage,
          screenSize: entry.screenSize,
          caseModel: entry.caseModel,
          isWireless: entry.isWireless,
          monitorInputs: entry.monitorInputs,
          isAbnt: entry.isAbnt,
          hasNumericKeypad: entry.hasNumericKeypad,
          observations: entry.observations,
          photos: [],
          status: entry.assignedTo ? 'Em Uso' : 'Disponível',
          assignedTo: entry.assignedTo || undefined,
        });
      }
      setShowBulkModal(false);
      setBulkEntries([{ tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', serialNumber: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' }]);
    } catch (err: any) {
      alert(`Erro no salvamento em lote: ${err.message || 'Verifique se há IDs duplicados'}`);
    } finally {
      setIsSavingBulk(false);
    }
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.serialNumber?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || a.type === filterType;
    return matchesSearch && matchesType;
  });

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 print:hidden">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por modelo, serial, marca ou ID..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-300 bg-white focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm font-semibold placeholder:text-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
          <button onClick={() => setShowBulkModal(true)} className="flex items-center gap-2 px-4 py-3 text-xs font-black text-slate-800 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all uppercase tracking-widest">
            <FileSpreadsheet className="w-4 h-4 text-emerald-600" />
            Lançar Levantamento
          </button>
          <button onClick={() => { resetFormData(); setShowForm(true); }} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black transition-all shadow-lg uppercase tracking-widest text-xs">
            <Plus className="w-5 h-5" />
            <span>Novo Ativo</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden print:hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Ativo / Serial</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Tipo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Marca/Modelo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredAssets.map((asset) => (
                <tr 
                  key={asset.id} 
                  onClick={() => setDetailAsset(asset)}
                  className="hover:bg-blue-50/50 transition-colors cursor-pointer group"
                >
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                      <span className="font-black text-slate-900 group-hover:text-blue-700">{asset.id}</span>
                      <span className="text-[10px] text-slate-400 font-mono flex items-center gap-1">
                        <ScanBarcode className="w-3 h-3" /> {asset.serialNumber || 'SEM SERIAL'}
                      </span>
