                      placeholder="Relate o que foi feito ou o motivo da baixa..."
                      value={finalDiagnosis}
                      onChange={(e) => setFinalDiagnosis(e.target.value)}
                    />
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-4 border-t border-slate-100">
                    <button 
                      type="button"
                      onClick={() => setShowPOForm(!showPOForm)}
                      className="w-full p-5 rounded-2xl border-2 border-slate-100 hover:border-blue-600 hover:bg-blue-50/30 transition-all flex items-center justify-between group"
                    >
                       <div className="flex items-center gap-3">
