                             <p className="text-[11px] font-black uppercase tracking-widest text-slate-700 leading-none">Peças</p>
                             <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase">Solicitar Compra</p>
                          </div>
                       </div>
                    </button>

                    <button 
                      type="button"
                      onClick={handleRetireAsset}
                      disabled={isSubmitting}
                      className="w-full p-5 rounded-2xl border-2 border-slate-100 hover:border-rose-600 hover:bg-rose-50/30 transition-all flex items-center justify-between group disabled:opacity-50"
                    >
                       <div className="flex items-center gap-3">
                          <Trash2 className="w-5 h-5 text-rose-500" />
                          <div className="text-left">
                             <p className="text-[11px] font-black uppercase tracking-widest text-rose-700 leading-none">Baixa / Inativar</p>
                             <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase">Retirar do Inventário</p>
                          </div>
                       </div>
                    </button>
                 </div>

                 {showPOForm && (
                    <div className="bg-blue-50 p-8 rounded-[2rem] border-2 border-blue-100 animate-in slide-in-from-top-4">
                       <div className="space-y-4">
                          <select 
                             className="w-full p-4 rounded-xl bg-white border border-blue-200 font-bold outline-none shadow-sm"
                             value={poType}
                             onChange={(e) => setPoType(e.target.value as AssetType)}
                          >
                             {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                          </select>
                          <button 
                             type="button"
                             onClick={handleCreatePurchaseOrder}
                             className="w-full bg-blue-600 text-white font-black py-4 rounded-xl shadow-lg uppercase tracking-widest text-[10px]"
                          >
                             Confirmar Pedido de Peça
                          </button>
                       </div>
                    </div>
                 )}

                 <div className="pt-6">
                    <button 
                      type="button"
                      onClick={handleConcludeMaintenance}
                      disabled={isSubmitting}
                      className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-6 rounded-[2rem] font-black uppercase tracking-widest text-xs shadow-xl transition-all flex items-center justify-center gap-3 active:scale-95"
                    >
                       {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : <CheckCircle2 className="w-6 h-6" />}
                       Concluir e Voltar ao Estoque
                    </button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

