  Cpu,
  Layers,
  Monitor,
  Wifi,
  Usb,
  Zap,
  Type,
  History,
  Clock,
  User,
  Wrench,
  CheckCircle2,
  Tag,
  ArrowRight,
  ShieldCheck,
  FileSpreadsheet,
  PlusCircle,
  Save,
  MessageSquarePlus,
  AlertCircle,
  Loader2,
  Building2,
  Package,
  ArrowLeftRight,
  Camera,
  Image as ImageIcon,
