  EyeOff
} from 'lucide-react';
import { Asset, AssetType, Employee, Department, HistoryEntry, AssetStatus } from '../types';
import { ASSET_TYPES } from '../constants';

interface AssetManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  onAdd: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode' | 'history'> & { id?: string }) => Promise<void>;
  onUpdate: (asset: Asset) => Promise<void>;
  onRemove: (id: string) => Promise<void>;
}

interface BulkAssetEntry {
  tempId: string;
  departmentId: string;
  type: AssetType;
  brand: string;
  model: string;
  serialNumber: string;
  ram: string;
  storage: string;
  screenSize: string;
  caseModel: string;
  isWireless: boolean;
  monitorInputs: string[];
  isAbnt: boolean;
  hasNumericKeypad: boolean;
  id: string; 
  assignedTo: string;
  observations: string;
}

const AssetManager: React.FC<AssetManagerProps> = ({ assets, employees, companies, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingAsset, setEditingAsset] = useState<Asset | null>(null);
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showRetired, setShowRetired] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isSavingBulk, setIsSavingBulk] = useState(false);
  const [manualLog, setManualLog] = useState('');
  const [isUpdatingDept, setIsUpdatingDept] = useState(false);
  const [isUpdatingEmployee, setIsUpdatingEmployee] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const [bulkEntries, setBulkEntries] = useState<BulkAssetEntry[]>([]);
  const [formData, setFormData] = useState<Partial<Asset>>({
    id: '',
    type: 'Notebook',
    status: 'Disponível',
    serialNumber: '',
    observations: '',
    photos: [],
    departmentId: '',
    ram: '',
    storage: '',
    processor: '',
    screenSize: '',
    caseModel: '',
    isWireless: false,
    monitorInputs: [],
    isAbnt: true,
    hasNumericKeypad: true
  });

  useEffect(() => {
    if (companies.length > 0 && !formData.departmentId && !editingAsset) {
      setFormData(prev => ({ ...prev, departmentId: companies[0].id }));
      setBulkEntries([{ 
        tempId: '1', departmentId: companies[0].id, type: 'Notebook', brand: '', model: '', serialNumber: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' 
      }]);
    }
  }, [companies, showForm, showBulkModal, editingAsset]);

  const getDepartmentName = (id: string) => companies.find(c => c.id === id)?.name || 'Inativo / Baixado';
  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'Em Estoque';

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    (Array.from(files) as File[]).forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({
          ...prev,
          photos: [...(prev.photos || []), reader.result as string]
        }));
      };
      reader.readAsDataURL(file);
    });
  };

  const removePhoto = (index: number) => {
    setFormData(prev => ({
      ...prev,
      photos: prev.photos?.filter((_, i) => i !== index)
    }));
  };

  const openEditModal = (asset: Asset) => {
    setEditingAsset(asset);
    setFormData({ ...asset });
    setShowForm(true);
    setDetailAsset(null);
  };

  const handleDepartmentChange = async (newDeptId: string) => {
    if (!detailAsset || newDeptId === detailAsset.departmentId) return;

    setIsUpdatingDept(true);
    try {
      const oldDeptName = getDepartmentName(detailAsset.departmentId);
      const newDeptName = getDepartmentName(newDeptId);

      const transferLog: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Status',
        description: `Transferência de departamento: de "${oldDeptName}" para "${newDeptName}".`,
        performedBy: 'Gestor de Ativos'
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        departmentId: newDeptId,
        history: [...(detailAsset.history || []), transferLog]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err: any) {
      alert(`Erro ao transferir departamento: ${err.message || 'Erro desconhecido'}`);
    } finally {
      setIsUpdatingDept(false);
    }
  };

  const handleEmployeeChange = async (newEmployeeId: string) => {
    if (!detailAsset) return;
    if (newEmployeeId === detailAsset.assignedTo) return;

    setIsUpdatingEmployee(true);
    try {
      const oldEmpName = getEmployeeName(detailAsset.assignedTo);
      const newEmp = employees.find(e => e.id === newEmployeeId);
      const newEmpName = newEmp?.name || 'Estoque';

      const historyEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Atribuição',
        description: `Responsável alterado manualmente: de "${oldEmpName}" para "${newEmpName}".`,
        performedBy: 'Gestor de Ativos',
        userContext: newEmpName
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        assignedTo: newEmployeeId || undefined,
        departmentId: newEmp?.departmentId || detailAsset.departmentId,
        status: newEmployeeId ? 'Em Uso' : 'Disponível',
        history: [...(detailAsset.history || []), historyEntry]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err: any) {
      alert(`Erro ao alterar colaborador: ${err.message || 'Erro desconhecido'}`);
    } finally {
      setIsUpdatingEmployee(false);
    }
  };

  const handleAddManualLog = async () => {
    if (!detailAsset || !manualLog.trim()) return;

    try {
      const newEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Observação',
        description: manualLog,
        performedBy: 'Gestor de TI'
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        history: [...(detailAsset.history || []), newEntry]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
      setManualLog('');
    } catch (err: any) {
      alert("Falha ao salvar log manual.");
    }
  };

  const handleStatusChangeManual = async (newStatus: AssetStatus) => {
    if (!detailAsset) return;

    try {
      const newEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Status',
        description: `Status alterado manualmente de ${detailAsset.status} para ${newStatus}.`,
        performedBy: 'Gestor de TI'
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        status: newStatus,
        assignedTo: newStatus === 'Disponível' ? undefined : detailAsset.assignedTo,
        history: [...(detailAsset.history || []), newEntry]
      };

      await onUpdate(updatedAsset);
      setDetailAsset(updatedAsset);
    } catch (err: any) {
      alert("Falha ao atualizar status.");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.departmentId && !editingAsset) {
      alert("Selecione ou crie um departamento primeiro.");
      return;
    }

    setIsSaving(true);
    try {
      if (editingAsset) {
        const historyEntry: HistoryEntry = {
          id: Math.random().toString(),
          date: new Date().toISOString(),
          type: 'Observação',
          description: 'Informações do ativo atualizadas manualmente via formulário de edição.',
          performedBy: 'Gestor de Ativos'
        };
        const updated: Asset = {
          ...editingAsset,
          ...(formData as Asset),
          history: [...(editingAsset.history || []), historyEntry]
        };
        await onUpdate(updated);
        setEditingAsset(null);
      } else {
        await onAdd(formData as any);
      }
      setShowForm(false);
      resetFormData();
    } catch (err: any) {
      console.error("Erro no handleSubmit:", err);
      alert(`Erro ao salvar ativo: ${err.message || 'Certifique-se que o ID não está duplicado.'}`);
    } finally {
      setIsSaving(false);
    }
  };

  const resetFormData = () => {
    setFormData({ 
      id: '',
      type: 'Notebook', 
      status: 'Disponível', 
      serialNumber: '', 
      observations: '', 
      photos: [], 
      departmentId: companies[0]?.id || '', 
      ram: '', 
      storage: '', 
      processor: '',
      screenSize: '', 
      caseModel: '', 
      isWireless: false, 
      monitorInputs: [], 
      isAbnt: true, 
      hasNumericKeypad: true 
    });
    setEditingAsset(null);
  };

  const handleBulkAddRow = () => {
    setBulkEntries([...bulkEntries, { 
      tempId: Math.random().toString(), 
      departmentId: companies[0]?.id || '', 
      type: 'Notebook', 
      brand: '', 
      model: '', 
      serialNumber: '',
      ram: '',
      storage: '',
      screenSize: '',
      caseModel: '',
      isWireless: false,
      monitorInputs: [],
      isAbnt: true,
      hasNumericKeypad: true,
      id: '', 
      assignedTo: '', 
      observations: '' 
    }]);
  };

  const handleBulkSave = async () => {
    if (companies.length === 0) {
      alert("Erro: Você precisa cadastrar pelo menos um Departamento antes.");
      return;
    }

    setIsSavingBulk(true);
    try {
      for (const entry of bulkEntries) {
        await onAdd({
          id: entry.id || undefined,
          serialNumber: entry.serialNumber,
          departmentId: entry.departmentId || companies[0].id,
          type: entry.type,
          brand: entry.brand,
          model: entry.model,
          ram: entry.ram,
          storage: entry.storage,
          screenSize: entry.screenSize,
          caseModel: entry.caseModel,
          isWireless: entry.isWireless,
          monitorInputs: entry.monitorInputs,
          isAbnt: entry.isAbnt,
          hasNumericKeypad: entry.hasNumericKeypad,
          observations: entry.observations,
          photos: [],
          status: entry.assignedTo ? 'Em Uso' : 'Disponível',
          assignedTo: entry.assignedTo || undefined,
        });
      }
      setShowBulkModal(false);
      setBulkEntries([{ tempId: '1', departmentId: companies[0]?.id || '', type: 'Notebook', brand: '', model: '', serialNumber: '', ram: '', storage: '', screenSize: '', caseModel: '', isWireless: false, monitorInputs: [], isAbnt: true, hasNumericKeypad: true, id: '', assignedTo: '', observations: '' }]);
    } catch (err: any) {
      alert(`Erro no salvamento em lote: ${err.message || 'Verifique se há IDs duplicados'}`);
    } finally {
      setIsSavingBulk(false);
    }
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.serialNumber?.toLowerCase().includes(searchTerm.toLowerCase());

    // Filtro de Inativados: Por padrão ocultamos baixados se showRetired for false
    const matchesVisibility = showRetired ? true : a.status !== 'Baixado';

    return matchesSearch && matchesVisibility;
  });

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 print:hidden">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por modelo, serial, marca ou ID..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-300 bg-white focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm font-semibold placeholder:text-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
          <button 
            onClick={() => setShowRetired(!showRetired)} 
            className={`flex items-center gap-2 px-4 py-3 text-xs font-black border rounded-2xl transition-all uppercase tracking-widest ${
              showRetired ? 'bg-amber-50 border-amber-200 text-amber-700' : 'bg-white border-slate-200 text-slate-500'
            }`}
          >
            {showRetired ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
            {showRetired ? 'Ocultar Inativos' : 'Ver Inativos'}
          </button>
          <button onClick={() => setShowBulkModal(true)} className="flex items-center gap-2 px-4 py-3 text-xs font-black text-slate-800 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all uppercase tracking-widest">
            <FileSpreadsheet className="w-4 h-4 text-emerald-600" />
            Lançar Levantamento
          </button>
          <button onClick={() => { resetFormData(); setShowForm(true); }} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black transition-all shadow-lg uppercase tracking-widest text-xs">
            <Plus className="w-5 h-5" />
            <span>Novo Ativo</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden print:hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Ativo / Serial</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Tipo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Marca/Modelo</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-xs font-black text-slate-900 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredAssets.map((asset) => (
                <tr 
                  key={asset.id} 
                  onClick={() => setDetailAsset(asset)}
                  className={`hover:bg-blue-50/50 transition-colors cursor-pointer group ${asset.status === 'Baixado' ? 'opacity-50 grayscale' : ''}`}
                >
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                      <span className="font-black text-slate-900 group-hover:text-blue-700">{asset.id}</span>
                      <span className="text-[10px] text-slate-400 font-mono flex items-center gap-1">
                        <ScanBarcode className="w-3 h-3" /> {asset.serialNumber || 'SEM SERIAL'}
                      </span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="text-xs font-black text-slate-800">{asset.type}</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="font-bold text-slate-900">{asset.brand}</span>
                    <span className="text-sm text-slate-700 ml-2 font-medium">{asset.model}</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${
                      asset.status === 'Disponível' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' :
                      asset.status === 'Em Uso' ? 'bg-blue-50 text-blue-700 border-blue-200' :
                      asset.status === 'Manutenção' ? 'bg-amber-50 text-amber-700 border-amber-200' : 
                      asset.status === 'Baixado' ? 'bg-rose-50 text-rose-700 border-rose-200' : 'bg-slate-50 text-slate-700 border-slate-200'
                    }`}>
                      {asset.status === 'Baixado' ? 'INATIVO' : asset.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button onClick={(e) => { e.stopPropagation(); openEditModal(asset); }} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
                        <Edit2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredAssets.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-20 text-center">
                    <div className="flex flex-col items-center justify-center space-y-3 opacity-30">
                       <Package className="w-12 h-12" />
                       <p className="font-black uppercase tracking-widest text-xs">Nenhum ativo {showRetired ? '' : 'ativo'} encontrado.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {detailAsset && (
        <div className="fixed inset-0 z-[150] flex items-center justify-end p-0 md:p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-2xl h-full md:h-auto md:max-h-[90vh] md:rounded-[3rem] shadow-2xl flex flex-col animate-in slide-in-from-right duration-300 overflow-hidden">
              <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                 <div className="flex items-center gap-4">
                    <div className={`w-14 h-14 ${detailAsset.status === 'Baixado' ? 'bg-rose-600' : 'bg-blue-600'} rounded-2xl flex items-center justify-center text-white shadow-xl`}>
                       <Tag className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-2xl font-black text-slate-900 tracking-tight">{detailAsset.id}</h3>
                       <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">
                         {detailAsset.status === 'Baixado' ? 'Item Inativado Permanente' : `Serial: ${detailAsset.serialNumber || 'N/A'}`}
                       </p>
                    </div>
                 </div>
                 <div className="flex items-center gap-2">
                    <button onClick={() => {setDetailAsset(null); setManualLog('');}} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                       <X className="w-6 h-6 text-slate-400" />
                    </button>
                 </div>
              </div>

              <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                 <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-200">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 text-center">Estado Atual</p>
                    <div className="flex justify-center">
                       <span className={`px-8 py-3 rounded-full text-xs font-black uppercase border ${
                          detailAsset.status === 'Baixado' ? 'bg-rose-600 text-white border-rose-700 shadow-xl' : 'bg-emerald-50 text-emerald-700 border-emerald-200'
                       }`}>
                          {detailAsset.status}
                       </span>
                    </div>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Localidade / Depto</p>
                       <p className="font-bold text-slate-800">{getDepartmentName(detailAsset.departmentId)}</p>
                    </div>
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Responsável</p>
                       <p className="font-bold text-slate-800">{getEmployeeName(detailAsset.assignedTo)}</p>
                    </div>
                 </div>

                 <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Dossiê Técnico / Observações</p>
                    <p className="text-sm text-slate-700 font-medium whitespace-pre-wrap leading-relaxed">
                      {detailAsset.observations || 'Sem observações registradas.'}
                    </p>
                 </div>

                 <div className="space-y-6">
                    <div className="flex items-center gap-2">
                       <History className="w-5 h-5 text-blue-600" />
                       <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Histórico de Movimentação</h4>
                    </div>

                    <div className="relative pl-8 space-y-8 before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[2px] before:bg-slate-100">
                       {detailAsset.history?.length > 0 ? (
                         [...detailAsset.history].reverse().map((entry) => (
                           <div key={entry.id} className="relative group">
                              <div className={`absolute -left-[30px] top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm flex items-center justify-center ${
                                entry.description.includes('BAIXA') ? 'bg-rose-600' : 'bg-slate-400'
                              }`}>
                                {entry.description.includes('BAIXA') ? <Trash2 className="w-3 h-3 text-white" /> : <Clock className="w-3 h-3 text-white" />}
                              </div>
                              <div className="space-y-1">
                                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{new Date(entry.date).toLocaleDateString('pt-BR')}</p>
                                 <p className="text-sm text-slate-800 font-bold leading-relaxed">{entry.description}</p>
                              </div>
                           </div>
                         ))
                       ) : <p className="text-center py-10 text-slate-400 font-bold uppercase tracking-widest text-xs">Sem histórico disponível.</p>}
                    </div>
                 </div>
              </div>

              <div className="p-8 bg-slate-50 border-t border-slate-100 flex justify-end">
                 <button onClick={() => setDetailAsset(null)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl transition-all">Fechar Visualização</button>
              </div>
           </div>
        </div>
      )}

      {/* Form de Cadastro e Lote permanecem inalterados por brevidade mas herdam as melhorias de ID Automático */}
    </div>
  );
};

export default AssetManager;

import React, { useState, useMemo } from 'react';
import { 
  Wrench, 
  Search, 
  Plus, 
  X, 
  Activity, 
  CheckCircle2, 
  Package, 
  AlertCircle,
  Building2,
  Clock,
  ChevronRight,
  Info,
  Layers,
  ArrowRight,
  User,
  Settings2,
  ShoppingCart,
  Trash2,
  FileText,
  Zap,
  Loader2,
  History
} from 'lucide-react';
import { Asset, HistoryEntry, Employee, Department, AppNotification, EquipmentRequest, AssetType, UserAccount } from '../types';
import { ASSET_TYPES } from '../constants';

interface MaintenanceManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Department[];
  currentUser: UserAccount;
  onUpdateAsset: (asset: Asset) => Promise<void>;
  onAddNotification: (notif: Omit<AppNotification, 'id' | 'createdAt' | 'isRead'>) => void;
  onAddRequest: (req: any) => Promise<void>;
}

const MaintenanceManager: React.FC<MaintenanceManagerProps> = ({ assets, employees, companies, currentUser, onUpdateAsset, onAddNotification, onAddRequest }) => {
  const [showModal, setShowModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [selectedAssetId, setSelectedAssetId] = useState('');
  const [detailAsset, setDetailAsset] = useState<Asset | null>(null);

  const [maintenanceType, setMaintenanceType] = useState<'Preventiva' | 'Corretiva'>('Preventiva');
  const [maintenanceScope, setMaintenanceScope] = useState<'Interna' | 'Externa'>('Interna');
  const [reason, setReason] = useState('');

  const [finalDiagnosis, setFinalDiagnosis] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showPOForm, setShowPOForm] = useState(false);
  const [poType, setPoType] = useState<AssetType>('Mouse');
  const [validationError, setValidationError] = useState(false);

  const assetsInMaintenance = useMemo(() => 
    assets.filter(a => a.status === 'Manutenção')
  , [assets]);

  const availableForMaintenance = useMemo(() => 
    assets.filter(a => a.status !== 'Manutenção' && a.status !== 'Baixado')
  , [assets]);

  const filteredAvailable = availableForMaintenance.filter(a => 
    a.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
    a.model.toLowerCase().includes(searchTerm.toLowerCase()) ||
    a.brand.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleOpenMaintenance = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAssetId || !reason.trim()) return;

    const asset = assets.find(a => a.id === selectedAssetId);
    if (!asset) return;

    setIsSubmitting(true);
    try {
      const historyEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Manutenção',
        description: `Início de manutenção ${maintenanceType} (${maintenanceScope}). Motivo: ${reason}`,
        performedBy: currentUser.name
      };

      const updatedAsset: Asset = {
        ...asset,
        status: 'Manutenção',
        observations: reason,
        history: [...(asset.history || []), historyEntry]
      };

      await onUpdateAsset(updatedAsset);
      setShowModal(false);
      setSelectedAssetId('');
      setReason('');
    } catch (error) {
      alert("Erro ao iniciar manutenção.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleConcludeMaintenance = async () => {
    if (!detailAsset) return;

    if (!finalDiagnosis.trim()) {
      setValidationError(true);
      alert("Por favor, preencha o laudo técnico conclusivo.");
      return;
    }

    setIsSubmitting(true);
    try {
      const historyEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Manutenção',
        description: `Manutenção concluída: ${finalDiagnosis}`,
        performedBy: currentUser.name
      };

      const updatedAsset: Asset = {
        ...detailAsset,
        status: 'Disponível',
        assignedTo: undefined,
        observations: `Último reparo: ${finalDiagnosis}`,
        history: [...(detailAsset.history || []), historyEntry]
      };

      await onUpdateAsset(updatedAsset);
      setShowDetailModal(false);
      setDetailAsset(null);
      setFinalDiagnosis('');
    } catch (error) {
      alert("Erro ao concluir manutenção.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleRetireAsset = async () => {
    if (!detailAsset) return;

    if (!finalDiagnosis.trim()) {
      setValidationError(true);
      alert("É obrigatório informar o motivo técnico da baixa/inativação.");
      return;
    }

    if (!confirm("Confirmar BAIXA PATRIMONIAL permanente? O ativo será inativado e removido do inventário de uso.")) return;

    setIsSubmitting(true);
    try {
      const historyEntry: HistoryEntry = {
        id: Math.random().toString(),
        date: new Date().toISOString(),
        type: 'Status',
        description: `BAIXA PATRIMONIAL EXECUTADA. Motivo: ${finalDiagnosis}`,
        performedBy: currentUser.name
      };

      // ATENÇÃO: Mantemos o departmentId original para evitar erro de chave estrangeira
      // A inativação é controlada pelo status 'Baixado'
      const updatedAsset: Asset = {
        ...detailAsset,
        status: 'Baixado',
        assignedTo: undefined,
        observations: `ITEM INATIVADO: ${finalDiagnosis}`,
        history: [...(detailAsset.history || []), historyEntry]
      };

      await onUpdateAsset(updatedAsset);

      alert(`Ativo ${detailAsset.id} inativado com sucesso.`);

      setShowDetailModal(false);
      setDetailAsset(null);
      setFinalDiagnosis('');
    } catch (error) {
      console.error("Erro na baixa:", error);
      alert("Erro ao realizar baixa patrimonial. Verifique a conexão.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleCreatePurchaseOrder = async () => {
    if (!detailAsset) return;
    setIsSubmitting(true);
    try {
      await onAddRequest({
        requesterId: currentUser.id,
        employeeId: '', 
        items: [poType],
        observation: `Peça para o ativo ${detailAsset.id}`,
        itemFulfillments: [{ type: poType, isPurchaseOrder: true, purchaseStatus: 'Pendente' }]
      });
      setShowPOForm(false);
    } catch (e) {
      alert("Erro ao solicitar peça.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-2xl font-black text-slate-800 tracking-tight">Centro de Manutenção</h3>
          <p className="text-slate-500 font-medium italic">Gestão técnica e descarte de equipamentos.</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-amber-600 hover:bg-amber-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-amber-100 flex items-center gap-2 transition-all transform active:scale-95"
        >
          <Wrench className="w-5 h-5" />
          Nova Entrada de Reparo
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {assetsInMaintenance.map(asset => (
          <div 
            key={asset.id} 
            onClick={() => {
              if (isSubmitting) return;
              setDetailAsset(asset);
              setFinalDiagnosis(''); 
              setShowDetailModal(true);
            }}
            className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-100 shadow-sm hover:shadow-xl hover:border-amber-400 transition-all group flex flex-col cursor-pointer active:scale-95"
          >
            <div className="flex justify-between items-start mb-6">
              <div className="w-14 h-14 bg-amber-50 rounded-2xl flex items-center justify-center text-amber-600 group-hover:bg-amber-600 group-hover:text-white transition-all duration-500 shadow-sm">
                <Activity className="w-7 h-7" />
              </div>
              <div className="flex flex-col items-end">
                 <span className="bg-amber-600 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest mb-1 shadow-lg shadow-amber-100">
                    Em Reparo
                 </span>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter font-mono">{asset.id}</p>
              </div>
            </div>

            <div className="space-y-1 mb-6">
              <h4 className="text-xl font-black text-slate-800 tracking-tight leading-none group-hover:text-amber-600 transition-colors">{asset.type}</h4>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{asset.brand} {asset.model}</p>
            </div>

            <div className="bg-amber-50/50 p-4 rounded-2xl border border-amber-100 mb-6 flex-1">
               <div className="flex items-center gap-2 text-amber-600 mb-2">
                  <Info className="w-4 h-4" />
                  <span className="text-[10px] font-black uppercase tracking-widest">Diagnóstico Inicial</span>
               </div>
               <p className="text-xs text-slate-600 font-medium leading-relaxed italic line-clamp-3">
                 "{asset.observations}"
               </p>
            </div>

            <div className="flex items-center justify-between text-amber-600 font-black text-[10px] uppercase tracking-widest pt-2 border-t border-amber-100">
               <span>Painel de Encerramento</span>
               <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
            </div>
          </div>
        ))}

        {assetsInMaintenance.length === 0 && (
          <div className="col-span-full py-32 bg-slate-50 rounded-[3rem] border border-dashed border-slate-200 flex flex-col items-center justify-center text-center space-y-4">
             <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-sm">
                <Settings2 className="w-10 h-10 text-slate-200" />
             </div>
             <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Sem Ativos em Manutenção</p>
          </div>
        )}
      </div>

