                    >
                       <ShoppingCart className="w-5 h-5 text-blue-600" />
                       <span className="text-[11px] font-black uppercase tracking-widest text-slate-700">Solicitar Peças</span>
                    </button>

                    <button 
                      type="button"
                      onClick={handleRetireAsset}
                      disabled={isSubmitting}
                      className="w-full p-5 rounded-2xl border-2 border-slate-100 hover:border-rose-600 hover:bg-rose-50/30 transition-all flex flex-col items-center justify-center gap-2 disabled:opacity-50"
                    >
                       <Trash2 className="w-5 h-5 text-rose-500" />
                       <span className="text-[11px] font-black uppercase tracking-widest text-rose-700">Baixa / Inativar</span>
                    </button>
                 </div>

                 {showPOForm && (
                    <div className="bg-blue-50 p-6 rounded-[2rem] border-2 border-blue-100 space-y-4">
                       <select 
                          className="w-full p-4 rounded-xl bg-white border border-blue-200 font-bold outline-none"
                          value={poType}
                          onChange={(e) => setPoType(e.target.value as AssetType)}
                       >
                          {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                       </select>
                       <button 
                          type="button"
                          onClick={handleCreatePurchaseOrder}
                          className="w-full bg-blue-600 text-white font-black py-4 rounded-xl shadow-lg uppercase tracking-widest text-[10px]"
                       >
                          Confirmar Pedido de Peça
                       </button>
                    </div>
                 )}

                 <div className="pt-6">
                    <button 
                      type="button"
                      onClick={handleConcludeMaintenance}
                      disabled={isSubmitting}
                      className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-6 rounded-[2rem] font-black uppercase tracking-widest text-xs shadow-xl transition-all flex items-center justify-center gap-3 active:scale-95"
                    >
                       {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : <CheckCircle2 className="w-6 h-6" />}
                       Concluir e Liberar p/ Uso
                    </button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

